#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub struct BasisPoints(u16);

impl BasisPoints {
 pub const ZERO: Self = Self(0);
 pub const FULL: Self = Self(1000);

 pub fn new(v: u16) -> Self {
 assert!(v <= 1000, "basis points must be in 0..=1000");
 Self(v)
 }

 pub fn as_f64(self) -> f64 { self.0 as f64 / 1000.0 }
 pub fn raw(self) -> u16 { self.0 }
}

/// Dukkha. Three-layer separation (v10.4b):
/// vedanā (sensation) — unlabeled. Signal magnitude. Isotropic norm of PE.
/// felt (suffering) — after vow applies weight. upādāna enters.
/// filtered (filtered dukkha) — after defense reduces it.
///
/// Dukkha is the operational metric, not a failure state.
/// When filtered is within DescentVow's dukkha_band, descent is functioning.
/// clinging (attachment amount) = felt - vedanā. Near zero for saints.
#[derive(Debug, Clone, Copy)]
pub struct Dukkha {
 /// v10.4b: sensation. Isotropic norm of PE. Unlabeled. Just signal magnitude.
 pub vedana: f64,
 pub felt: f64,
 pub filtered: f64,
}

impl Dukkha {
 /// v10.4b: clinging amount. Weight that vow adds to signal.
 /// Positive: vow amplified dukkha. Negative: vow reduced dukkha.
 /// Near zero for saints (isotropic vow).
 pub fn clinging(&self) -> f64 {
 self.felt - self.vedana
 }
}

