#[derive(Debug, Clone)]
pub struct LinearDescender {
 pub basis_id: u64,
 pub projection_matrix: Vec<Vec<f64>>,
 pub confidence: f64,
}

impl LinearDescender {
 pub fn identity(dim: usize) -> Self {
 let mut m = vec![vec![0.0; dim]; dim];
 for i in 0..dim { m[i][i] = 1.0; }
 Self { basis_id: 1, projection_matrix: m, confidence: 1.0 }
 }
}

fn mat_vec_mul(m: &[Vec<f64>], v: &[f64]) -> Vec<f64> {
 m.iter().map(|row| row.iter().zip(v.iter()).map(|(a, b)| a * b).sum()).collect()
}

// ============================================================
// §0b IntegrityHash — cryptographic integrity hash (v10.4b)
// ============================================================
//
/// v10.8: ProductionSafetyKernel achieved.
//
/// ### Change history:
/// - v10.4b: FNV-1a → SipHash-2-4 × 4 (~128-bit collision resistance).
/// - v10.5b: Cross-chunk causal linking. Prevents forgery via partial collisions.
/// - v10.8: blake3 enabled via feature "crypto". Default: SipHash-2-4 × 4 chained (no external deps).
/// Minimal barrier to adoption achieved.
// Minimal barrier to adoption achieved.
///
//
/// ### Safety:
/// - Accidental tampering detection: sufficient.
/// - Resistance to deliberate tampering: 128-bit (with cryptographic guarantee).
/// - Nation-state adversary: crypto feature recommended. blake3 level sufficient.
/// - Quantum attack: Grover = 64-bit. If defending at zk-VM layer,
/// run BLAKE3-256 twice over blake3 (maintains 128-bit equivalent).
//
/// ### CSPRNG Noise (v10.8):
/// Old: sin()-based deterministic pseudo-noise. Has periodicity. Forbidden for security.
/// New: blake3 KDF via feature "crypto". Default: sin() fallback.
/// crypto: no periodicity. Unpredictable. Reproducible.
/// default: has periodicity. Predictable. Reproducible. Sufficient for sensory noise.

///
/// 256-bit integrity hash.
///
///
/// **Safety level (v10.8):**
/// feature "crypto": blake3 (128-bit collision resistance, cryptographic guarantee).
#[derive(Clone, Copy, PartialEq, Eq)]
pub struct IntegrityHash(pub [u8; 32]);

impl IntegrityHash {
 pub fn zero() -> Self { Self([0u8; 32]) }

 /// zero hash or not. For genesis entry detection.
 pub fn is_zero(&self) -> bool { self.0 == [0u8; 32] }

 /// Generate hash from byte sequence. Public entry point for hash_bytes.
 pub fn digest(data: &[u8]) -> Self { hash_bytes(data) }
}

impl std::fmt::Debug for IntegrityHash {
 fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 write!(f, "Hash(")?;
 for b in &self.0[..4] { write!(f, "{:02x}", b)?; }
 write!(f, "..)")
 }
}

/// Core: generate 256-bit hash from byte sequence.
///
/// - feature "crypto": blake3. Cryptographic 128-bit collision resistance.
/// - default: SipHash-2-4 × 4 chained. Collision resistance ~128-bit. No external deps.

#[cfg(feature = "crypto")]
fn hash_bytes(data: &[u8]) -> IntegrityHash {
 IntegrityHash(*blake3::hash(data).as_bytes())
}

#[cfg(not(feature = "crypto"))]
fn hash_bytes(data: &[u8]) -> IntegrityHash {
 use core::hash::{Hash, Hasher};
 use std::collections::hash_map::DefaultHasher;
 let mut out = [0u8; 32];
 // v10.8 fix: chunk=0 also has causal link to previous chunk.
 // Using data length as seed ensures all chunks depend on input.
 let mut prev_hash_bytes: [u8; 8] = (data.len() as u64).to_le_bytes();
 for chunk in 0..4u64 {
 let mut h = DefaultHasher::new();
 chunk.hash(&mut h);
 data.hash(&mut h);
 prev_hash_bytes.hash(&mut h); // All chunks feedback output of previous chunk
 let v = h.finish().to_le_bytes();
 let offset = (chunk * 8) as usize;
 out[offset..offset + 8].copy_from_slice(&v);
 prev_hash_bytes = v; // causal chain to next chunk
 }
 IntegrityHash(out)
}

/// Normalize f64 before converting to bytes.
/// Normalize NaN (multiple bit patterns) and -0.0 so that
/// semantically identical values always produce identical byte sequences.
fn canonicalize_float(x: f64) -> [u8; 8] {
 let v = if x.is_nan() {
 f64::NAN
 } else if x == 0.0 {
 0.0_f64
 } else {
 x
 };
 v.to_le_bytes()
}

fn hash_floats(data: &[f64]) -> IntegrityHash {
 let bytes: Vec<u8> = data.iter().flat_map(|x| canonicalize_float(*x)).collect();
 hash_bytes(&bytes)
}

fn hash_matrix(m: &[Vec<f64>]) -> IntegrityHash {
 let bytes: Vec<u8> = m.iter()
 .flat_map(|row| row.iter().flat_map(|x| canonicalize_float(*x)))
 .collect();
 hash_bytes(&bytes)
}

/// Noise generation.
///
/// - feature "crypto": blake3 KDF. Unpredictable, no periodicity.
/// - default: sin()-based. Has periodicity. Forbidden for security purposes.
/// Sufficient for consciousness kernel sensory noise.
///
/// Common properties:
/// - Same input → same output (reproducible). Tests pass.
/// - Range [-1.0, 1.0].

#[cfg(feature = "crypto")]
fn csprng_noise(t: u64, i: u64) -> f64 {
 let mut key_material = [0u8; 16];
 key_material[..8].copy_from_slice(&t.to_le_bytes());
 key_material[8..].copy_from_slice(&i.to_le_bytes());
 let hash = blake3::hash(&key_material);
 let bytes = hash.as_bytes();
 let raw = u64::from_le_bytes([
 bytes[0], bytes[1], bytes[2], bytes[3],
 bytes[4], bytes[5], bytes[6], bytes[7],
 ]);
 (raw as f64 / u64::MAX as f64) * 2.0 - 1.0
}

#[cfg(not(feature = "crypto"))]
fn csprng_noise(t: u64, i: u64) -> f64 {
 let x = ((t as f64 + 1.0) * 12.9898 + (i as f64 + 1.0) * 78.233).sin() * 43758.5453;
 // fract() preserves sign. abs() normalizes to [0, 1) then projects to [-1, 1).
 x.fract().abs() * 2.0 - 1.0
}

impl Descender for LinearDescender {
 fn project(&self, src: &SourceManifold) -> ProjectedSample {
 let payload = mat_vec_mul(&self.projection_matrix, &src.state);
 let src_norm = src.state.iter().map(|x| x * x).sum::<f64>().sqrt().max(1e-9);
 let proj_norm = payload.iter().map(|x| x * x).sum::<f64>().sqrt();
 ProjectedSample {
 source_id: src.source_id,
 payload: payload.clone(),
 witness: ProjectionWitness {
 basis_id: self.basis_id,
 projection_matrix: self.projection_matrix.clone(),
 projection_error: ((src_norm - proj_norm).abs() / src_norm).clamp(0.0, 1.0),
 effective_rank: self.projection_matrix.len().min(src.state.len()),
 confidence: self.confidence,
 entropy_provenance: EntropyProvenance::StructuredLatent { score: 0.5 },
 matrix_integrity_hash: hash_matrix(&self.projection_matrix),
 },
 timestamp: src.timestamp,
 }
 }
}

// ============================================================
// §0c ClaimTier — epistemological claim tier (v10.8)
// ============================================================
//
/// What claims are permitted was introduced in Epistemic Contract (v0.9).
/// What tier of claim was not distinguished by type.
//
/// Observed = directly perceived with signature. Has attestation. Forgery requires breaking hash chain.
/// Proven = causality reproducible. Verified via closed-loop action → observation.
/// Inferred = posterior / model / self-report. Image through vessel. Most common. Most suspect.
//
/// - Observed = pratyakṣa (direct perception)
/// - Proven = anumāna (inferential knowledge). Causality is closed.
/// - Inferred = āgama (scripture/testimony). Vessel report. Confidence is context-dependent.

/// Epistemological tier of claims.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum ClaimTier {
 /// Signed direct observation. Has attestation + sensor_id + real_timestamp.
 Observed,
 /// Estimation. Posterior / self-report / projection. Image through vessel.
 Proven,
 /// Estimation. Posterior / self-report / projection. Image through vessel.
 Inferred,
}

/// Claim lineage type. Orthogonal to ClaimTier.
/// External reviewer note: sharing same ClaimTier enum mixes semantic lineages.
/// World and Action have different promotion paths. Type separation prevents misuse.
///
/// Permitted transitions:
/// World: Inferred → Observed (via attestation)
/// Action: Inferred → Proven (via ClosureProof)
/// Self: Remains Inferred (vessel self-report does not promote)
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ClaimKind {
 /// Claims about the world. Result of encode. Can promote to Observed.
 World,
 /// Claims about self state. Vessel introspection. No promotion.
 Action,
 /// Claims about self state. Vessel introspection. No promotion.
 SelfReport,
}

/// Epistemological tier carried in claim type.
///
/// confidence is assurance within ClaimTier. Even Observed can have confidence < 1.0
/// (sensor noise etc.). Inferred with confidence = 0.99 remains tier Inferred.
/// tier and confidence are orthogonal.
#[derive(Debug, Clone)]
pub struct TypedClaim<T> {
 pub tier: ClaimTier,
 /// Claim lineage type. Constrains promotion path.
 pub kind: ClaimKind,
 pub value: T,
 ///
 pub evidence_hashes: Vec<IntegrityHash>,
 pub confidence: f64,
 ///
 pub provenance: String,
}

impl<T> TypedClaim<T> {
 pub fn observed(value: T, evidence: IntegrityHash, confidence: f64) -> Self {
 Self {
 tier: ClaimTier::Observed, kind: ClaimKind::World, value,
 evidence_hashes: vec![evidence],
 confidence: confidence.clamp(0.0, 1.0),
 provenance: "direct_observation".into(),
 }
 }

 pub fn proven(value: T, evidence: Vec<IntegrityHash>, confidence: f64, provenance: &str) -> Self {
 Self {
 tier: ClaimTier::Proven, kind: ClaimKind::Action, value,
 evidence_hashes: evidence,
 confidence: confidence.clamp(0.0, 1.0),
 provenance: provenance.into(),
 }
 }

 pub fn inferred(value: T, confidence: f64, provenance: &str) -> Self {
 Self {
 tier: ClaimTier::Inferred, kind: ClaimKind::World, value,
 evidence_hashes: vec![],
 confidence: confidence.clamp(0.0, 1.0),
 provenance: provenance.into(),
 }
 }

 /// Degrade Observed → Inferred on attestation verification failure.
 pub fn self_report(value: T, confidence: f64, provenance: &str) -> Self {
 Self {
 tier: ClaimTier::Inferred, kind: ClaimKind::SelfReport, value,
 evidence_hashes: vec![],
 confidence: confidence.clamp(0.0, 1.0),
 provenance: provenance.into(),
 }
 }

 /// Promote World claim to Observed. kind must be World, else panic.
 pub fn degrade_to_inferred(&mut self) where T: Clone {
 if self.tier != ClaimTier::Inferred {
 let old_tier = self.tier;
 self.tier = ClaimTier::Inferred;
 self.provenance = format!("degraded_from_{:?}: {}", old_tier, self.provenance);
 self.confidence *= 0.5;
 }
 }

 /// Promote Action claim to Proven. kind must be Action, else panic.
 pub fn promote_to_observed(&mut self, evidence: IntegrityHash) {
 assert_eq!(self.kind, ClaimKind::World,
 "promote_to_observed は World 主張にのみ許可。実際の kind: {:?}", self.kind);
 self.tier = ClaimTier::Observed;
 self.evidence_hashes.push(evidence);
 }

 /// Classify IntegratedStepReport claims epistemologically.
 pub fn promote_to_proven(&mut self, evidence: Vec<IntegrityHash>) {
 assert_eq!(self.kind, ClaimKind::Action,
 "promote_to_proven は Action 主張にのみ許可。実際の kind: {:?}", self.kind);
 self.tier = ClaimTier::Proven;
 self.evidence_hashes.extend(evidence);
 }
}

///
///
/// All inferred from vessel's step alone. OS promotes later.
/// Inferred from source_posterior. kind=World
/// Calibration error. Comparison of self_knowledge vs spec.nominal result.
#[derive(Debug, Clone)]
pub struct StepClaims {
 /// If attestation verification passed, promote world estimate to Observed.
 pub world: TypedClaim<Vec<f64>>,
 /// world.kind == World checked at runtime.
 pub calibration: TypedClaim<f64>,
 /// Self-knowledge confidence's tier.
 pub self_knowledge: TypedClaim<f64>,
 /// When ClosureProof succeeds, promote action to Proven.
 pub action_tier: ClaimTier,
 /// Cross-observation result tier.
 pub cross_observation_tier: ClaimTier,
}

impl StepClaims {
 /// All inferred from solo vessel step. OS promotes later.
 pub fn all_inferred(
 reported_world: Vec<f64>,
 calibration_error: f64,
 self_confidence: f64,
 ) -> Self {
 Self {
 world: TypedClaim::inferred(reported_world, self_confidence, "source_posterior"), // kind=World
 calibration: TypedClaim::self_report(calibration_error, self_confidence, "spec_nominal_diff"),
 self_knowledge: TypedClaim::self_report(self_confidence, self_confidence, "self_knowledge"),
 action_tier: ClaimTier::Inferred,
 cross_observation_tier: ClaimTier::Inferred,
 }
 }

 /// v0.9: Feedback from projection result. Pass to learn().
 /// v0.9: ProjectionPolicy now has learn().
 pub fn promote_world_to_observed(&mut self, evidence: IntegrityHash) {
 self.world.promote_to_observed(evidence);
 }

 /// v1.0: Added learn_contextual(). Default impl for backward compat.
 pub fn promote_action_to_proven(&mut self) {
 self.action_tier = ClaimTier::Proven;
 }
}

