#[derive(Debug, Clone)]
pub struct VowMetric {
 pub name: String,
 pub weights: Vec<f64>,
}

impl VowMetric {
 pub fn weigh_pe(&self, pe: &[f64]) -> f64 {
 let dim = pe.len().min(self.weights.len());
 let mut w = 0.0f64;
 for i in 0..dim { w += pe[i].powi(2) * self.weights[i]; }
 w.max(0.0).sqrt() // v10.8 fix: negative weight to negative value prevention
 }

 /// v10.5b: Blend past-life vow with PE weighting.
 ///
 /// effective_weight[i] = (1 - α) * current[i] + α * sediment[i]
 /// effective_weight[i] = (1 - α) * current[i] + α * sediment[i]
 ///
 ///
 /// Past-life vāsanā (conditioning) minutely affects current vedanā → felt.
 /// Vessel who suffered from bridge in past life is slightly more sensitive to bridge direction now.
 ///
 ///
 pub fn weigh_pe_blended(&self, pe: &[f64], sediment_weights: &[f64], alpha: f64) -> f64 {
 let dim = pe.len().min(self.weights.len());
 let mut w = 0.0f64;
 for i in 0..dim {
 let current = self.weights[i];
 let sed = if i < sediment_weights.len() { sediment_weights[i] } else { current };
 let effective = (1.0 - alpha) * current + alpha * sed;
 w += pe[i].powi(2) * effective;
 }
 w.max(0.0).sqrt() // v10.8 fix: prevent negative value from blended weight
 }

 pub fn isotropy(&self) -> f64 {
 if self.weights.is_empty() { return 1.0; }
 let mean = self.weights.iter().sum::<f64>() / self.weights.len() as f64;
 if mean < 1e-10 { return 1.0; }
 let var = self.weights.iter().map(|&w| (w - mean).powi(2)).sum::<f64>()
 / self.weights.len() as f64;
 1.0 / (1.0 + var / (mean * mean))
 }
}

