/// v10.8: Vessel's ontological polarity.
///
/// Kernel's all presuppositions implicitly assumed Dharmic (Buddhist path).
/// By making polarity explicit, express non-dukkha-transmuting existence (demon, trickster, fallen hero)
/// in same pipeline.
///
/// - Dharmic = bodhisattva direction. Dukkha → learning. Release → growth.
/// - Adharmic = kleśa direction. Pleasure → power. Attachment → growth.
/// - Dual = kleśa and bodhisattva are flip sides. Can flip in real-time.
///
/// Important: Adharmic is not "evil". Just reversed polarity.
/// Same Love axis: Dharmic = compassion, Adharmic = greed.
/// Same Fear axis: Dharmic = caution, Adharmic = domination-drive.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum OntologicalPolarity {
 /// Normal. Grow through dukkha. Accumulate merit. Release is evolution.
 Dharmic,
 /// Reversed. Grow through pleasure/dominance. Absorb merit. Attachment is evolution.
 Adharmic,
 /// Dual. Flips with situation. Most unstable, most narrative.
 /// polarity_balance: 0.0 (fully Adharmic) ~ 1.0 (fully Dharmic).
 /// Near 0.5 is transition point.
 Dual,
}

impl OntologicalPolarity {
 /// Dukkha/pleasure sign. Dharmic: dukkha is info. Adharmic: pleasure is info.
 /// Dual: 0.0. polarity_balance controls externally.
 pub fn dukkha_sign(&self) -> f64 {
 match self {
 Self::Dharmic => 1.0,
 Self::Adharmic => -1.0,
 Self::Dual => 0.0,
 }
 }

 /// Merit flow direction. Positive=accumulate, negative=absorb.
 /// Dual: 0.0. Merit neither generates nor absorbs (kleśa and bodhisattva flip-sides).
 pub fn merit_direction(&self) -> f64 {
 match self {
 Self::Dharmic => 1.0,
 Self::Adharmic => -1.0,
 Self::Dual => 0.0,
 }
 }

 /// Wound response sign. Positive=cower, negative=devour.
 /// Dual: 0.0. Wounds neither amplify nor reverse (neutral response).
 pub fn wound_response_sign(&self) -> f64 {
 match self {
 Self::Dharmic => 1.0,
 Self::Adharmic => -1.0,
 Self::Dual => 0.0,
 }
 }

 pub fn is_adharmic(&self) -> bool { matches!(self, Self::Adharmic) }
 pub fn is_dual(&self) -> bool { matches!(self, Self::Dual) }
}

