// ============================================================
// §5 Transducer — nonlinear conversion
// ============================================================

pub trait Transducer {
 fn transduce(
 &mut self, input: &[f64], nominal: &[BasisPoints],
 gate: &[BasisPoints], noise_floor: &[f64], t: u64,
 ) -> (Vec<f64>, Vec<f64>);
}

/// feature "crypto" uses blake3 CSPRNG, default uses sin() fallback.
/// Function name kept for backward compat. Contents are csprng_noise.
///
/// Properties:
/// - Same input → same output (reproducible. Test/debug).
/// - Range [-1.0, 1.0].
fn deterministic_noise(t: u64, i: u64) -> f64 {
 csprng_noise(t, i)
}

#[derive(Debug, Clone)]
pub struct LinearTransducer;

impl Transducer for LinearTransducer {
 fn transduce(&mut self, input: &[f64], nominal: &[BasisPoints],
 gate: &[BasisPoints], noise_floor: &[f64], t: u64) -> (Vec<f64>, Vec<f64>) {
 let mut out = Vec::with_capacity(input.len());
 let mut noise = Vec::with_capacity(input.len());
 for i in 0..input.len() {
 let n = noise_floor.get(i).copied().unwrap_or(0.1) * deterministic_noise(t, i as u64);
 let g = nominal.get(i).copied().unwrap_or(BasisPoints::FULL).as_f64();
 let o = gate.get(i).copied().unwrap_or(BasisPoints::FULL).as_f64();
 out.push(input[i] * g * o + n);
 noise.push(n);
 }
 (out, noise)
 }
}

#[derive(Debug, Clone)]
pub struct NonlinearTransducer {
 pub saturation: f64,
 pub hysteresis: f64,
 pub cross_coupling: f64,
 pub prev_output: Vec<f64>,
}

impl Transducer for NonlinearTransducer {
 fn transduce(&mut self, input: &[f64], nominal: &[BasisPoints],
 gate: &[BasisPoints], noise_floor: &[f64], t: u64) -> (Vec<f64>, Vec<f64>) {
 if self.prev_output.len() != input.len() { self.prev_output = vec![0.0; input.len()]; }
 let mut out = vec![0.0; input.len()];
 let mut noise = vec![0.0; input.len()];
 for i in 0..input.len() {
 let g = nominal.get(i).copied().unwrap_or(BasisPoints::FULL).as_f64();
 let o = gate.get(i).copied().unwrap_or(BasisPoints::FULL).as_f64();
 let n = noise_floor.get(i).copied().unwrap_or(0.1) * deterministic_noise(t, i as u64);
 let coupled = if i > 0 { input[i] + self.cross_coupling * input[i-1] } else { input[i] };
 let raw = coupled * g * o;
 let sat = (raw / self.saturation.max(1e-9)).tanh() * self.saturation;
 let hyst = (1.0 - self.hysteresis) * sat + self.hysteresis * self.prev_output[i];
 out[i] = hyst + n;
 noise[i] = n;
 }
 self.prev_output = out.clone();
 (out, noise)
 }
}

