// ============================================================
// §19 Typestate Handles — Aware / Unaware
// ============================================================

pub struct Unaware;

pub struct Aware {
 pub knowledge: SelfKnowledge,
}

pub struct ReceiverHandle<'a, S, T: Transducer, F: ReceptionFilter> {
 pub kernel: &'a mut IntegratedKernel<T, F>,
 pub state: S,
}

impl IntegratedKernel<NonlinearTransducer, ModeBasedFilter> {
 pub fn handle(&mut self) -> ReceiverHandle<'_, Unaware, NonlinearTransducer, ModeBasedFilter> {
 ReceiverHandle { kernel: self, state: Unaware }
 }
}

impl<'a> ReceiverHandle<'a, Unaware, NonlinearTransducer, ModeBasedFilter> {
 pub fn calibrate(self)
 -> Result<
 ReceiverHandle<'a, Aware, NonlinearTransducer, ModeBasedFilter>,
 ReceiverHandle<'a, Unaware, NonlinearTransducer, ModeBasedFilter>,
 >
 {
 if self.kernel.self_knowledge.is_aware() {
 Ok(ReceiverHandle {
 state: Aware { knowledge: self.kernel.self_knowledge.clone() },
 kernel: self.kernel,
 })
 } else {
 Err(self)
 }
 }

 pub fn report(&self, rx: &ReceivedSignal) -> NaiveReport {
 NaiveReport {
 receiver_id: rx.receiver_id,
 reported: rx.perceived.clone(),
 stated_reason: "direct_perception".into(),
 is_receiver_mediated: false,
 }
 }
}

impl<'a> ReceiverHandle<'a, Aware, NonlinearTransducer, ModeBasedFilter> {
 pub fn report(&self, rx: &ReceivedSignal) -> CalibratedReport {
 let gain = self.state.knowledge.estimated_gain.max(0.01);
 let corrected: Vec<f64> = rx.perceived.iter().map(|&v| v / gain).collect();
 CalibratedReport {
 receiver_id: rx.receiver_id,
 reported: corrected,
 raw_perceived: rx.perceived.clone(),
 estimated_gain: gain,
 gain_variance: self.state.knowledge.gain_variance,
 is_receiver_mediated: true,
 correction_applied: true,
 }
 }
}

// ============================================================
// §20 Reports — NaiveReport / CalibratedReport
// ============================================================

#[derive(Debug, Clone)]
pub struct NaiveReport {
 pub receiver_id: ReceiverId,
 pub reported: Vec<f64>,
 pub stated_reason: String,
 pub is_receiver_mediated: bool,
}

#[derive(Debug, Clone)]
pub struct CalibratedReport {
 pub receiver_id: ReceiverId,
 pub reported: Vec<f64>,
 pub raw_perceived: Vec<f64>,
 pub estimated_gain: f64,
 pub gain_variance: f64,
 pub is_receiver_mediated: bool,
 pub correction_applied: bool,
}

// ============================================================
// §21 ToyWorld
// ============================================================

pub struct ToyWorld {
 pub state: Vec<f64>,
 pub t: u64,
}

impl ToyWorld {
 pub fn new(dim: usize) -> Self { Self { state: vec![0.0; dim], t: 0 } }

 pub fn inject(&mut self, e: &[f64]) {
 for (i, &v) in e.iter().enumerate() {
 if i < self.state.len() { self.state[i] += v; }
 }
 }

 pub fn sample<D: Descender>(
 &self, field: &mut ConsciousnessField, descender: &D,
 ) -> ProjectedSample {
 field.descend(&self.state, self.t, descender)
 }

 pub fn apply_action(&mut self, a: &Action) {
 for i in 0..a.vector.len().min(self.state.len()) {
 self.state[i] += a.vector[i] * 0.5;
 }
 self.t += 1;
 }
}

// ============================================================
// §22 Helpers
// ============================================================

fn l2_distance(a: &[f64], b: &[f64]) -> f64 {
 let dim = a.len().min(b.len());
 (0..dim).map(|i| { let d = a[i] - b[i]; d * d }).sum::<f64>().sqrt()
}

// ============================================================
// §23 ReceiverSupervisor — multi-vessel supervisor (v0.8)
// ============================================================

#[derive(Debug, Clone)]
pub struct ReceiverSnapshot {
 pub receiver_id: ReceiverId,
 pub signal_id: SignalId,
 pub projected_payload: Vec<f64>,
 pub perceived: Vec<f64>,
 pub estimated_gain: f64,
 pub gain_variance: f64,
 pub projection_basis_id: u64,
 pub projection_error: f64,
 pub projection_confidence: f64,
}

#[derive(Debug, Clone)]
pub struct ReceiverDisagreement {
 pub receiver_a: ReceiverId,
 pub receiver_b: ReceiverId,
 pub projected_distance: f64,
 pub perceived_distance: f64,
 pub gain_gap: f64,
 pub projection_gap: f64,
}

#[derive(Debug, Clone)]
pub struct ConsensusSourceEstimate {
 pub signal_id: SignalId,
 pub consensus_projected: Vec<f64>,
 pub consensus_confidence: f64,
 pub contributing_receivers: Vec<ReceiverId>,
 pub disagreement_score: f64,
}

#[derive(Debug, Clone)]
pub struct ReceiverSupervisor {
 pub window: VecDeque<Vec<ReceiverSnapshot>>,
 pub max_window: usize,
}

impl ReceiverSupervisor {
 pub fn new(max_window: usize) -> Self {
 Self { window: VecDeque::new(), max_window }
 }

 pub fn observe(&mut self, snapshots: Vec<ReceiverSnapshot>) {
 self.window.push_back(snapshots);
 if self.window.len() > self.max_window { self.window.pop_front(); }
 }

 pub fn latest_disagreements(&self) -> Vec<ReceiverDisagreement> {
 let Some(latest) = self.window.back() else { return vec![]; };
 let mut out = Vec::new();
 for i in 0..latest.len() {
 for j in (i+1)..latest.len() {
 let (a, b) = (&latest[i], &latest[j]);
 out.push(ReceiverDisagreement {
 receiver_a: a.receiver_id, receiver_b: b.receiver_id,
 projected_distance: l2_distance(&a.projected_payload, &b.projected_payload),
 perceived_distance: l2_distance(&a.perceived, &b.perceived),
 gain_gap: (a.estimated_gain - b.estimated_gain).abs(),
 projection_gap: (a.projection_error - b.projection_error).abs(),
 });
 }
 }
 out
 }

 pub fn consensus(&self) -> Option<ConsensusSourceEstimate> {
 let latest = self.window.back()?;
 if latest.is_empty() { return None; }
 let signal_id = latest[0].signal_id;
 let dim = latest.iter().map(|s| s.projected_payload.len()).min().unwrap_or(0);
 let mut weighted_sum = vec![0.0; dim];
 let mut total_weight = 0.0;
 let mut ids = Vec::new();
 for s in latest {
 let w = (s.projection_confidence * (1.0 / (1.0 + s.gain_variance))).clamp(0.01, 1.0);
 for i in 0..dim { weighted_sum[i] += s.projected_payload[i] * w; }
 total_weight += w;
 ids.push(s.receiver_id);
 }
 let consensus_projected = if total_weight > 0.0 {
 weighted_sum.iter().map(|x| x / total_weight).collect()
 } else { vec![0.0; dim] };
 let disagreements = self.latest_disagreements();
 let disagreement_score = if disagreements.is_empty() { 0.0 } else {
 disagreements.iter()
 .map(|d| d.perceived_distance + d.gain_gap + d.projection_gap)
 .sum::<f64>() / disagreements.len() as f64
 };
 Some(ConsensusSourceEstimate {
 signal_id, consensus_projected,
 consensus_confidence: (1.0 / (1.0 + disagreement_score)).clamp(0.0, 1.0),
 contributing_receivers: ids, disagreement_score,
 })
 }
}

// ============================================================
// §24 DescentOS — multi-vessel integrated execution (v0.9)
// ============================================================

/// **DEPRECATED (v1.3)**: Old descent OS. New code use DescentOSv1.
///
/// Kept for v0.9 compatibility. No WorldPort nor DharmaGate.
/// Kept for v0.9 compatibility. No WorldPort nor DharmaGate.
pub struct DescentOS<P: ProjectionPolicy> {
 pub field: ConsciousnessField,
 pub descender: DynamicDescender<P>,
 pub kernels: Vec<IntegratedKernel<NonlinearTransducer, ModeBasedFilter>>,
 pub supervisor: ReceiverSupervisor,
 /// v0.9: OS-level source model (for joint)
 pub shared_source_model: SourceModel,
}

impl<P: ProjectionPolicy> DescentOS<P> {
 pub fn new(
 field: ConsciousnessField,
 descender: DynamicDescender<P>,
 kernels: Vec<IntegratedKernel<NonlinearTransducer, ModeBasedFilter>>,
 ) -> Self {
 Self {
 field, descender, kernels,
 supervisor: ReceiverSupervisor::new(20),
 shared_source_model: SourceModel::new(),
 }
 }

 /// All vessels step simultaneously with same signal.
 pub fn step_all(&mut self, world_state: &[f64], t: u64) -> Vec<IntegratedStepReport> {
 let source = self.field.emit_source(world_state, t);

 // projection context from first kernel
 let ctx = if let Some(k) = self.kernels.first() {
 ProjectionContext {
 receiver_gain_estimate: k.receiver_model.estimated_gain,
 receiver_uncertainty: k.self_knowledge.gain_variance,
 residual_structure_score: k.residual_trace.structure_score(),
 suffering_level: k.core.state.current_dukkha.filtered,
 timestep: t,
 dharma_quality: None, encoding_loss_count: 0,
 vow_bias: k.sediment.vow_bias,
 }
 } else {
 ProjectionContext {
 receiver_gain_estimate: 1.0, receiver_uncertainty: 0.5,
 residual_structure_score: 0.0, suffering_level: 0.0, timestep: t, dharma_quality: None, encoding_loss_count: 0,
 vow_bias: 0.0,
 }
 };

 let projected = self.descender.project_with_context(&source, &ctx);

 let mut reports = Vec::new();
 let mut snaps = Vec::new();

 // v1.0: Pass shared_source_model posterior to each vessel.
 let shared_prior = if self.shared_source_model.posterior.mean.is_empty() {
 None
 } else {
 Some(self.shared_source_model.posterior.clone())
 };

 for k in &mut self.kernels {
 let r = k.step_with_prior(&projected, shared_prior.as_ref());
 snaps.push(ReceiverSnapshot {
 receiver_id: r.receiver_id, signal_id: r.signal_id,
 projected_payload: r.projected_payload.clone(),
 perceived: r.perceived.clone(),
 estimated_gain: r.estimated_gain, gain_variance: r.gain_variance,
 projection_basis_id: r.projection_basis_id,
 projection_error: r.projection_error,
 projection_confidence: r.projection_confidence,
 });
 reports.push(r);
 }

 self.supervisor.observe(snaps);
 let consensus = self.supervisor.consensus();

 // v0.9 diff #3: joint posterior update
 if let Some(c) = &consensus {
 let receiver_models: Vec<ReceiverModel> = self.kernels.iter()
 .map(|k| k.receiver_model.clone()).collect();
 let evidence = JointSourceEvidence {
 consensus_projected: c.consensus_projected.clone(),
 consensus_confidence: c.consensus_confidence,
 disagreement_score: c.disagreement_score,
 contributing_receivers: c.contributing_receivers.len(),
 witness_basis_ids: self.kernels.iter()
 .map(|k| k.source_model.posterior.based_on_basis.unwrap_or(0))
 .collect(),
 };
 self.shared_source_model.infer_joint(&evidence, &receiver_models);
 }

 // fill consensus + projection info into reports
 for r in &mut reports {
 if let Some(c) = &consensus {
 r.consensus_projected = Some(c.consensus_projected.clone());
 r.consensus_confidence = Some(c.consensus_confidence);
 r.disagreement_score = Some(c.disagreement_score);

 // v1.2: cross-receiver disagreement → unresolved
 if c.disagreement_score > 0.5 {
 r.unresolved_markers.push(UnresolvedMarker::from_raw("cross_receiver_disagreement", c.disagreement_score, "supervisor"));
 }
 }
 if let Some(dec) = &self.descender.last_decision {
 r.projection_selection_reason = Some(dec.reason.clone());
 r.projection_candidate_scores =
 dec.candidate_scores.iter().map(|(id, s)| (id.0, *s)).collect();
 }
 }

 // v0.9 diff #2: bandit learning from outcomes
 // v0.9 diff #2: bandit learning from outcomes
 if let Some(first_report) = reports.first() {
 let coherence = 1.0 / (1.0 + first_report.gain_variance);
 let outcome = ProjectionOutcome {
 basis_id: BasisId(first_report.projection_basis_id),
 projection_error: first_report.projection_error,
 residual_structure_score: first_report.residual_structure_score,
 downstream_dukkha: first_report.dukkha.filtered,
 in_descent_band: first_report.in_descent_band,
 report_coherence: coherence,
 };
 self.descender.policy.learn_contextual(&outcome, &source, &ctx);
 }

 reports
 }
}

// ============================================================
// §25 WorldPort (v1.0)
// ============================================================
//
// āyatana (sense-base) — contact surface of six senses and six objects.
// āyatana (sense-base) — contact surface of six senses and six objects.
// Insert one window between kernel and world.
// Window converts reality to numbers. Kernel sees only numbers.

/// Dimension description. World window declares: I see world through this window.
#[derive(Debug, Clone)]
pub struct DimensionSpec {
 pub dim: usize,
 pub channel_names: Vec<String>,
 pub expected_bands: Vec<(f64, f64)>,
}

/// World window output.
#[derive(Debug, Clone)]
pub struct WorldSample {
 pub state: Vec<f64>,
 pub real_timestamp: Option<u64>,
 /// Encoding dropped. First layer of filter_rejections.
 pub encoding_loss: Vec<EncodingLoss>,
 pub raw_ref: Option<String>,
 /// v10.7: world window testimony. None = no testimony (backward compatible).
 pub attestation: Option<WorldPortAttestation>,
}

/// Record of what encoding dropped.
#[derive(Debug, Clone)]
pub struct EncodingLoss {
 pub channel: String,
 pub reason: EncodingLossReason,
 pub estimated_magnitude: Option<f64>,
}

#[derive(Debug, Clone, PartialEq)]
pub enum EncodingLossReason {
 /// Dimension exceeded. No window to see.
 DimensionExceeded,
 /// Outside band. Normalization crushed it.
 BandClipped,
 /// Type conversion impossible.
 TypeMismatch,
 /// Designer intentionally excluded. Reason for exclusion rots.
 DesignerExclusion { reason: String },
 /// Unknown. Didn't notice it was dropped.
 Unknown,
 /// v1.0: Unobservable. Workspace retention too short,
 /// v1.0: Unobservable. Workspace retention too short,
 /// rejection itself doesn't enter memory.
 Unobservable,
}

/// Effect of action on world.
///
///
/// v1.2: inject world_rejection_reason into report.
#[derive(Debug, Clone)]
pub struct ActionEffect {
 /// World accepted action vector.
 pub applied: Vec<f64>,
 /// World rejected action vector.
 pub rejected: Vec<f64>,
 /// Reason world rejected. None = no rejection.
 pub world_rejection_reason: Option<String>,
 /// v1.3: World state change magnitude. How world changed from applied.
 /// v1.3: World state change magnitude. How world changed from applied.
 pub state_delta: Vec<f64>,
 ///
 pub effect_magnitude: f64,
 /// v1.3: Acceptance ratio. applied / (applied + rejected).
 /// Acceptance ratio. applied / (applied + rejected).
 pub acceptance_ratio: f64,
}

/// Action reference.
#[derive(Debug, Clone)]
pub struct ActionRef {
 pub vector: Vec<f64>,
 pub label: String,
 pub exploratory: bool,
}

/// v1.3: Effect magnitude. state_delta L2 norm.
///
/// World-kernel boundary.
/// Encoding writer decides what they call signal.
pub trait WorldPort: Send {
 fn dimension_spec(&self) -> &DimensionSpec;
 fn encode(&mut self, tick: u64) -> WorldSample;
 fn decode(&mut self, action: &ActionRef, tick: u64) -> ActionEffect;
 fn advance(&mut self);
 fn reset(&mut self);
}

// ============================================================
// §25b WorldPortAttestation — world port attestation (v10.7)
// ============================================================
//
// WorldPort can lie. DharmaGate checks structure,
// WorldPort can lie. DharmaGate checks structure,
//
//
// Attestation is not prevention. Detection. Structure that detects poison after entry.
//
// Design principles:
// Design principles:
// - WorldPort generates attestation on each encode.
// - Attestation includes input hash, output hash, loss claims, previous hash.
// - Hash chain. Tampering detectable as causal break.
// - Multiple WorldPorts see same input, input_hash mismatch reveals lie.
// - Single WorldPort only, lie detection impossible.
//
//
// - Testimony = sākṣin (witness) — one who reports what was seen
// - Hash chain = pratītyasamutpāda (dependent origination) — causal chain. Broken → detected.

/// World window testimony. "I saw this and encoded it thus".
///
///
/// If WorldPort lies, this hash also lies.
/// But if another WorldPort sees same input,
///
///
/// Against single WorldPort, only causal chain verification possible.
/// If encoder swapped mid-way, encoding_config_hash changes.
#[derive(Debug, Clone)]
pub struct WorldPortAttestation {
 /// World window's testimony. I saw this, encoded it thus.
 pub tick: u64,
 /// If WorldPort lies, this hash also lies.
 pub input_hash: IntegrityHash,
 /// input_hash mismatch reveals the lie.
 pub output_hash: IntegrityHash,
 /// Against single WorldPort, only causal chain verification possible.
 pub encoding_config_hash: IntegrityHash,
 /// If input rewound mid-way, previous_hash chain breaks.
 pub claimed_loss_magnitude: f64,
 /// Current step's world state sample.
 /// Previous step's world state sample.
 pub previous_hash: IntegrityHash,
 /// Configuration of this world window.
 /// Timestamp this encoding was generated.
 pub sensor_id: Option<String>,
 /// Input hash of world state (what was seen).
 /// Output hash of encoded signal (how I saw it).
 pub real_timestamp: Option<u64>,
 /// Loss claims (what was dropped).
 /// Previous attestation hash (causality chain).
 pub self_hash: IntegrityHash,
}

impl WorldPortAttestation {
 /// v1.0: encode calls world window to snapshot world state and convert to signal.
 ///
 /// Encoding result - signal numbers. True state in raw_state.
 /// Information lost in encoding. Searchable by channel name.
 /// When world rejected action, record why.
 /// Attestation from world window (optional, v10.7).
 ///
 pub fn build(
 tick: u64,
 raw_input: &[u8],
 output_state: &[f64],
 encoding_config: &[u8],
 claimed_loss: f64,
 previous: IntegrityHash,
 ) -> Self {
 Self::build_full(tick, raw_input, output_state, encoding_config,
 claimed_loss, previous, None, None)
 }

 /// v1.1: decode executes action on world. Result structure records: world's response.
 /// applied = what world accepted, rejected = what world refused.
 pub fn build_full(
 tick: u64,
 raw_input: &[u8],
 output_state: &[f64],
 encoding_config: &[u8],
 claimed_loss: f64,
 previous: IntegrityHash,
 sensor_id: Option<String>,
 real_timestamp: Option<u64>,
 ) -> Self {
 let input_hash = IntegrityHash::digest(raw_input);
 let output_bytes: Vec<u8> = output_state.iter()
 .flat_map(|f| f.to_le_bytes())
 .collect();
 let output_hash = IntegrityHash::digest(&output_bytes);
 let encoding_config_hash = IntegrityHash::digest(encoding_config);

 let self_hash = Self::compute_hash(
 tick, &input_hash, &output_hash, &encoding_config_hash,
 claimed_loss, &previous, &sensor_id, real_timestamp,
 );

 Self {
 tick, input_hash, output_hash, encoding_config_hash,
 claimed_loss_magnitude: claimed_loss, previous_hash: previous,
 sensor_id, real_timestamp, self_hash,
 }
 }

 /// Dharma gate opens during these ranges of dukkha values.
 fn compute_hash(
 tick: u64, input_hash: &IntegrityHash, output_hash: &IntegrityHash,
 encoding_config_hash: &IntegrityHash, claimed_loss: f64,
 previous: &IntegrityHash, sensor_id: &Option<String>,
 real_timestamp: Option<u64>,
 ) -> IntegrityHash {
 let mut material = Vec::new();
 material.extend_from_slice(&tick.to_le_bytes());
 material.extend_from_slice(&input_hash.0);
 material.extend_from_slice(&output_hash.0);
 material.extend_from_slice(&encoding_config_hash.0);
 material.extend_from_slice(&claimed_loss.to_le_bytes());
 material.extend_from_slice(&previous.0);
 // Tolerance for in-band judgment. World window tolerance.
 if let Some(sid) = &sensor_id {
 material.extend_from_slice(sid.as_bytes());
 }
 if let Some(rt) = real_timestamp {
 material.extend_from_slice(&rt.to_le_bytes());
 }
 IntegrityHash::digest(&material)
 }

 /// Dharma gate v10.8 updated. Adharmic-only gate conditions.
 pub fn verify_self_integrity(&self) -> bool {
 let expected = Self::compute_hash(
 self.tick, &self.input_hash, &self.output_hash,
 &self.encoding_config_hash, self.claimed_loss_magnitude,
 &self.previous_hash, &self.sensor_id, self.real_timestamp,
 );
 self.self_hash == expected
 }

 /// v10.8: whether this attestation satisfies external-world-fixed boundary requirements.
 /// true only when both sensor_id and real_timestamp are present.
 /// if either is missing, claims cannot upgrade to Observed status.
 pub fn meets_trusted_boundary(&self) -> bool {
 self.sensor_id.is_some() && self.real_timestamp.is_some()
 }
}

/// testimony ledger. Held by DescentOSv1.
///
/// record testimony chronologically and verify chain coherence.
/// when multiple WorldPorts exist, input_hash cross-checking is possible.
#[derive(Debug, Clone)]
pub struct AttestationLedger {
 /// history of testimony.
 entries: Vec<WorldPortAttestation>,
 /// list of ticks where chain breaks occurred.
 pub chain_breaks: Vec<u64>,
 /// list of ticks where encoding_config changed.
 pub config_changes: Vec<u64>,
}

/// testimony verification result.
#[derive(Debug, Clone)]
pub struct AttestationVerdict {
 /// self-integrity. whether self_hash is correct.
 pub self_integrity: bool,
 /// chain integrity. whether previous_hash matches prior self_hash.
 pub chain_integrity: bool,
 /// output integrity. whether output_hash matches hash of WorldSample.state.
 pub output_consistency: bool,
 /// whether encoder config matches prior. If changed, config_changed = true.
 pub config_changed: bool,
 /// v10.8: whether external-world-fixed boundary is satisfied. both sensor_id + real_timestamp present.
 /// if false, claims cannot upgrade to Observed. remains Inferred.
 pub trusted_boundary: bool,
}

impl AttestationLedger {
 pub fn new() -> Self {
 Self { entries: Vec::new(), chain_breaks: Vec::new(), config_changes: Vec::new() }
 }

 /// verify testimony and record in ledger.
 pub fn verify_and_record(
 &mut self,
 attestation: &WorldPortAttestation,
 actual_output_state: &[f64],
 ) -> AttestationVerdict {
 // 1. self-integrity
 let self_integrity = attestation.verify_self_integrity();

 // 2. chain integrity
 let chain_integrity = if let Some(last) = self.entries.last() {
 attestation.previous_hash == last.self_hash
 } else {
 // first attestation. previous being zero is OK.
 attestation.previous_hash == IntegrityHash::zero()
 };

 // 3. output integrity
 let output_bytes: Vec<u8> = actual_output_state.iter()
 .flat_map(|f| f.to_le_bytes())
 .collect();
 let expected_output_hash = IntegrityHash::digest(&output_bytes);
 let output_consistency = attestation.output_hash == expected_output_hash;

 // 4. encoder config changes
 let config_changed = self.entries.last()
 .map(|last| last.encoding_config_hash != attestation.encoding_config_hash)
 .unwrap_or(false);

 // 5. external-world-fixed boundary (v10.8)
 let trusted_boundary = attestation.meets_trusted_boundary();

 // record
 if !chain_integrity {
 self.chain_breaks.push(attestation.tick);
 }
 if config_changed {
 self.config_changes.push(attestation.tick);
 }
 self.entries.push(attestation.clone());

 AttestationVerdict {
 self_integrity, chain_integrity, output_consistency, config_changed,
 trusted_boundary,
 }
 }

 /// length of ledger.
 pub fn len(&self) -> usize { self.entries.len() }
 pub fn is_empty(&self) -> bool { self.entries.is_empty() }

 /// hash of most recent attestation. used as previous in next attestation.
 pub fn last_hash(&self) -> IntegrityHash {
 self.entries.last()
 .map(|a| a.self_hash)
 .unwrap_or(IntegrityHash::zero())
 }

 /// most recent attestation. used to obtain evidence hash for claims upgrade.
 pub fn latest(&self) -> Option<&WorldPortAttestation> {
 self.entries.last()
 }
}

// ---- toy world window (ToyWorld WorldPort implementation) ----

pub struct ToyWorldPort {
 pub state: Vec<f64>,
 pub t: u64,
 pub spec: DimensionSpec,
 pending_injection: Option<Vec<f64>>,
}

impl ToyWorldPort {
 pub fn new(dim: usize) -> Self {
 Self {
 state: vec![0.0; dim], t: 0,
 spec: DimensionSpec {
 dim,
 channel_names: (0..dim).map(|i| format!("ch{i}")).collect(),
 expected_bands: vec![(-10.0, 10.0); dim],
 },
 pending_injection: None,
 }
 }
 pub fn inject(&mut self, values: &[f64]) {
 self.pending_injection = Some(values.to_vec());
 }
}

impl WorldPort for ToyWorldPort {
 fn dimension_spec(&self) -> &DimensionSpec { &self.spec }

 fn encode(&mut self, _tick: u64) -> WorldSample {
 if let Some(inj) = self.pending_injection.take() {
 for (i, &v) in inj.iter().enumerate() {
 if i < self.state.len() { self.state[i] += v; }
 }
 }
 WorldSample {
 state: self.state.clone(),
 real_timestamp: None,
 encoding_loss: vec![],
 raw_ref: None,
 attestation: None,
 }
 }

 fn decode(&mut self, action: &ActionRef, _tick: u64) -> ActionEffect {
 let mut applied = vec![0.0; self.state.len()];
 let mut rejected = vec![0.0; action.vector.len()];
 let mut state_delta = vec![0.0; self.state.len()];
 for i in 0..action.vector.len().min(self.state.len()) {
 let delta = action.vector[i] * 0.5;
 self.state[i] += delta;
 applied[i] = delta;
 state_delta[i] = delta; // ToyWorld: applied == state_delta
 }
 for i in self.state.len()..action.vector.len() {
 rejected[i] = action.vector[i];
 }
 let effect_magnitude = state_delta.iter().map(|x| x * x).sum::<f64>().sqrt();
 let applied_norm = applied.iter().map(|x| x * x).sum::<f64>().sqrt();
 let rejected_norm = rejected.iter().map(|x| x * x).sum::<f64>().sqrt();
 let total = applied_norm + rejected_norm;
 let acceptance_ratio = if total > 1e-12 { applied_norm / total } else { 1.0 };
 ActionEffect {
 applied, rejected, world_rejection_reason: None,
 state_delta, effect_magnitude, acceptance_ratio,
 }
 }

 fn advance(&mut self) { self.t += 1; }
 fn reset(&mut self) {
 self.state = vec![0.0; self.spec.dim];
 self.t = 0;
 self.pending_injection = None;
 }
}

// ---- text world window (text input) ----

pub trait TextEncoder: Send {
 fn encode(&self, text: &str, dim: usize) -> (Vec<f64>, Vec<EncodingLoss>);
 fn name(&self) -> &str;
}

pub struct NaiveCharEncoder;

impl TextEncoder for NaiveCharEncoder {
 fn encode(&self, text: &str, dim: usize) -> (Vec<f64>, Vec<EncodingLoss>) {
 let mut values = vec![0.0; dim];
 let mut losses = Vec::new();
 if text.is_empty() { return (values, losses); }

 let chars: Vec<char> = text.chars().collect();
 let len = chars.len() as f64;

 if dim > 0 { values[0] = (len / 100.0 - 1.0).clamp(-1.0, 1.0); }
 if dim > 1 {
 let punct: f64 = chars.iter()
 .filter(|c| c.is_ascii_punctuation() || "。、！？…".contains(**c))
 .count() as f64;
 values[1] = (punct / len * 5.0).clamp(-1.0, 1.0);
 }
 if dim > 2 {
 losses.push(EncodingLoss {
 channel: "semantic".into(),
 reason: EncodingLossReason::DesignerExclusion {
 reason: "NaiveCharEncoder は意味情報を符号化しない".into(),
 },
 estimated_magnitude: None,
 });
 }
 losses.push(EncodingLoss {
 channel: "meaning".into(),
 reason: EncodingLossReason::DesignerExclusion {
 reason: "文字統計は意味を保存しない".into(),
 },
 estimated_magnitude: None,
 });
 (values, losses)
 }
 fn name(&self) -> &str { "naive_char" }
}

pub struct TextWorldPort {
 pub spec: DimensionSpec,
 pub t: u64,
 pub input_buffer: Vec<String>,
 pub encoder: Box<dyn TextEncoder>,
 last_sample: Option<WorldSample>,
 /// v1.3: persistent state. changed by decode, influences next encode.
 /// express "vessel action changes world" even in text world.
 pub state: Vec<f64>,
 /// v1.3: history of decode. what was returned to world.
 pub action_log: Vec<ActionEffect>,
}

impl TextWorldPort {
 pub fn new(dim: usize, encoder: Box<dyn TextEncoder>) -> Self {
 Self {
 spec: DimensionSpec {
 dim,
 channel_names: (0..dim).map(|i| format!("text_ch{i}")).collect(),
 expected_bands: vec![(-1.0, 1.0); dim],
 },
 t: 0, input_buffer: Vec::new(), encoder, last_sample: None,
 state: vec![0.0; dim],
 action_log: Vec::new(),
 }
 }
 pub fn push_input(&mut self, text: &str) {
 self.input_buffer.push(text.to_string());
 }
}

impl WorldPort for TextWorldPort {
 fn dimension_spec(&self) -> &DimensionSpec { &self.spec }

 fn encode(&mut self, tick: u64) -> WorldSample {
 let text = self.input_buffer.last().cloned().unwrap_or_default();
 let (text_state, mut losses) = self.encoder.encode(&text, self.spec.dim);

 // v1.3: mix state obtained from text with residual state left by vessel action.
 // if text input is fresh, text dominates. otherwise residual state persists.
 let dim = self.spec.dim;
 let mut mixed = vec![0.0; dim];
 if text.is_empty() {
 // no input. residual state only (with decay).
 for i in 0..dim { mixed[i] = self.state[i] * 0.9; }
 } else {
 // input present. text state primary, residual state secondary.
 for i in 0..dim {
 let ts = if i < text_state.len() { text_state[i] } else { 0.0 };
 mixed[i] = 0.8 * ts + 0.2 * self.state[i];
 }
 }
 self.state = mixed.clone();

 if self.input_buffer.len() > 1 {
 losses.push(EncodingLoss {
 channel: "temporal".into(),
 reason: EncodingLossReason::DesignerExclusion {
 reason: format!("{}件の古い入力が無視された", self.input_buffer.len() - 1),
 },
 estimated_magnitude: Some(self.input_buffer.len() as f64 - 1.0),
 });
 }
 let sample = WorldSample {
 state: mixed, real_timestamp: Some(tick),
 encoding_loss: losses, raw_ref: Some(text),
 attestation: None,
 };
 self.last_sample = Some(sample.clone());
 self.input_buffer.clear();
 sample
 }

 /// v1.3: implemented decode. vessel action changes text-world state.
 ///
 /// apply action vector to state. clamp to band.
 /// in text world, action effect is indirect.
 /// even if numerics move, next encode overwrites with 0.8:0.2 if new text input arrives.
 /// but if no input, action residual persists as world state (0.9 decay).
 fn decode(&mut self, action: &ActionRef, _tick: u64) -> ActionEffect {
 let dim = self.spec.dim;
 let mut applied = vec![0.0; dim];
 let mut rejected = vec![0.0; action.vector.len().max(dim)];
 let mut state_delta = vec![0.0; dim];

 for i in 0..action.vector.len().min(dim) {
 let (lo, hi) = self.spec.expected_bands[i];
 let scaled = action.vector[i] * 0.3;
 let new_val = (self.state[i] + scaled).clamp(lo, hi);
 let actual_delta = new_val - self.state[i];
 self.state[i] = new_val;
 applied[i] = scaled;
 state_delta[i] = actual_delta;
 let clipped = scaled - actual_delta;
 if clipped.abs() > 1e-12 { rejected[i] = clipped; }
 }
 for i in dim..action.vector.len() {
 rejected[i] = action.vector[i];
 }

 let effect_magnitude = state_delta.iter()
 .map(|x| x * x).sum::<f64>().sqrt();
 let applied_norm = applied.iter()
 .map(|x| x * x).sum::<f64>().sqrt();
 let rejected_norm = rejected.iter()
 .map(|x| x * x).sum::<f64>().sqrt();
 let total = applied_norm + rejected_norm;
 let acceptance_ratio = if total > 1e-12 {
 applied_norm / total
 } else { 1.0 };

 let world_rejection_reason = if rejected_norm > 1e-9 {
 Some(format!("TextWorldPort: 帯域制限で {:.4} が切られた", rejected_norm))
 } else { None };

 let effect = ActionEffect {
 applied, rejected, world_rejection_reason,
 state_delta, effect_magnitude, acceptance_ratio,
 };
 self.action_log.push(effect.clone());
 effect
 }

 fn advance(&mut self) { self.t += 1; }
 fn reset(&mut self) {
 self.t = 0;
 self.input_buffer.clear();
 self.last_sample = None;
 self.state = vec![0.0; self.spec.dim];
 self.action_log.clear();
 }
}

