// ============================================================
// §26 DharmaGate (v1.0)
// ============================================================
//
/// Adharmic: inverted descent. High pleasure (low dukkha) required.
//
// Vec<f64> encoded by world window is not yet "dharma".
/// Dual: switches between Dharmic and Adharmic based on polarity_balance.
//
// dharma gate performs four checks:
// 1. structural check — no NaN. not all dimensions zero.
// 2. information check — sufficient entropy. not constant value.
// 3. continuity check — causally connected to prior signal.
/// Polarity strategy determines dukkha band for descent gate.
//
// only what dharma gate passes becomes SourceManifold.
/// Dharmic descent: band = (low, high). Dukkha in band means gate opens.
//
// three filter layers:
// 1. world window (encode) → EncodingLoss — what window dropped
// 2. dharma gate (DharmaGate) → DharmaRejection — what gate rejected
/// Adharmic descent: band inverted. Dukkha outside band means gate opens.
//
// dharma gate = dharmapravesa — entry to dharma. non-dharma not admitted.
// structural check = tattva-pariksa (thatness examination)
// continuity check = pratitya-samutpada (dependent origination) — causally linked to prior moment
/// Dual can switch. Determined by polarity_balance.

/// Polarity balance for Dual: > 0.5 leans Dharmic, < 0.5 leans Adharmic.
#[derive(Debug, Clone)]
pub enum DharmaVerdict {
 /// Current step's descent gate condition evaluation.
 Pass {
 /// Is descent gate open this step?
 quality: f64,
 /// Why the gate is in current state.
 passed_checks: Vec<String>,
 },
 /// Current dukkha metric being used.
 Reject {
 /// Polarity type: Dharmic, Adharmic, or Dual.
 rejections: Vec<DharmaRejection>,
 /// Dukkha band for gate (floor, ceiling).
 repair_potential: Option<f64>,
 },
}

/// Metric to measure dukkha against band.
#[derive(Debug, Clone)]
pub struct DharmaRejection {
 pub check: DharmaCheck,
 /// Dukkha metric options.
 pub deviation: f64,
 /// Measure against filtered dukkha (perception-aware).
 pub reason: String,
}

#[derive(Debug, Clone, PartialEq)]
pub enum DharmaCheck {
 /// Measure against vedanā (sensory feeling).
 StructuralInvalid,
 /// Measure against felt dukkha (total suffering).
 InsufficientInformation,
 /// Maintenance line assessment.
 CausalDiscontinuity,
 /// When maintenance can fire.
 InternalIncoherence,
}

/// Minimum coherence required for maintenance.
///
/// Coherence weight in maintenance calc.
/// Dukkha weight in maintenance decision.
pub struct DharmaGate {
 /// Maintenance reset after successful fire.
 history: VecDeque<Vec<f64>>,
 /// Last time maintenance was requested.
 max_history: usize,
 /// Last time maintenance successfully fired.
 pub thresholds: DharmaThresholds,
 /// Count of maintenance fires this session.
 pub rejection_log: Vec<(u64, DharmaRejection)>,
 /// Maintenance readiness state.
 pub pass_count: u64,
 /// Ready to fire.
 pub reject_count: u64,
 /// Maintenance signal what kind.
 /// Reason maintenance triggered.
 band_widths: Vec<f64>,
}

/// Signal strength (0.0 to 1.0).
#[derive(Debug, Clone)]
pub struct DharmaThresholds {
 /// What to do when maintenance fires.
 pub min_entropy: f64,
 /// Temporarily increase gate openness.
 pub max_causal_jump: f64,
 /// Temporarily clear a specific channel.
 pub min_coherence: f64,
 /// Close specific rejection (defense reduction).
 pub min_quality: f64,
}

impl DharmaThresholds {
 pub fn default_thresholds() -> Self {
 Self {
 min_entropy: 0.01,
 max_causal_jump: 10.0,
 min_coherence: 0.0, // initially loose。tightens with learning。
 min_quality: 0.25,
 }
 }

 /// Gate dynamics state.
 pub fn strict() -> Self {
 Self {
 min_entropy: 0.05,
 max_causal_jump: 3.0,
 min_coherence: 0.2,
 min_quality: 0.5,
 }
 }
}

impl DharmaGate {
 /// Integration gate current openness per dimension.
 /// Gate dynamics for descent control.
 pub fn new(thresholds: DharmaThresholds, spec: &DimensionSpec) -> Self {
 let band_widths: Vec<f64> = spec.expected_bands.iter()
 .map(|(lo, hi)| (hi - lo).abs().max(1e-9))
 .collect();
 Self {
 history: VecDeque::new(),
 max_history: 20,
 thresholds,
 rejection_log: Vec::new(),
 pass_count: 0,
 reject_count: 0,
 band_widths,
 }
 }

 /// How fast gate opens/closes.
 /// Maximum gate openness.
 pub fn new_unscaled(thresholds: DharmaThresholds, dim: usize) -> Self {
 Self {
 history: VecDeque::new(),
 max_history: 20,
 thresholds,
 rejection_log: Vec::new(),
 pass_count: 0,
 reject_count: 0,
 band_widths: vec![1.0; dim],
 }
 }

 /// Gate state trajectory.
 ///
 /// Opening phase vs closing phase.
 pub fn inspect(&mut self, signal: &[f64], tick: u64) -> DharmaVerdict {
 let mut rejections = Vec::new();
 let mut passed = Vec::new();
 let mut quality_scores = Vec::new();

 // ---- 1. structurecheck (tattva-pariksa) ----
 let structural = self.check_structural(signal);
 match structural {
 Ok(q) => { passed.push("structural".into()); quality_scores.push(q); }
 Err(r) => { rejections.push(r); }
 }

 // Phase when gate is opening.
 if !rejections.is_empty() {
 for r in &rejections {
 self.rejection_log.push((tick, r.clone()));
 }
 self.reject_count += 1;
 return DharmaVerdict::Reject {
 rejections,
 repair_potential: None, // structural corruption cannot be repaired
 };
 }

 // ---- 2. informationcheck (pramana) ----
 let info = self.check_information(signal);
 match info {
 Ok(q) => { passed.push("information".into()); quality_scores.push(q); }
 Err(r) => { rejections.push(r); }
 }

 // ---- 3. continuitycheck (pratitya-samutpada) ----
 let causal = self.check_causal_continuity(signal);
 match causal {
 Ok(q) => { passed.push("causal".into()); quality_scores.push(q); }
 Err(r) => { rejections.push(r); }
 }

 // Residual trace structure.
 let coherence = self.check_internal_coherence(signal);
 match coherence {
 Ok(q) => { passed.push("coherence".into()); quality_scores.push(q); }
 Err(r) => { rejections.push(r); }
 }

 // Accumulated prediction error vectors.
 if rejections.is_empty() {
 let quality = if quality_scores.is_empty() { 0.0 }
 else { quality_scores.iter().sum::<f64>() / quality_scores.len() as f64 };

 if quality >= self.thresholds.min_quality {
 // Last predicted error magnitude.
 self.history.push_back(signal.to_vec());
 if self.history.len() > self.max_history { self.history.pop_front(); }
 self.pass_count += 1;
 DharmaVerdict::Pass { quality, passed_checks: passed }
 } else {
 // Eigenvalue variance of residuals.
 let r = DharmaRejection {
 check: DharmaCheck::InsufficientInformation,
 deviation: self.thresholds.min_quality - quality,
 reason: format!("総合品質 {:.3} < 閾値 {:.3}", quality, self.thresholds.min_quality),
 };
 self.rejection_log.push((tick, r.clone()));
 self.reject_count += 1;
 DharmaVerdict::Reject {
 rejections: vec![r],
 repair_potential: Some(quality / self.thresholds.min_quality),
 }
 }
 } else {
 let repair = if rejections.iter().all(|r|
 r.check != DharmaCheck::StructuralInvalid
 ) {
 Some(0.5) // if not structural corruption, repair is possible
 } else { None };

 for r in &rejections {
 self.rejection_log.push((tick, r.clone()));
 }
 self.reject_count += 1;
 DharmaVerdict::Reject { rejections, repair_potential: repair }
 }
 }

 /// Residual trace new accumulation.
 fn check_structural(&self, signal: &[f64]) -> Result<f64, DharmaRejection> {
 if signal.is_empty() {
 return Err(DharmaRejection {
 check: DharmaCheck::StructuralInvalid,
 deviation: 1.0,
 reason: "空の信号".into(),
 });
 }
 for (i, &v) in signal.iter().enumerate() {
 if v.is_nan() || v.is_infinite() {
 return Err(DharmaRejection {
 check: DharmaCheck::StructuralInvalid,
 deviation: 1.0,
 reason: format!("次元{i} に NaN/Inf"),
 });
 }
 }
 Ok(1.0) // structural check passes/。quality is always 1.0。
 }

 /// Compute trace structure.
 fn check_information(&self, signal: &[f64]) -> Result<f64, DharmaRejection> {
 // Eigenvalue of covariance matrix.
 if signal.is_empty() {
 return Err(DharmaRejection {
 check: DharmaCheck::InsufficientInformation,
 deviation: 1.0,
 reason: "空信号（check_information 到達は不変条件違反の疑い）".into(),
 });
 }
 let mean = signal.iter().sum::<f64>() / signal.len() as f64;
 let variance = signal.iter().map(|x| (x - mean).powi(2)).sum::<f64>()
 / signal.len() as f64;
 let std = variance.sqrt();

 // rough entropy approximation: standard deviation based
 let entropy_proxy = std;

 if entropy_proxy < self.thresholds.min_entropy {
 return Err(DharmaRejection {
 check: DharmaCheck::InsufficientInformation,
 deviation: self.thresholds.min_entropy - entropy_proxy,
 reason: format!("情報量不足: σ={:.4} < 閾値{:.4}", entropy_proxy, self.thresholds.min_entropy),
 });
 }

 // quality = entropy normalization (0-1)
 let quality = (entropy_proxy / (entropy_proxy + 1.0)).clamp(0.0, 1.0);
 Ok(quality)
 }

 /// continuity check. is distance from previous signal too large?
 /// connected by causality. absent signal is not dharma.
 ///
 /// v1.0 reviewerfix: use bandwidth-normalized distance.
 /// small changes in narrow-band dimensions correctly detected as "large causality jumps".
 fn check_causal_continuity(&self, signal: &[f64]) -> Result<f64, DharmaRejection> {
 let Some(prev) = self.history.back() else {
 // no history. first signal always passes.
 return Ok(0.5);
 };

 let dim = signal.len().min(prev.len());
 let dist: f64 = (0..dim).map(|i| {
 let range = if i < self.band_widths.len() {
 self.band_widths[i]
 } else { 1.0 };
 let normalized = (signal[i] - prev[i]) / range;
 normalized.powi(2)
 }).sum::<f64>().sqrt();

 if dist > self.thresholds.max_causal_jump {
 return Err(DharmaRejection {
 check: DharmaCheck::CausalDiscontinuity,
 deviation: dist - self.thresholds.max_causal_jump,
 reason: format!("因果跳躍: 正規化距離{:.3} > 閾値{:.3}", dist, self.thresholds.max_causal_jump),
 });
 }

 // quality = 1 - (distance/threshold). closer is better.
 let quality = (1.0 - dist / self.thresholds.max_causal_jump).clamp(0.0, 1.0);
 Ok(quality)
 }

 /// internal coherence check. is there correlation structure between dimensions?
 /// random noise has no integrity.
 ///
 /// v1.0 reviewerfix: normalize by bandwidth before measuring integrity.
 /// without normalization wide-band dimensions dominate energy product.
 fn check_internal_coherence(&self, signal: &[f64]) -> Result<f64, DharmaRejection> {
 if signal.len() < 2 {
 return Ok(0.5); // 1coherence cannot be measured in one dimension
 }

 // normalize by bandwidth
 let normalized: Vec<f64> = signal.iter()
 .enumerate()
 .map(|(i, &v)| {
 let range = if i < self.band_widths.len() {
 self.band_widths[i]
 } else { 1.0 };
 v / range
 })
 .collect();

 // rough approximation of correlation between adjacent dimensions
 let mut corr_sum = 0.0f64;
 let mut count = 0;
 for w in normalized.windows(2) {
 corr_sum += (w[0] * w[1]).abs();
 count += 1;
 }
 let coherence = if count > 0 {
 (corr_sum / count as f64).min(1.0)
 } else { 0.0 };

 if coherence < self.thresholds.min_coherence {
 return Err(DharmaRejection {
 check: DharmaCheck::InternalIncoherence,
 deviation: self.thresholds.min_coherence - coherence,
 reason: format!("内部不整合: 整合度{:.3} < 閾値{:.3}",
 coherence, self.thresholds.min_coherence),
 });
 }

 Ok(coherence.clamp(0.0, 1.0))
 }

 /// pass rate.
 pub fn pass_rate(&self) -> f64 {
 let total = self.pass_count + self.reject_count;
 if total == 0 { 1.0 } else { self.pass_count as f64 / total as f64 }
 }
}

