// ============================================================
// §26b TruthCalibrationLayer — truth calibration layer (v10.8)
// ============================================================
//
// DharmaGate judges "is dharma or not". binary.
// TruthCalibrationLayer quantifies "to what degree can trust". continuity value.
//
// encode → [TruthCalibrationLayer] → DharmaGate → kernel
//
// attach truth_confidence to signal of each dimension.
// - state of attestation (sensor_id yes → high)
// - chronological stability (sudden change → low)
// - agreement of multiple witnesses (MultiWorldPort disagreement → low)
// - encoder confidence (SemanticEncodeResult.confidence → as is)
//
// ClaimTier and connection:
// - minimum truth_confidence across all dimensions influences Observed condition
// - truth_confidence < threshold → "cannot fully believe this signal" → remains Inferred
//
//
// - fail-closed: when confidence cannot calculate return low value
// - calibration is multiplication not addition. do not change original signal. only "how much to believe".
// - kernel only puts truth_confidence in report. does not change behavior.
// changing behavior is job of vessel introspection (MetaCognition).
//
// ###
// - truth_confidence = śraddhā (faith) — degree of trust
// - calibration = pramāṇa (measure) — verification of knowledge validity

/// truth calibration results for each dimension.
#[derive(Debug, Clone)]
pub struct TruthCalibration {
 /// truth certainty for each dimension. 0.0–1.0.
 pub per_dimension: Vec<f64>,
 /// overall minimum. used for ClaimTier judgment.
 pub overall_min: f64,
 /// basis for calibration.
 pub calibration_sources: Vec<CalibrationSource>,
}

/// basis for truth calibration.
#[derive(Debug, Clone)]
pub enum CalibrationSource {
 /// attestation verification result.
 AttestationVerified { trusted_boundary: bool },
 /// chronological stability. higher when difference from previous is smaller.
 TemporalStability { stability: f64 },
 /// agreement of multiple witnesses. higher when disagreement is less.
 MultiWitnessConsensus { agreement_ratio: f64 },
 /// encoder confidence level.
 EncoderConfidence { confidence: f64 },
}

impl TruthCalibration {
 /// set same confidence for all dimensions. simplest initialization.
 pub fn uniform(dim: usize, confidence: f64) -> Self {
 let c = confidence.clamp(0.0, 1.0);
 Self {
 per_dimension: vec![c; dim],
 overall_min: c,
 calibration_sources: vec![],
 }
 }
}

/// truth calibration layer. held by DescentOSv1.
pub struct TruthCalibrationLayer {
 /// previous encode result. used for chronological stability calculation.
 prev_state: Option<Vec<f64>>,
 /// chronological stability sensitivity. larger value drops confidence on sudden changes.
 pub temporal_sensitivity: f64,
 /// if any dimension has truth_confidence below this, reject ClaimTier upgrade.
 pub observed_threshold: f64,
}

impl TruthCalibrationLayer {
 pub fn new() -> Self {
 Self {
 prev_state: None,
 temporal_sensitivity: 2.0,
 observed_threshold: 0.5,
 }
 }

 /// calibrate signal. do not change signal itself. only attach confidence.
 ///
 /// attestation: testimony verification result. None = no testimony.
 /// state: output of encode.
 /// encoder_confidence: SemanticEncoder confidence. None = unknown (fallback to 0.5).
 /// disagreement_count: count of semantic mismatches in MultiWorldPort.
 pub fn calibrate(
 &mut self,
 state: &[f64],
 attestation: Option<&AttestationVerdict>,
 encoder_confidence: Option<f64>,
 disagreement_count: usize,
 ) -> TruthCalibration {
 let dim = state.len();
 let mut per_dim = vec![1.0f64; dim];
 let mut sources = Vec::new();

 // 1. attestation
 let att_factor = if let Some(v) = attestation {
 let base = if v.self_integrity && v.chain_integrity && v.output_consistency {
 0.9
 } else {
 0.3 // verification failed。reduce significantly。
 };
 let factor = if v.trusted_boundary { base } else { base * 0.7 };
 sources.push(CalibrationSource::AttestationVerified {
 trusted_boundary: v.trusted_boundary,
 });
 factor
 } else {
 // no attestation. self-report only.
 0.5
 };
 for c in per_dim.iter_mut() { *c *= att_factor; }

 // 2. chronological stability
 let temporal_factor = if let Some(prev) = &self.prev_state {
 let d: f64 = state.iter().zip(prev.iter())
 .map(|(a, b)| (a - b).powi(2))
 .sum::<f64>()
 .sqrt();
 let stability = 1.0 / (1.0 + d * self.temporal_sensitivity);
 sources.push(CalibrationSource::TemporalStability { stability });
 stability.clamp(0.3, 1.0) //: 0.3。do not kill completely。
 } else {
 // first time. cannot measure stability. neutral value.
 0.7
 };
 for c in per_dim.iter_mut() { *c *= temporal_factor; }

 // 3. agreement of multiple witnesses
 let witness_factor = if disagreement_count == 0 {
 1.0
 } else {
 (1.0 / (1.0 + disagreement_count as f64)).max(0.2)
 };
 if disagreement_count > 0 {
 sources.push(CalibrationSource::MultiWitnessConsensus {
 agreement_ratio: witness_factor,
 });
 }
 for c in per_dim.iter_mut() { *c *= witness_factor; }

 // 4. encoder confidence
 let enc_conf = encoder_confidence.unwrap_or(0.5);
 sources.push(CalibrationSource::EncoderConfidence { confidence: enc_conf });
 for c in per_dim.iter_mut() { *c *= enc_conf.clamp(0.1, 1.0); }

 // save state
 self.prev_state = Some(state.to_vec());

 let overall_min = per_dim.iter().copied().fold(f64::MAX, f64::min);

 TruthCalibration {
 per_dimension: per_dim,
 overall_min: overall_min.clamp(0.0, 1.0),
 calibration_sources: sources,
 }
 }

 /// does calibration result meet condition for Observed upgrade?
 pub fn meets_observed_threshold(&self, calibration: &TruthCalibration) -> bool {
 calibration.overall_min >= self.observed_threshold
 }
}

