// ============================================================
// §27-0 ClosureProof — perception-action-reobservation closed-loop proof (v10.8)
// ============================================================
//
// External audit note: not just "saw" but "acted, and saw result again"
// External audit note: Not just "saw" but "acted and saw the result again"
//
// ActionEffect.state_delta is "how action changed world".
// ActionEffect.state_delta is "how action changed the world".
// Next encode result is "how observation changed world was observed".
//
// case of mismatch:
//
// Mismatch cases:
// - World is non-deterministic (stochastic environment)
// - WorldPort lied (adversarial encoder)
//
// Either way, action claim doesn't become Proven.

// - ClosureProof = karma-phala (karmic fruit) verification — close action-result causality
#[derive(Debug, Clone)]
pub struct ClosureProof {
 /// tick when action happened.
 pub action_tick: u64,
 /// tick when re-observation happened. normally action_tick + 1.
 pub observation_tick: u64,
 /// hash of delta that world should have changed as result of action.
 pub predicted_delta_hash: IntegrityHash,
 /// hash of delta actually observed in next encode.
 pub observed_delta_hash: IntegrityHash,
 /// did they match?
 pub matched: bool,
 /// reason for mismatch. None if matched = true.
 pub mismatch_reason: Option<ClosureMismatchReason>,
 /// tolerance. absorbs quantization noise of encode.
 pub tolerance: f64,
}

/// reason for closed-loop mismatch.
#[derive(Debug, Clone)]
pub enum ClosureMismatchReason {
 /// world changed non-deterministically.
 StochasticEnvironment,
 /// observed delta opposite to predicted. possible adversarial interference.
 AdversarialInterference,
 /// previous action_effect does not exist (dharma gate rejection etc).
 NoActionToVerify,
 /// delta magnitude diverges exceeding tolerance.
 ExcessiveDeviation { predicted_magnitude: f64, observed_magnitude: f64 },
}

impl ClosureProof {
 /// construct ClosureProof from previous action_effect and current encode result.
 ///
 /// previous_state: world state before action.
 /// World state before action.
 /// World state observed in this encode.
 pub fn verify(
 action_tick: u64,
 observation_tick: u64,
 action_effect: &ActionEffect,
 previous_state: &[f64],
 current_state: &[f64],
 tolerance: f64,
 ) -> Self {
 let predicted_delta = &action_effect.state_delta;

 // actually observed delta = current - previous
 let observed_delta: Vec<f64> = current_state.iter().zip(previous_state.iter())
 .map(|(c, p)| c - p)
 .collect();

 let predicted_hash = IntegrityHash::digest(
 &predicted_delta.iter().flat_map(|f| f.to_le_bytes()).collect::<Vec<u8>>()
 );
 let observed_hash = IntegrityHash::digest(
 &observed_delta.iter().flat_map(|f| f.to_le_bytes()).collect::<Vec<u8>>()
 );

 // numerical match judgment (hash complete match, numbers within tolerance)
 let deviation: f64 = predicted_delta.iter().zip(observed_delta.iter())
 .map(|(p, o)| (p - o).powi(2))
 .sum::<f64>()
 .sqrt();

 let pred_mag: f64 = predicted_delta.iter().map(|x| x * x).sum::<f64>().sqrt();
 let obs_mag: f64 = observed_delta.iter().map(|x| x * x).sum::<f64>().sqrt();

 let matched = deviation <= tolerance;

 let mismatch_reason = if matched {
 None
 } else {
 // is direction reversed?
 let dot: f64 = predicted_delta.iter().zip(observed_delta.iter())
 .map(|(p, o)| p * o).sum();
 if dot < 0.0 && pred_mag > 1e-6 && obs_mag > 1e-6 {
 Some(ClosureMismatchReason::AdversarialInterference)
 } else if deviation > tolerance * 5.0 {
 Some(ClosureMismatchReason::ExcessiveDeviation {
 predicted_magnitude: pred_mag,
 observed_magnitude: obs_mag,
 })
 } else {
 Some(ClosureMismatchReason::StochasticEnvironment)
 }
 };

 Self {
 action_tick, observation_tick,
 predicted_delta_hash: predicted_hash,
 observed_delta_hash: observed_hash,
 matched, mismatch_reason, tolerance,
 }
 }

 /// case when previous action_effect did not exist.
 pub fn no_action(tick: u64) -> Self {
 Self {
 action_tick: tick.saturating_sub(1),
 observation_tick: tick,
 predicted_delta_hash: IntegrityHash::zero(),
 observed_delta_hash: IntegrityHash::zero(),
 matched: false,
 mismatch_reason: Some(ClosureMismatchReason::NoActionToVerify),
 tolerance: 0.0,
 }
 }
}

/// result of step(). has all three-layer losses.
#[derive(Debug, Clone)]
pub struct StepResult {
 /// kernel report. empty if dharma gate rejected.
 pub reports: Vec<IntegratedStepReport>,
 /// what world window dropped (first layer).
 pub encoding_losses: Vec<EncodingLoss>,
 /// what dharma gate rejected (second layer).
 pub dharma_rejections: Vec<DharmaRejection>,
 /// dharma gate quality score. None = dharma gate rejected.
 pub dharma_quality: Option<f64>,
 /// v1.3: how world processed action. None = dharma gate rejection or no action.
 pub action_effect: Option<ActionEffect>,
 /// v10.5: complete result of cross observation. OS generated.
 pub cross_observations: Vec<CrossObservationSummary>,
 /// timing of this step.
 pub tick: u64,
 /// v10.7: world window testimony verification result. None = no testimony.
 pub attestation_verdict: Option<AttestationVerdict>,
 /// v10.7b: step rejected because session is open but absent.
 /// v10.7b: Session open absent, step rejected.
 pub session_refused: bool,
 /// v10.8: closed-loop proof of perception-action-re-observation.
 /// v10.8: Perception-action-reobservation closed-loop proof.
 /// Previous action confirmed in this encode?
 pub closure_proof: Option<ClosureProof>,
}

impl StepResult {
 /// did signal reach kernel?
 pub fn reached_kernel(&self) -> bool { !self.reports.is_empty() && !self.session_refused }
}

