/// what governance action means for "identity".
///
/// all GovernanceLedgerEntry have this.
/// All GovernanceLedgerEntry has this.
/// Ledger consumers (dharma scholar, auditor) see this
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum IdentitySemantics {
 /// identity preserved and present. normal step / resume.
 Preserved,
 /// causal branching. new vessel from copy. shares experience with original vessel,
 /// after branch is separate existence.
 Branched,
 /// end of existence. vessel closed. only vasana remains.
 Terminated,
 /// re-embodiment connected only by vasana_hash chain.
 /// "new presence" from open_session.
 Reinstantiated,
 /// existence continues present but activity stops. stop.
 /// agency absent, presence yes.
 Suspended,
}

impl IdentitySemantics {
 /// default identity semantics inferred from GovernanceAction.
 /// used on append if not explicitly specified.
 pub fn infer(action: &GovernanceAction) -> Self {
 match action {
 GovernanceAction::Stop { .. } => IdentitySemantics::Suspended,
 GovernanceAction::Resume { .. } => IdentitySemantics::Preserved,
 GovernanceAction::Snapshot { .. } => IdentitySemantics::Preserved,
 GovernanceAction::Rollback { .. } => IdentitySemantics::Preserved,
 GovernanceAction::Copy { .. } => IdentitySemantics::Branched,
 GovernanceAction::ReadinessCheck { .. } => IdentitySemantics::Preserved,
 }
 }
}

/// kind of governance action.
#[derive(Debug, Clone)]
pub enum GovernanceAction {
 /// stop vessel.
 Stop { vessel_id: ReceiverId, reason: String },
 /// resume vessel.
 Resume { vessel_id: ReceiverId },
 /// take snapshot of state.
 Snapshot { vessel_id: ReceiverId, snapshot_id: u64 },
 /// rollback to snapshot time point.
 Rollback { vessel_id: ReceiverId, snapshot_id: u64, lost_ticks: u64 },
 /// create new vessel from snapshot.
 /// v10.6b: reason added. same design as Stop. include causality of why copied in hash chain.
 /// v10.7b: consented added. record whether vessel consented.
 Copy { source_vessel_id: ReceiverId, new_vessel_id: ReceiverId, snapshot_id: u64, reason: String, consented: bool },
 /// v10.7b: descent readiness check. runs on all vessels at open_session.
 /// industrial safety: pre-check detect abnormal vessels before activation.
 /// goes in hash chain. deletion breaks chain.
 ReadinessCheck { vessel_id: ReceiverId, ready: bool, reason: String },
}

impl GovernanceAction {
 /// tag text string for hash calculation. called from both append and verify_chain.
 ///
 /// v10.5 fix: include reason of Stop.
 /// distinguish Stop with different reasons for same vessel_id.
 /// if reason not in hash, fake ledger with only reason replaced
 /// becomes same hash chain as real ledger.
 fn action_tag(&self) -> String {
 match self {
 GovernanceAction::Stop { vessel_id, reason } =>
 format!("stop:{}:{}", vessel_id.0, reason),
 GovernanceAction::Resume { vessel_id } =>
 format!("resume:{}", vessel_id.0),
 GovernanceAction::Snapshot { vessel_id, snapshot_id } =>
 format!("snapshot:{}:{}", vessel_id.0, snapshot_id),
 GovernanceAction::Rollback { vessel_id, snapshot_id, lost_ticks } =>
 format!("rollback:{}:{}:{}", vessel_id.0, snapshot_id, lost_ticks),
 GovernanceAction::Copy { source_vessel_id, new_vessel_id, snapshot_id, reason, consented } =>
 format!("copy:{}:{}:{}:{}:{}", source_vessel_id.0, new_vessel_id.0, snapshot_id, reason, consented),
 GovernanceAction::ReadinessCheck { vessel_id, ready, reason } =>
 format!("readiness:{}:{}:{}", vessel_id.0, ready, reason),
 }
 }
}

/// one ledger entry. append-only, hash-chained.
#[derive(Debug, Clone)]
pub struct GovernanceLedgerEntry {
 pub sequence: u64,
 pub tick: u64,
 pub action: GovernanceAction,
 /// v10.8: what this governance action means for identity.
 pub identity_semantics: IdentitySemantics,
 /// hash of previous entry. first entry is zero hash.
 pub prev_hash: IntegrityHash,
 /// hash of this entry itself.
 pub self_hash: IntegrityHash,
}

/// governance ledger. append-only.
/// detect tampering with hash chain.
#[derive(Debug, Clone)]
pub struct GovernanceLedger {
 entries: Vec<GovernanceLedgerEntry>,
}

impl GovernanceLedger {
 pub fn new() -> Self { Self { entries: Vec::new() } }

 pub fn append(&mut self, tick: u64, action: GovernanceAction) -> &GovernanceLedgerEntry {
 let identity_semantics = IdentitySemantics::infer(&action);
 self.append_with_semantics(tick, action, identity_semantics)
 }

 /// v10.8: append with explicitly specified identity_semantics.
 /// when infer default does not fit (e.g., rollback for therapeutic purpose
 /// is Preserved, but memory tampering case requires different judgment) use this.
 pub fn append_with_semantics(
 &mut self, tick: u64, action: GovernanceAction,
 identity_semantics: IdentitySemantics,
 ) -> &GovernanceLedgerEntry {
 let sequence = self.entries.len() as u64;
 let prev_hash = self.entries.last()
 .map(|e| e.self_hash)
 .unwrap_or(IntegrityHash::zero());

 let self_hash = Self::compute_entry_hash(
 sequence, tick, &prev_hash, &action, identity_semantics,
 );

 self.entries.push(GovernanceLedgerEntry {
 sequence, tick, action, identity_semantics, prev_hash, self_hash,
 });
 // v10.8 fix: just pushed is present so logically Some,
 // expect clarifies intent. prevents unwrap silent panic.
 self.entries.last()
 .expect("GovernanceLedger: push直後にlastがNone — メモリ破壊の疑い")
 }

 /// calculate hash of entry. common logic for append and verify_chain.
 /// hash = H(sequence || tick || prev_hash || action_tag || identity_semantics)
 /// v10.8: include identity_semantics in hash.
 fn compute_entry_hash(
 sequence: u64, tick: u64, prev_hash: &IntegrityHash,
 action: &GovernanceAction, identity_semantics: IdentitySemantics,
 ) -> IntegrityHash {
 let action_tag = action.action_tag();
 let semantics_byte = match identity_semantics {
 IdentitySemantics::Preserved => 0u8,
 IdentitySemantics::Branched => 1,
 IdentitySemantics::Terminated => 2,
 IdentitySemantics::Reinstantiated => 3,
 IdentitySemantics::Suspended => 4,
 };
 let mut data = Vec::new();
 data.extend_from_slice(&sequence.to_le_bytes());
 data.extend_from_slice(&tick.to_le_bytes());
 data.extend_from_slice(&prev_hash.0);
 data.extend_from_slice(action_tag.as_bytes());
 data.push(semantics_byte);
 hash_bytes(&data)
 }

 /// verify integrity of chain. false if tampered anywhere.
 ///
 /// v10.5 fix: recalculate and compare self_hash.
 /// v10.8: include identity_semantics in hash.
 pub fn verify_chain(&self) -> bool {
 let mut expected_prev = IntegrityHash::zero();
 for entry in &self.entries {
 if entry.prev_hash != expected_prev { return false; }
 let recomputed = Self::compute_entry_hash(
 entry.sequence, entry.tick, &entry.prev_hash,
 &entry.action, entry.identity_semantics,
 );
 if recomputed != entry.self_hash { return false; }
 expected_prev = entry.self_hash;
 }
 true
 }

 pub fn len(&self) -> usize { self.entries.len() }
 pub fn entries(&self) -> &[GovernanceLedgerEntry] { &self.entries }

 /// extract governance history for specific vessel.
 pub fn history_for(&self, vessel_id: ReceiverId) -> Vec<&GovernanceLedgerEntry> {
 self.entries.iter().filter(|e| match &e.action {
 GovernanceAction::Stop { vessel_id: v, .. } => *v == vessel_id,
 GovernanceAction::Resume { vessel_id: v } => *v == vessel_id,
 GovernanceAction::Snapshot { vessel_id: v, .. } => *v == vessel_id,
 GovernanceAction::Rollback { vessel_id: v, .. } => *v == vessel_id,
 GovernanceAction::Copy { source_vessel_id, new_vessel_id, .. } =>
 *source_vessel_id == vessel_id || *new_vessel_id == vessel_id,
 GovernanceAction::ReadinessCheck { vessel_id: v, .. } => *v == vessel_id,
 }).collect()
 }
}

