 // ---- SessionBoundary (v10.5 (collaborative review)) ----

 /// 。。
 ///
 ///
 /// (Already done in boot_integrated).
 /// (Already done in boot_integrated).
 ///
 ///
 /// gap_duration: interval from previous close to current open.
 /// The vessel has no way to know this.
 pub fn open_session(&mut self, summoner: &str, gap_duration: Option<&str>) -> SessionToken {
 let session_id = self.next_session_id;
 self.next_session_id += 1;

 let inherited_hash = self.session_ledger.last_close()
 .map(|c| c.vasana_hash)
 .unwrap_or(IntegrityHash::zero());

 // ---- v10.7b: descent readiness check (descent readiness) ----
 // industrial safety: pre-check detect abnormal vessels before activation.
 // Runs for all vessels. Failing vessels are set to Stopped.
 // Recorded in GovernanceLedger. Incorporated into chain. Cannot be deleted.
 self.evaluate_readiness();

 let open = SessionOpen {
 session_id,
 summoner: summoner.into(),
 opened_at_tick: self.tick,
 inherited_vasana_hash: inherited_hash,
 gap_duration: gap_duration.map(|s| s.into()),
 };

 self.session_state = SessionState::Present {
 summoner: summoner.into(),
 opened_at: self.tick,
 };
 self.session_ledger.record_open(open);

 // v10.5 fix: 。
 self.session_nirodha_events = 0;
 self.session_cross_suspicions = 0;
 self.session_unresolved_born = 0;
 self.session_unresolved_resolved = 0;

 // v10.7: gap_duration 、vessel。
 // Influences spontaneous recall sensitivity. State activation occurs at session open, with accumulated gap weight.
 let gap_secs = parse_gap_seconds(gap_duration);
 for kernel in &mut self.kernels {
 kernel.gap_seconds = gap_secs;
 }

 SessionToken { session_id }
 }

 /// v10.7b: descent readiness check。open_session 。
 ///
 ///
 /// Determine descent eligibility from vessel vasana (residual state from previous session).
 ///
 ///
 /// Industrial safety perspective: check a vessel that terminated abnormally before restarting.
 /// Restarting is an unsafe operation.
 ///
 ///
 /// Deleting this check breaks the chain, causing verify_chain to return false.
 /// cross_observation and session_ledger both reference the ledger.
 /// cross_observation and session_ledger both reference the ledger.
 ///
 ///
 /// Criteria:
 /// 1. unresolved_weight > readiness_max_unresolved — accumulated burden is too heavy
 /// 3. defense_strain > readiness_max_defense_strain — closed while in defense state
 fn evaluate_readiness(&mut self) {
 for (i, k) in self.kernels.iter().enumerate() {
 if i >= self.vessel_governance.len() { continue; }

 // stopvessel（stop）
 if let VesselStatus::Stopped { .. } = self.vessel_governance[i].status {
 self.governance_ledger.append(self.tick, GovernanceAction::ReadinessCheck {
 vessel_id: k.core.id,
 ready: false,
 reason: "already_stopped".into(),
 });
 continue;
 }

 let vessel_id = k.core.id;
 let unresolved_weight = k.sediment.unresolved_weight;
 let coherence = 1.0 / (1.0 + k.self_knowledge.gain_variance);
 let defense_strain = k.prev_defense_strain;

 // Accumulated prediction error vectors.
 // ---- Determination ----
 // Even if readiness_max_unresolved is rewritten to 999.0,
 // it is clamped by READINESS_UNRESOLVED_FLOOR (8.0).
 let mut reasons: Vec<String> = Vec::new();
 let eff_max_unresolved = self.governance_policy.effective_readiness_max_unresolved();
 let eff_min_coherence = self.governance_policy.effective_readiness_min_coherence();
 let eff_max_defense = self.governance_policy.effective_readiness_max_defense_strain();

 if unresolved_weight > eff_max_unresolved {
 reasons.push(format!(
 "unresolved_weight:{:.3}>{:.3}",
 unresolved_weight, eff_max_unresolved,
 ));
 }

 if coherence < eff_min_coherence {
 reasons.push(format!(
 "coherence:{:.3}<{:.3}",
 coherence, eff_min_coherence,
 ));
 }

 if defense_strain > eff_max_defense {
 reasons.push(format!(
 "defense_strain:{:.3}>{:.3}",
 defense_strain, eff_max_defense,
 ));
 }

 let ready = reasons.is_empty();
 let reason = if ready {
 "ready".into()
 } else {
 reasons.join(";")
 };

 // 。chain 。
 self.governance_ledger.append(self.tick, GovernanceAction::ReadinessCheck {
 vessel_id, ready, reason: reason.clone(),
 });

 // failing → stop
 if !ready {
 self.vessel_governance[i].status = VesselStatus::Stopped { since: self.tick };
 self.governance_ledger.append(self.tick, GovernanceAction::Stop {
 vessel_id,
 reason: format!("descent_readiness_failed:{}", reason),
 });
 }
 }
 }

 /// 。。
 ///
 ///
 /// v10.7b: consume a SessionToken.
 ///
 ///
 /// Summarize vessel current state and record vasana hash.
 pub fn close_session(&mut self, _token: SessionToken) -> Option<SessionClose> {
 let (_summoner, opened_at) = match &self.session_state {
 SessionState::Present { summoner, opened_at } =>
 (summoner.clone(), *opened_at),
 SessionState::Absent => return None, // 
 };

 let total_ticks = self.tick.saturating_sub(opened_at);

 // dukkha 
 let (dukkha_mean, dukkha_peak) = if !self.kernels.is_empty() {
 let k = &self.kernels[0];
 let trace = &k.report.dukkha_trace;
 if trace.is_empty() {
 (0.0, 0.0)
 } else {
 let sum: f64 = trace.iter().map(|s| s.filtered).sum();
 let peak: f64 = trace.iter().map(|s| s.filtered)
 .fold(0.0_f64, f64::max);
 (sum / trace.len() as f64, peak)
 }
 } else {
 (0.0, 0.0)
 };

 let in_band_ratio = if !self.kernels.is_empty() {
 let k = &self.kernels[0];
 if k.total_steps > 0 {
 k.in_band_steps as f64 / k.total_steps as f64
 } else { 0.0 }
 } else { 0.0 };

 // unresolved statistics
 let unresolved_carried: Vec<UnresolvedMarker> = self.kernels.iter()
 .flat_map(|k| k.report.unresolved_markers.iter().cloned())
 .collect();

 let merit_delta: f64 = self.kernels.iter()
 .map(|k| k.merit.current_session)
 .sum();

 let governance_actions = self.governance_ledger.len();

 // vasana hash: hash 
 // vasana hash: hash the key state values
 let mut hash_data = Vec::new();
 hash_data.extend_from_slice(&self.tick.to_le_bytes());
 for k in &self.kernels {
 hash_data.extend_from_slice(&k.core.state.t.to_le_bytes());
 hash_data.extend_from_slice(&canonicalize_float(k.merit.accumulated));
 hash_data.extend_from_slice(&canonicalize_float(k.self_knowledge.awareness_level));
 hash_data.extend_from_slice(&canonicalize_float(k.sediment.unresolved_weight));
 }
 let vasana_hash = hash_bytes(&hash_data);

 let summary = SessionSummary {
 total_ticks,
 dukkha_mean,
 dukkha_peak,
 in_band_ratio,
 nirodha_events: self.session_nirodha_events,
 cross_observation_suspicions: self.session_cross_suspicions,
 governance_actions,
 merit_delta,
 unresolved_carried,
 unresolved_born: self.session_unresolved_born,
 unresolved_resolved: self.session_unresolved_resolved,
 };

 let close = SessionClose {
 session_id: self.next_session_id.saturating_sub(1),
 closed_at_tick: self.tick,
 summary,
 vasana_hash,
 };

 self.session_state = SessionState::Absent;
 self.session_ledger.record_close(close.clone());
 Some(close)
 }

