// §27 Dimension adaptation — seed construction for world port
// ============================================================

/// next。
/// Build seed aligned with the dimensionality of the world window.
/// Even if the dimensionality changes, the "meaning" of the seed does not change.
pub fn adapt_seed_dim(seed: &IntegratedSeed, target_dim: usize) -> IntegratedSeed {
 if seed.dim == target_dim { return seed.clone(); }

 let adapt_vec = |v: &[f64], default: f64| -> Vec<f64> {
 let mut out = vec![default; target_dim];
 for i in 0..v.len().min(target_dim) { out[i] = v[i]; }
 out
 };
 let adapt_bp = |v: &[BasisPoints], default: BasisPoints| -> Vec<BasisPoints> {
 let mut out = vec![default; target_dim];
 for i in 0..v.len().min(target_dim) { out[i] = v[i]; }
 out
 };
 let adapt_dir = |v: &[f64]| -> Vec<f64> {
 let mut out = vec![0.0; target_dim];
 for i in 0..v.len().min(target_dim) { out[i] = v[i]; }
 let norm: f64 = out.iter().map(|x| x * x).sum::<f64>().sqrt();
 if norm > 1e-10 { for x in &mut out { *x /= norm; } }
 out
 };

 IntegratedSeed {
 name: seed.name.clone(),
 receiver_id: seed.receiver_id,
 dim: target_dim,
 vow: VowMetric {
 name: seed.vow.name.clone(),
 weights: adapt_vec(&seed.vow.weights, 1.0),
 },
 nominal_bp: adapt_bp(&seed.nominal_bp, BasisPoints::new(100)),
 noise_floor: adapt_vec(&seed.noise_floor, 0.1),
 descent_vow: seed.descent_vow.clone(),
 maintainer: seed.maintainer.clone(),
 transducer_config: match &seed.transducer_config {
 TransducerConfig::Linear => TransducerConfig::Linear,
 TransducerConfig::Nonlinear { saturation, hysteresis, cross_coupling } =>
 TransducerConfig::Nonlinear {
 saturation: *saturation, hysteresis: *hysteresis,
 cross_coupling: *cross_coupling,
 },
 },
 inherited_merit: seed.inherited_merit,
 vessel_capacity: seed.vessel_capacity,
 skandhas: seed.skandhas.iter().map(|s| Skandha {
 name: s.name.clone(), intensity: s.intensity,
 anisotropy: adapt_vec(&s.anisotropy, 0.0),
 impermanence: s.impermanence,
 }).collect(),
 initially_unconscious: seed.initially_unconscious.clone(),
 filter_modes: seed.filter_modes.iter().map(|m| ReceptionMode {
 direction: adapt_dir(&m.direction),
 sensitivity: m.sensitivity, name: m.name.clone(),
 }).collect(),
 filter_rejections: seed.filter_rejections.iter().map(|r| RejectionPattern {
 direction: adapt_dir(&r.direction),
 strength: r.strength, origin: r.origin.clone(),
 }).collect(),
 }
}

