/// LLM encoding。。
///
///
///
pub struct LlmSemanticEncoder {
 /// LLM 。 → four-element。
 /// None fallback (NaiveEncoder)。
 encode_fn: Box<dyn Fn(&str) -> Option<[f64; 4]> + Send + Sync>,
 fallback: NaiveEncoder,
 model_id: String,
}

impl LlmSemanticEncoder {
 pub fn new(
 model_id: &str,
 encode_fn: impl Fn(&str) -> Option<[f64; 4]> + Send + Sync + 'static,
 ) -> Self {
 Self {
 encode_fn: Box::new(encode_fn),
 fallback: NaiveEncoder::new(),
 model_id: model_id.into(),
 }
 }
}

impl SemanticEncoder for LlmSemanticEncoder {
 fn encode_text(&self, text: &str) -> SemanticEncodeResult {
 match (self.encode_fn)(text) {
 Some(elements) => {
 // LLM 。confidence high、。
 SemanticEncodeResult {
 elements,
 losses: vec![EncodingLoss {
 channel: "llm_opacity".into(),
 estimated_magnitude: Some(0.0),
 reason: EncodingLossReason::Unknown,
 }],
 confidence: 0.8,
 uninterpretable: vec![],
 }
 }
 None => {
 // LLM failure.fallback.confidence low.
 let mut result = self.fallback.encode_text(text);
 result.confidence *= 0.5; // fallback 
 result.losses.push(EncodingLoss {
 channel: "llm_fallback".into(),
 estimated_magnitude: Some(0.5),
 reason: EncodingLossReason::Unknown,
 });
 result
 }
 }
 }
 fn config_bytes(&self) -> Vec<u8> {
 format!("llm_{}",self.model_id).into_bytes()
 }
 fn name(&self) -> &str { "LlmSemanticEncoder" }
}

