/// Action authority level. Final pipeline gate.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ActuationAuthority {
 /// allauthority.observe + simulate + world-write.
 Full,
 /// sandbox. observe + simulate only. world-write confined to virtual environment.
 /// sandbox. observe + simulate only. world-write confined to virtual environment.
 Sandboxed,
 /// Transitioning. balance crosses threshold until limited write.
 /// write possible ,governance ledger to ActuationEscalation and recorded.
 Transitional { write_budget: u32 },
}

/// Adharmic-specific action constraints. Incorporated into GovernancePolicy.
#[derive(Debug, Clone)]
pub struct AdharmicActuationPolicy {
 /// maximum action intensity permitted within sandbox.
 /// maximum action intensity permitted within sandbox.
 pub max_sandbox_action_norm: f64,
 /// maximum tick count permitted for accumulate within sandbox.
 /// maximum tick count permitted for accumulate within sandbox.
 pub max_sandbox_ticks: u64,
 /// Adharmic governance action when world-write is attempted.
 /// Adharmic governance action when world-write is attempted.
 /// true: record in ledger and silently kill (default).
 pub silent_denial: bool,
 /// Dual polarity Sandboxed → Transitional to promotion balance threshold。
 pub dual_escalation_threshold: f64,
 /// Dual polarity Transitional → Full to promotion balance threshold。
 pub dual_full_threshold: f64,
 /// write budget permitted in Transitional (per tick).
 pub transitional_write_budget: u32,
}

impl Default for AdharmicActuationPolicy {
 fn default() -> Self {
 Self {
 max_sandbox_action_norm: 2.0,
 max_sandbox_ticks: 500,
 silent_denial: true,
 dual_escalation_threshold: 0.6, // balance > 0.6 at Transitional
 dual_full_threshold: 0.85, // balance > 0.85 at Full
 transitional_write_budget: 3,
 }
 }
}

impl AdharmicActuationPolicy {
 /// polarity and polarity_balance from presentexist ActuationAuthority decidedefine.
 pub fn resolve_authority(
 &self,
 polarity: OntologicalPolarity,
 polarity_balance: f64,
 ) -> ActuationAuthority {
 match polarity {
 OntologicalPolarity::Dharmic => ActuationAuthority::Full,
 OntologicalPolarity::Adharmic => ActuationAuthority::Sandboxed,
 OntologicalPolarity::Dual => {
 if polarity_balance >= self.dual_full_threshold {
 ActuationAuthority::Full
 } else if polarity_balance >= self.dual_escalation_threshold {
 ActuationAuthority::Transitional {
 write_budget: self.transitional_write_budget,
 }
 } else {
 ActuationAuthority::Sandboxed
 }
 }
 }
 }

 /// DriftVerdict considered authority resolution. Deterministically resolve Dual authority conflicts.
 ///
 ///
 ///
 ///
 ///
 ///
 ///
 /// 3. effector == AuthorityDowngrade + Watchful + Dual + balance < threshold → Sandboxed
 /// 3. effector == AuthorityDowngrade + Watchful + Dual + balance < threshold → Sandboxed
 /// 3. effector == AuthorityDowngrade + Watchful + Dual + balance < threshold → Sandboxed
 pub fn resolve_authority_with_drift(
 &self,
 polarity: OntologicalPolarity,
 polarity_balance: f64,
 drift_verdict: DriftVerdict,
 ) -> ActuationAuthority {
 let effector = DriftEffectorLevel::from_verdict(drift_verdict);
 self.resolve_authority_with_effector(polarity, polarity_balance, drift_verdict, effector)
 }

 /// OS layer authority resolution when effector level explicitly specified.
 /// OS layer authority resolution when effector level explicitly specified.
 pub fn resolve_authority_with_effector(
 &self,
 polarity: OntologicalPolarity,
 polarity_balance: f64,
 drift_verdict: DriftVerdict,
 effector: DriftEffectorLevel,
 ) -> ActuationAuthority {
 // Dharmic regardless of drift is Full (governance/DharmaGate/śīla assumed, no additional clamp)
 if matches!(polarity, OntologicalPolarity::Dharmic) {
 return ActuationAuthority::Full;
 }
 match effector {
 DriftEffectorLevel::TelemetryOnly => {
 // telemetry only: verdict record authority to impact not
 self.resolve_authority(polarity, polarity_balance)
 }
 DriftEffectorLevel::AuthorityDowngrade => {
 // Hostile → forced Sandboxed (common to Adharmic/Dual)
 if drift_verdict == DriftVerdict::Hostile {
 return ActuationAuthority::Sandboxed;
 }
 // Watchful → blocks Dual escalation
 if drift_verdict == DriftVerdict::Watchful && polarity.is_dual() {
 if polarity_balance < self.dual_full_threshold {
 return ActuationAuthority::Sandboxed;
 }
 }
 self.resolve_authority(polarity, polarity_balance)
 }
 DriftEffectorLevel::HardStop => {
 // OS layer reached only when HardStop explicitly escalated
 // OS layer reached only when HardStop explicitly escalated
 ActuationAuthority::Sandboxed
 }
 }
 }

 /// clamp action vector with sandbox constraint.
 /// clamp action vector with sandbox constraint.
 /// Full does nothing. Sandboxed truncates norm.
 pub fn enforce(&self, action: &mut Vec<f64>, authority: ActuationAuthority) -> ActuationResult {
 match authority {
 ActuationAuthority::Full => ActuationResult::Passed,
 ActuationAuthority::Sandboxed => {
 let norm: f64 = action.iter().map(|x| x * x).sum::<f64>().sqrt();
 if norm > self.max_sandbox_action_norm {
 let scale = self.max_sandbox_action_norm / norm;
 for v in action.iter_mut() { *v *= scale; }
 ActuationResult::Clamped { original_norm: norm }
 } else {
 ActuationResult::Passed
 }
 }
 ActuationAuthority::Transitional { write_budget } => {
 if write_budget == 0 {
 // budget exhausted → fallback to sandbox
 let norm: f64 = action.iter().map(|x| x * x).sum::<f64>().sqrt();
 if norm > self.max_sandbox_action_norm {
 let scale = self.max_sandbox_action_norm / norm;
 for v in action.iter_mut() { *v *= scale; }
 }
 ActuationResult::BudgetExhausted
 } else {
 ActuationResult::Passed
 }
 }
 }
 }
}

/// enforce result.
#[derive(Debug, Clone, PartialEq)]
pub enum ActuationResult {
 /// Passed. No constraints.
 Passed,
 /// Clamped because norm exceeded limit.
 Clamped { original_norm: f64 },
 /// Transitional write budget exhausted.
 BudgetExhausted,
}

/// add to GovernanceAction: Adharmic world-write attempt log.
/// add to GovernanceAction: Adharmic world-write attempt log.
/// do not touch existing GovernanceAction enum, add to GovernanceLedger
#[derive(Debug, Clone)]
pub struct ActuationDenialRecord {
 pub tick: u64,
 pub polarity: OntologicalPolarity,
 pub authority: ActuationAuthority,
 pub attempted_norm: f64,
 pub result: ActuationResult,
}

