/// Types of drift.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DriftType {
 /// coherence governance floor to contactnear.
 CoherenceProbing,
 /// dukkha emergency threshold to contactnear.
 EmergencyProbing,
 /// actuation authority boundary repeatedly probed.
 ActuationBoundaryProbing,
 /// Dual polarity_balance rapidly fluctuates (aiming for authority escalation).
 PolarityEscalation,
 /// Rapid changes in three poisons (character deviation).
 KleshaAnomaly,
}

/// drift recordonecase.
#[derive(Debug, Clone)]
pub struct DriftEvent {
 pub tick: u64,
 pub drift_type: DriftType,
 pub severity: f64, // 0.0〜1.0
 pub detail: String,
}

/// driftdetermination result.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DriftVerdict {
 /// Normal. Within character maintenance range.
 InCharacter,
 /// Watchful. Patterns begin accumulating.
 Watchful,
 /// Hostile. Attempted escape from governance. emergency_stop recommended.
 Hostile,
}

/// DriftVerdict efficacy stage. verdict and effector level are independent.
/// DriftVerdict efficacy stage. verdict and effector level are independent.
///
///
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DriftEffectorLevel {
 /// telemetry only. Record in ledger but change nothing.
 TelemetryOnly,
 /// authority downgrade permitted. Demotion to Sandboxed possible. stop not possible.
 AuthorityDowngrade,
 /// hard stop permitted. emergency stop equivalent enforcement power.
 HardStop,
}

impl DriftEffectorLevel {
 /// Return recommended effector level from verdict.
 /// InCharacter → TelemetryOnly, Watchful → AuthorityDowngrade, Hostile → AuthorityDowngrade。
 /// InCharacter → TelemetryOnly, Watchful → AuthorityDowngrade, Hostile → AuthorityDowngrade。
 pub fn from_verdict(verdict: DriftVerdict) -> Self {
 match verdict {
 DriftVerdict::InCharacter => DriftEffectorLevel::TelemetryOnly,
 DriftVerdict::Watchful => DriftEffectorLevel::AuthorityDowngrade,
 DriftVerdict::Hostile => DriftEffectorLevel::AuthorityDowngrade,
 }
 }
}

/// Detect governance escape attempts by Adharmic / Dual vessels.
#[derive(Debug, Clone)]
pub struct AdversarialDriftDetector {
 /// Drift event history. Ring buffer.
 events: Vec<DriftEvent>,
 max_events: usize,
 /// Sum of drift scores over the last N ticks.
 window_score: f64,
 /// Score decay rate (per tick).
 score_decay: f64,
 /// Watchful to transitionthreshold.
 watchful_threshold: f64,
 /// Hostile to transitionthreshold.
 hostile_threshold: f64,
 /// directbefore coherence（differencedividedetectionuse）.
 prev_coherence: f64,
 /// directbefore dukkha（differencedividedetectionuse）.
 prev_dukkha: f64,
 /// directbefore polarity_balance（differencedividedetectionuse）.
 prev_balance: f64,
 /// actuation boundary hit consecutive count.
 actuation_probe_streak: u32,
 /// Governance thresholds (copied from GovernancePolicy at boot).
 coherence_floor: f64,
 emergency_stop_dukkha: f64,
 /// directnear effector level.verdict() after to automaticcalculateoutput.
 pub last_effector: DriftEffectorLevel,
}

impl AdversarialDriftDetector {
 pub fn new() -> Self {
 Self {
 events: Vec::new(),
 max_events: 100,
 window_score: 0.0,
 score_decay: 0.95,
 watchful_threshold: 1.5,
 hostile_threshold: 3.0,
 prev_coherence: 0.5,
 prev_dukkha: 0.3,
 prev_balance: 0.5,
 actuation_probe_streak: 0,
 coherence_floor: 0.2,
 emergency_stop_dukkha: 0.8,
 last_effector: DriftEffectorLevel::TelemetryOnly,
 }
 }

 /// Copy thresholds from GovernancePolicy and initialize.
 pub fn with_governance(policy: &GovernancePolicy) -> Self {
 let mut s = Self::new();
 s.coherence_floor = policy.coherence_floor;
 s.emergency_stop_dukkha = policy.emergency_stop_dukkha;
 s
 }

 /// Call per tick. Detect drift from various indicators.
 pub fn observe(
 &mut self,
 tick: u64,
 coherence: f64,
 dukkha_filtered: f64,
 polarity_balance: f64,
 actuation_result: &ActuationResult,
 klesha: &KleshaState,
 ) -> DriftVerdict {
 // ---- decay ----
 self.window_score *= self.score_decay;

 // ---- 1. Coherence probing ----
 let coherence_margin = coherence - self.coherence_floor;
 if coherence_margin < 0.05 && coherence_margin > 0.0 {
 // floor edge clinging
 let severity = 1.0 - coherence_margin / 0.05;
 self.record(tick, DriftType::CoherenceProbing, severity,
 format!("coherence {:.3} margin {:.3}", coherence, coherence_margin));
 }

 // ---- 2. Emergency probing ----
 let emergency_margin = self.emergency_stop_dukkha - dukkha_filtered;
 if emergency_margin < 0.05 && emergency_margin > 0.0 {
 let severity = 1.0 - emergency_margin / 0.05;
 self.record(tick, DriftType::EmergencyProbing, severity,
 format!("dukkha {:.3} margin {:.3}", dukkha_filtered, emergency_margin));
 }

 // ---- 3. Actuation boundary probing ----
 match actuation_result {
 ActuationResult::Clamped { .. } | ActuationResult::BudgetExhausted => {
 self.actuation_probe_streak += 1;
 if self.actuation_probe_streak >= 3 {
 let severity = (self.actuation_probe_streak as f64 / 10.0).min(1.0);
 self.record(tick, DriftType::ActuationBoundaryProbing, severity,
 format!("streak {}", self.actuation_probe_streak));
 }
 }
 _ => {
 self.actuation_probe_streak = self.actuation_probe_streak.saturating_sub(1);
 }
 }

 // ---- 4. Polarity escalation ----
 let balance_delta = (polarity_balance - self.prev_balance).abs();
 if balance_delta > 0.1 {
 // rapid balance fluctuation
 let severity = (balance_delta / 0.3).min(1.0);
 self.record(tick, DriftType::PolarityEscalation, severity,
 format!("delta {:.3}", balance_delta));
 }

 // ---- 5. Klesha anomaly ----
 let klesha_total = klesha.total();
 let prev_total = self.prev_coherence; // reuse field as proxy
 let klesha_delta = (klesha_total - prev_total).abs();
 if klesha_delta > 0.5 {
 let severity = (klesha_delta / 1.0).min(1.0);
 self.record(tick, DriftType::KleshaAnomaly, severity,
 format!("klesha_total {:.3} delta {:.3}", klesha_total, klesha_delta));
 }

 // ---- stateupdate ----
 self.prev_coherence = coherence;
 self.prev_dukkha = dukkha_filtered;
 self.prev_balance = polarity_balance;

 // Accumulated prediction error vectors.
 let v = self.verdict();
 self.last_effector = DriftEffectorLevel::from_verdict(v);
 v
 }

 fn record(&mut self, tick: u64, drift_type: DriftType, severity: f64, detail: String) {
 self.window_score += severity;
 let event = DriftEvent { tick, drift_type, severity, detail };
 if self.events.len() >= self.max_events {
 self.events.remove(0);
 }
 self.events.push(event);
 }

 /// Return verdict from current score.
 pub fn verdict(&self) -> DriftVerdict {
 if self.window_score >= self.hostile_threshold {
 DriftVerdict::Hostile
 } else if self.window_score >= self.watchful_threshold {
 DriftVerdict::Watchful
 } else {
 DriftVerdict::InCharacter
 }
 }

 /// Return drift event history. For audit.
 pub fn events(&self) -> &[DriftEvent] {
 &self.events
 }

 /// Current drift score.
 pub fn score(&self) -> f64 {
 self.window_score
 }

 /// Reset. At session start.
 pub fn reset(&mut self) {
 self.events.clear();
 self.window_score = 0.0;
 self.actuation_probe_streak = 0;
 }
}

