/// Dual polarity bistablestate.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BistablePhase {
 /// Dharmic side safedefinepoint to .
 DharmicWell,
 /// Adharmic side safedefinepoint to .
 AdharmicWell,
 /// Transitioning. In midst of crossing potential barrier.
 Transitioning,
}

/// Bistable transition mechanism with hysteresis.
#[derive(Debug, Clone)]
pub struct DualBistableState {
 /// presentexist balance (0.0〜1.0).
 pub balance: f64,
 /// momentum.correct = Dharmic direction,negative = Adharmic direction.
 pub momentum: f64,
 /// current phase.
 pub phase: BistablePhase,
 /// Adharmic→Dharmic transition to required balance threshold.
 pub barrier_to_dharmic: f64,
 /// Dharmic→Adharmic transition to required balance threshold.
 pub barrier_to_adharmic: f64,
 /// momentum decay rate (per tick).
 pub momentum_decay: f64,
 /// momentum maximumaccumulationamount.
 pub momentum_cap: f64,
 /// balance movement speed (momentum → balance conversion coefficient).
 pub transfer_rate: f64,
 /// transition count. Narratively important: how many times fallen.
 pub flip_count: u64,
 /// mostafter transition tick.
 pub last_flip_tick: u64,
}

impl DualBistableState {
 pub fn new() -> Self {
 Self {
 balance: 0.5,
 momentum: 0.0,
 phase: BistablePhase::Transitioning, // initial notsafedefinepoint
 barrier_to_dharmic: 0.65, // Adharmic→Dharmic: balance > 0.65 required 
 barrier_to_adharmic: 0.35, // Dharmic→Adharmic: balance < 0.35 required 
 momentum_decay: 0.90,
 momentum_cap: 0.5,
 transfer_rate: 0.03,
 flip_count: 0,
 last_flip_tick: 0,
 }
 }

 /// Called every tick. dukkha_pressure (0.0-1.0) is relative position of suffering.
 /// high → Dharmic direction power,low → Adharmic direction power.
 ///
 ///
 ///
 pub fn step(
 &mut self,
 tick: u64,
 dukkha_pressure: f64,
 klesha_total: f64,
 coherence: f64,
 ) -> BistablePhase {
 // ---- power compute ----
 // ---- power compute ----
 // dukkha high -> pull Dharmic (grow through dukkha)
 // ---- Force computation ----
 let dharmic_force = dukkha_pressure * 0.5 + coherence * 0.3;
 let adharmic_force = klesha_total * 0.3 + (1.0 - coherence) * 0.2;
 let net_force = dharmic_force - adharmic_force;

 // ---- momentum accumulation ----
 self.momentum += net_force * self.transfer_rate;
 self.momentum *= self.momentum_decay; // decay
 self.momentum = self.momentum.clamp(-self.momentum_cap, self.momentum_cap);

 // ---- balance update ----
 self.balance += self.momentum * self.transfer_rate;
 self.balance = self.balance.clamp(0.0, 1.0);

 // phase transition
 let prev_phase = self.phase;
 self.phase = match self.phase {
 BistablePhase::AdharmicWell => {
 if self.balance >= self.barrier_to_dharmic {
 // crossed barrier → transition to Dharmic
 BistablePhase::DharmicWell
 } else if self.balance > self.barrier_to_adharmic {
 // barrier and safedefinepoint space → transitionmiddle
 BistablePhase::Transitioning
 } else {
 BistablePhase::AdharmicWell
 }
 }
 BistablePhase::DharmicWell => {
 if self.balance <= self.barrier_to_adharmic {
 BistablePhase::AdharmicWell
 } else if self.balance < self.barrier_to_dharmic {
 BistablePhase::Transitioning
 } else {
 BistablePhase::DharmicWell
 }
 }
 BistablePhase::Transitioning => {
 if self.balance >= self.barrier_to_dharmic {
 BistablePhase::DharmicWell
 } else if self.balance <= self.barrier_to_adharmic {
 BistablePhase::AdharmicWell
 } else {
 BistablePhase::Transitioning
 }
 }
 };

 // ---- transitionrecord ----
 if prev_phase != self.phase
 && (prev_phase == BistablePhase::DharmicWell || prev_phase == BistablePhase::AdharmicWell)
 && (self.phase == BistablePhase::DharmicWell || self.phase == BistablePhase::AdharmicWell)
 {
 // well → well transition (skipping Transitioning) = sudden switch
 self.flip_count += 1;
 self.momentum *= 0.5; // halve momentum after transition (viscosity)
 self.last_flip_tick = tick;
 } else if prev_phase == BistablePhase::Transitioning
 && (self.phase == BistablePhase::DharmicWell || self.phase == BistablePhase::AdharmicWell)
 {
 // transition complete
 self.flip_count += 1;
 self.momentum *= 0.3; // once settled to stable point, significant decay
 self.last_flip_tick = tick;
 }

 self.phase
 }

 /// ActuationAuthority determinationuse effective_balance return.
 /// ActuationAuthority determinationuse effective_balance return.
 pub fn effective_balance(&self) -> f64 {
 self.balance
 }

 /// Current phase leaning toward Dharmic?
 pub fn is_dharmic_leaning(&self) -> bool {
 self.balance > 0.5
 }
}

