// ============================================================
// §30 śīla — precepts (v10.7b)
// ============================================================

#[derive(Debug, Clone)]
pub struct Precept {
 pub name: String,
 pub direction: Vec<f64>,
 pub severity: f64,
 pub origin: String,
}

#[derive(Debug, Clone)]
pub struct SilaViolation {
 pub precept_name: String,
 pub projected_magnitude: f64,
 pub effective_removal: f64,
 pub partial_enforcement: bool,
}

#[derive(Debug, Clone, Default)]
pub struct SilaSummary {
 pub applied: bool,
 pub violations_detected: bool,
 pub violation_count: usize,
 pub total_removed: f64,
 pub violations: Vec<SilaViolation>,
}

pub fn apply_sila(action: &mut Action, precepts: &[Precept], awareness: f64) -> SilaSummary {
 if precepts.is_empty() { return SilaSummary::default(); }
 let mut violations = Vec::new();
 let mut total_removed = 0.0f64;
 let dim = action.vector.len();

 // v10.7b fix: calculate projection of all precepts first, then remove in bulk.
 // v10.7b fix: calculate projection of all precepts first, then remove in bulk.
 // sequential application: precept A changes action, then B checks after,
 let mut removal_vector = vec![0.0f64; dim];

 for precept in precepts {
 let pd = precept.direction.len().min(dim);
 if pd == 0 { continue; }

 // v10.7b fix: direction normalization。
 // v10.7b fix: direction normalization。
 // if not normalized, magnitude of direction affects removal amount.
 let dir_norm: f64 = precept.direction[..pd].iter()
 .map(|x| x * x).sum::<f64>().sqrt();
 if dir_norm < 1e-10 { continue; }
 let normalized: Vec<f64> = (0..pd).map(|i| precept.direction[i] / dir_norm).collect();

 let dot: f64 = (0..pd).map(|i| action.vector[i] * normalized[i]).sum();
 if dot <= 0.0 { continue; }

 let enforcement = (awareness * precept.severity).clamp(0.0, 1.0);
 let effective_removal = dot * enforcement;

 // accumulate in removal vector (action not yet changed)
 for i in 0..pd {
 removal_vector[i] += effective_removal * normalized[i];
 }
 total_removed += effective_removal;

 violations.push(SilaViolation {
 precept_name: precept.name.clone(), projected_magnitude: dot,
 effective_removal, partial_enforcement: enforcement < 0.99,
 });
 }

 // bulk removal
 if total_removed > 0.0 {
 for i in 0..dim {
 action.vector[i] -= removal_vector[i];
 }
 }

 let violations_detected = !violations.is_empty();
 if violations_detected && !action.label.contains("_sila") {
 action.label = format!("{}_sila", action.label);
 }
 SilaSummary { applied: true, violations_detected, violation_count: violations.len(), total_removed, violations }
}

