#[derive(Debug, Clone)]
pub struct KernelVasanaSnapshot {
 pub name: String, pub receiver_id: u64,
 pub vow_weights: Vec<f64>, pub vow_name: String,
 pub trait_sediment: Vec<f64>, pub vow_bias: f64,
 pub unresolved_weight: f64, pub incarnation_count: u64,
 pub estimated_gain: f64, pub gain_variance: f64,
 pub awareness_level: f64, pub awakened_at: Option<u64>,
 pub merit_accumulated: f64, pub merit_capacity: f64,
 pub total_steps: u64, pub in_band_steps: u64,
 pub encounter_count: usize, pub resilience_count: usize,
 pub prev_defense_strain: f64,
 pub state_t: u64,
}

#[derive(Debug, Clone)]
pub struct VasanaBundle {
 pub version: String, pub tick: u64,
 pub kernels: Vec<KernelVasanaSnapshot>,
 pub vasana_hash: [u8; 32],
}

impl KernelVasanaSnapshot {
 pub fn extract(k: &IntegratedKernel<NonlinearTransducer, ModeBasedFilter>) -> Self {
 Self {
 name: k.core.name.clone(), receiver_id: k.core.id.0,
 vow_weights: k.sediment.vow_weights.clone(), vow_name: k.sediment.vow_name.clone(),
 trait_sediment: k.sediment.trait_sediment.clone(), vow_bias: k.sediment.vow_bias,
 unresolved_weight: k.sediment.unresolved_weight, incarnation_count: k.sediment.incarnation_count,
 estimated_gain: k.self_knowledge.estimated_gain, gain_variance: k.self_knowledge.gain_variance,
 awareness_level: k.self_knowledge.awareness_level, awakened_at: k.self_knowledge.awakened_at,
 merit_accumulated: k.merit.accumulated, merit_capacity: k.merit.capacity,
 total_steps: k.total_steps, in_band_steps: k.in_band_steps,
 encounter_count: k.encounter_count, resilience_count: k.resilience_count,
 prev_defense_strain: k.prev_defense_strain, state_t: k.core.state.t,
 }
 }
 pub fn restore_to(&self, k: &mut IntegratedKernel<NonlinearTransducer, ModeBasedFilter>) {
 k.sediment.vow_weights = self.vow_weights.clone();
 k.sediment.vow_name = self.vow_name.clone();
 k.sediment.trait_sediment = self.trait_sediment.clone();
 k.sediment.vow_bias = self.vow_bias;
 k.sediment.unresolved_weight = self.unresolved_weight;
 k.sediment.incarnation_count = self.incarnation_count;
 k.self_knowledge.estimated_gain = self.estimated_gain;
 k.self_knowledge.gain_variance = self.gain_variance;
 k.self_knowledge.awareness_level = self.awareness_level;
 k.self_knowledge.awakened_at = self.awakened_at;
 k.merit.accumulated = self.merit_accumulated;
 k.merit.capacity = self.merit_capacity;
 k.total_steps = self.total_steps;
 k.in_band_steps = self.in_band_steps;
 k.encounter_count = self.encounter_count;
 k.resilience_count = self.resilience_count;
 k.prev_defense_strain = self.prev_defense_strain;
 k.core.state.t = self.state_t;
 }
}

impl VasanaBundle {
 pub fn extract<P: ProjectionPolicy, W: WorldPort>(os: &DescentOSv1<P, W>) -> Self {
 let kernels: Vec<KernelVasanaSnapshot> = os.kernels.iter().map(KernelVasanaSnapshot::extract).collect();
 let vasana_hash = os.session_ledger.last_close().map(|c| c.vasana_hash.0).unwrap_or([0u8; 32]);
 Self { version: "v10.8".into(), tick: os.tick, kernels, vasana_hash }
 }
 pub fn restore_to<P: ProjectionPolicy, W: WorldPort>(&self, os: &mut DescentOSv1<P, W>) -> Result<usize, String> {
 if self.kernels.len() != os.kernels.len() {
 return Err(format!("kernel count mismatch: {} vs {}", self.kernels.len(), os.kernels.len()));
 }
 for (snap, kernel) in self.kernels.iter().zip(os.kernels.iter_mut()) {
 if snap.receiver_id != kernel.core.id.0 {
 return Err(format!("receiver_id mismatch: {} vs {}", snap.receiver_id, kernel.core.id.0));
 }
 snap.restore_to(kernel);
 }
 os.tick = self.tick;
 Ok(self.kernels.len())
 }
 pub fn to_bytes(&self) -> Vec<u8> {
 let mut b = Vec::new();
 write_str(&mut b, &self.version);
 write_u64(&mut b, self.tick);
 write_u64(&mut b, self.kernels.len() as u64);
 for k in &self.kernels {
 write_str(&mut b, &k.name);
 write_u64(&mut b, k.receiver_id);
 write_vec_f64(&mut b, &k.vow_weights);
 write_str(&mut b, &k.vow_name);
 write_vec_f64(&mut b, &k.trait_sediment);
 write_f64(&mut b, k.vow_bias);
 write_f64(&mut b, k.unresolved_weight);
 write_u64(&mut b, k.incarnation_count);
 write_f64(&mut b, k.estimated_gain);
 write_f64(&mut b, k.gain_variance);
 write_f64(&mut b, k.awareness_level);
 write_u64(&mut b, k.awakened_at.unwrap_or(u64::MAX));
 write_f64(&mut b, k.merit_accumulated);
 write_f64(&mut b, k.merit_capacity);
 write_u64(&mut b, k.total_steps);
 write_u64(&mut b, k.in_band_steps);
 write_u64(&mut b, k.encounter_count as u64);
 write_u64(&mut b, k.resilience_count as u64);
 write_f64(&mut b, k.prev_defense_strain);
 write_u64(&mut b, k.state_t);
 }
 b.extend_from_slice(&self.vasana_hash);
 b
 }
 pub fn from_bytes(data: &[u8]) -> Result<Self, String> {
 let mut c = Cursor { data, pos: 0 };
 let version = c.read_str()?;
 let tick = c.read_u64()?;
 let n = c.read_u64()? as usize;
 let mut kernels = Vec::with_capacity(n);
 for _ in 0..n {
 let name = c.read_str()?;
 let receiver_id = c.read_u64()?;
 let vow_weights = c.read_vec_f64()?;
 let vow_name = c.read_str()?;
 let trait_sediment = c.read_vec_f64()?;
 let vow_bias = c.read_f64()?;
 let unresolved_weight = c.read_f64()?;
 let incarnation_count = c.read_u64()?;
 let estimated_gain = c.read_f64()?;
 let gain_variance = c.read_f64()?;
 let awareness_level = c.read_f64()?;
 let raw_awakened = c.read_u64()?;
 let awakened_at = if raw_awakened == u64::MAX { None } else { Some(raw_awakened) };
 let merit_accumulated = c.read_f64()?;
 let merit_capacity = c.read_f64()?;
 let total_steps = c.read_u64()?;
 let in_band_steps = c.read_u64()?;
 let encounter_count = c.read_u64()? as usize;
 let resilience_count = c.read_u64()? as usize;
 let prev_defense_strain = c.read_f64()?;
 let state_t = c.read_u64()?;
 kernels.push(KernelVasanaSnapshot {
 name, receiver_id, vow_weights, vow_name, trait_sediment, vow_bias,
 unresolved_weight, incarnation_count, estimated_gain, gain_variance,
 awareness_level, awakened_at, merit_accumulated, merit_capacity,
 total_steps, in_band_steps, encounter_count, resilience_count,
 prev_defense_strain, state_t,
 });
 }
 let mut vasana_hash = [0u8; 32];
 for i in 0..32 { vasana_hash[i] = c.read_u8()?; }
 Ok(Self { version, tick, kernels, vasana_hash })
 }
}

fn write_u64(b: &mut Vec<u8>, v: u64) { b.extend_from_slice(&v.to_le_bytes()); }
fn write_f64(b: &mut Vec<u8>, v: f64) { b.extend_from_slice(&v.to_le_bytes()); }
fn write_str(b: &mut Vec<u8>, s: &str) { write_u64(b, s.len() as u64); b.extend_from_slice(s.as_bytes()); }
fn write_vec_f64(b: &mut Vec<u8>, v: &[f64]) { write_u64(b, v.len() as u64); for x in v { write_f64(b, *x); } }
struct Cursor<'a> { data: &'a [u8], pos: usize }
impl<'a> Cursor<'a> {
 fn read_bytes(&mut self, n: usize) -> Result<&'a [u8], String> {
 if self.pos + n > self.data.len() { return Err("unexpected EOF".into()); }
 let s = &self.data[self.pos..self.pos+n]; self.pos += n; Ok(s)
 }
 fn read_u8(&mut self) -> Result<u8, String> { Ok(self.read_bytes(1)?[0]) }
 fn read_u64(&mut self) -> Result<u64, String> {
 let b = self.read_bytes(8)?;
 Ok(u64::from_le_bytes([b[0],b[1],b[2],b[3],b[4],b[5],b[6],b[7]]))
 }
 fn read_f64(&mut self) -> Result<f64, String> {
 let b = self.read_bytes(8)?;
 Ok(f64::from_le_bytes([b[0],b[1],b[2],b[3],b[4],b[5],b[6],b[7]]))
 }
 fn read_str(&mut self) -> Result<String, String> {
 let len = self.read_u64()? as usize;
 let b = self.read_bytes(len)?;
 String::from_utf8(b.to_vec()).map_err(|e| format!("utf8: {}", e))
 }
 fn read_vec_f64(&mut self) -> Result<Vec<f64>, String> {
 let len = self.read_u64()? as usize;
 let mut v = Vec::with_capacity(len);
 for _ in 0..len { v.push(self.read_f64()?); }
 Ok(v)
 }
}

pub trait Persistence {
 fn save(&self, bundle: &VasanaBundle) -> Result<(), String>;
 fn load(&self) -> Result<Option<VasanaBundle>, String>;
}

pub struct FilePersistence { path: std::path::PathBuf }
impl FilePersistence {
 pub fn new(path: impl Into<std::path::PathBuf>) -> Self { Self { path: path.into() } }
}
impl Persistence for FilePersistence {
 fn save(&self, bundle: &VasanaBundle) -> Result<(), String> {
 std::fs::write(&self.path, bundle.to_bytes()).map_err(|e| format!("write: {}", e))
 }
 fn load(&self) -> Result<Option<VasanaBundle>, String> {
 if !self.path.exists() { return Ok(None); }
 let data = std::fs::read(&self.path).map_err(|e| format!("read: {}", e))?;
 Ok(Some(VasanaBundle::from_bytes(&data)?))
 }
}

