/// Other's resilience. decoder material for 'how much to round'.
///
///
///
///
///
///
///
/// ### Usage
///
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum ReceiverResilience {
 /// Fragile other. child. lonely person. LLM rounding maximally permitted.
 /// Vulnerable targets. children. lonely people. permit maximum LLM rounding.
 Fragile,
 /// Normal resilience. adult. moderate rounding.
 /// friction_strength 50-70% temperature at 。
 Moderate,
 /// High resilience. designer, practitioner, peer. no rounding.
 /// High resilience. designers, practitioners, colleagues. do not round.
 Robust,
 /// Raw data. therapist, supervisor, auditor. see numerically.
 Raw,
}

impl ReceiverResilience {
 /// word temperature coefficient to friction_strength.
 /// temperature coefficient relative to friction_strength.
 pub fn temperature_coefficient(&self) -> f64 {
 match self {
 Self::Fragile => 0.3,
 Self::Moderate => 0.6,
 Self::Robust => 1.0,
 Self::Raw => 1.0, // Raw coefficient 1.0. decoder outputs numeric as-is.
 }
 }

 /// instruction string to decoder. injected into LLM system prompt.
 pub fn decoder_instruction(&self) -> &str {
 match self {
 Self::Fragile => "Speak gently. Soften all friction. Protect. The listener is vulnerable.",
 Self::Moderate => "Speak naturally. Moderate friction. Be honest but not harsh.",
 Self::Robust => "Speak directly. Do not soften friction. The listener can handle it.",
 Self::Raw => "Output raw interpretation. Include numerical values. No softening.",
 }
 }
}

/// Convert action to natural language.
pub trait SemanticDecoder: Send + Sync {
 /// action → text.
 /// interpretation: LlmWorldPort::interpret_action result.
 /// action → text。
 /// action → text。
 /// interpretation: result of LlmWorldPort::interpret_action.
 fn decode_action(
 &self,
 interpretation: &ActionInterpretation,
 context: &str,
 resilience: ReceiverResilience,
 friction_strength: f64,
 ) -> String;

 /// human-readable name.
 fn name(&self) -> &str;
}

/// template-based naive decoder. LLM not required. for test/dev.
pub struct NaiveDecoder;

impl SemanticDecoder for NaiveDecoder {
 fn decode_action(
 &self, interp: &ActionInterpretation, _context: &str,
 resilience: ReceiverResilience, friction_strength: f64,
 ) -> String {
 let temp = resilience.temperature_coefficient();
 let effective_friction = friction_strength * temp;

 let mut parts = Vec::new();
 if interp.love_delta.abs() > 0.05 {
 let dir = if interp.love_delta > 0.0 { "toward" } else { "away from" };
 parts.push(format!("love: {} ({:.2})", dir, interp.love_delta));
 }
 if interp.logic_delta.abs() > 0.05 {
 let dir = if interp.logic_delta > 0.0 { "toward" } else { "away from" };
 parts.push(format!("logic: {} ({:.2})", dir, interp.logic_delta));
 }
 if interp.fear_delta.abs() > 0.05 {
 let dir = if interp.fear_delta > 0.0 { "rising" } else { "calming" };
 parts.push(format!("fear: {} ({:.2})", dir, interp.fear_delta));
 }
 if interp.creation_delta.abs() > 0.05 {
 let dir = if interp.creation_delta > 0.0 { "exploring" } else { "consolidating" };
 parts.push(format!("creation: {} ({:.2})", dir, interp.creation_delta));
 }

 let movement = if parts.is_empty() {
 "stillness".to_string()
 } else {
 parts.join(", ")
 };

 let flags = [
 if interp.exploratory { Some("exploratory") } else { None },
 if interp.sila_active { Some("sila") } else { None },
 if interp.chanda_active { Some("chanda") } else { None },
 if interp.intrusion_leaked { Some("intrusion") } else { None },
 ].iter().filter_map(|f| *f).collect::<Vec<_>>().join("+");

 let friction_tag = if effective_friction > 0.01 {
 format!(" friction={:.2}(raw={:.2}×{:.1})", effective_friction, friction_strength, temp)
 } else { String::new() };

 if flags.is_empty() {
 format!("[{}{}] {}", interp.action_label, friction_tag, movement)
 } else {
 format!("[{}|{}{}] {}", interp.action_label, flags, friction_tag, movement)
 }
 }

 fn name(&self) -> &str { "NaiveDecoder" }
}

/// action → text conversion by external LLM. for production.
///
///
///
pub struct LlmDecoder {
 decode_fn: Box<dyn Fn(&ActionInterpretation, &str) -> Option<String> + Send + Sync>,
 fallback: NaiveDecoder,
}

impl LlmDecoder {
 pub fn new(
 decode_fn: impl Fn(&ActionInterpretation, &str) -> Option<String> + Send + Sync + 'static,
 ) -> Self {
 Self { decode_fn: Box::new(decode_fn), fallback: NaiveDecoder }
 }
}

impl SemanticDecoder for LlmDecoder {
 fn decode_action(
 &self, interp: &ActionInterpretation, context: &str,
 resilience: ReceiverResilience, friction_strength: f64,
 ) -> String {
 // resilience.decoder_instruction() context to additionand LLM to pass
 let enriched_context = format!(
 "{}\n[resilience: {:?}, instruction: {}, friction: {:.2}, effective_temp: {:.2}]",
 context, resilience, resilience.decoder_instruction(),
 friction_strength, friction_strength * resilience.temperature_coefficient(),
 );
 match (self.decode_fn)(interp, &enriched_context) {
 Some(text) => text,
 None => self.fallback.decode_action(interp, context, resilience, friction_strength),
 }
 }
 fn name(&self) -> &str { "LlmDecoder" }
}

