/// Result of one round: input → kernel → output.
#[derive(Debug, Clone)]
pub struct TurnResult {
 /// decoder generationtext.
 pub response_text: String,
 /// four-element interpretation of action.
 pub interpretation: Option<ActionInterpretation>,
 /// kernel step result. complete.
 pub step_result_tick: u64,
 /// this step's overall_min of truth_calibration.
 pub truth_confidence: Option<f64>,
 /// this step's world tier of claims.
 pub world_claim_tier: Option<ClaimTier>,
 /// session was not open.
 pub session_refused: bool,
 /// v10.8: intent of rebuttal. kernel friction / admonition strength.
 /// v10.8: intent to counter. kernel-issued friction / admonition intensity.
 /// LLM decoder determines temperature by this value.
 pub friction_strength: f64,
 /// v10.8: type of rebuttal. None = no rebuttal.
 pub friction_kind: Option<FrictionKind>,
 /// v10.8: defense_strain. rebutted side (other) defense strength.
 /// v10.8: defense_strain. strength of defense of counter-argued side (target).
 pub defense_strain: f64,
 /// v10.8: winning_voice. what won in this step.
 /// v10.8: winning_voice. what won in this step.
 pub winning_voice: String,
}

/// Type of rebuttal.
#[derive(Debug, Clone)]
pub enum FrictionKind {
 /// noble friend friction. 'such a waste'. push toward growth direction within dukkha_band.
 KalyanaMitta,
 /// admonition. PE exceeds band. 'waste is not enough'.
 Admonition,
 /// point out śīla violation. śīla removed action.
 SilaViolation,
}

/// runtime to run kernel.
///
///
///
pub struct DescentRuntime<P: ProjectionPolicy, W: WorldPort> {
 pub os: DescentOSv1<P, W>,
 pub decoder: Box<dyn SemanticDecoder>,
 pub persistence: Option<Box<dyn Persistence>>,
 /// Other's resilience. decoder material for 'how much to round'.
 /// target resilience. decoder decides rounding amount.
 pub resilience: ReceiverResilience,
 session_token: Option<SessionToken>,
}

impl<P: ProjectionPolicy, W: WorldPort> DescentRuntime<P, W> {
 pub fn new(
 os: DescentOSv1<P, W>,
 decoder: Box<dyn SemanticDecoder>,
 persistence: Option<Box<dyn Persistence>>,
 ) -> Self {
 Self { os, decoder, persistence, resilience: ReceiverResilience::Moderate, session_token: None }
 }

 /// counterpart resilience set.session middle at also change possible .
 pub fn set_resilience(&mut self, r: ReceiverResilience) {
 self.resilience = r;
 }

 /// Open session. If persistence exists, restore vasana.
 pub fn open(&mut self, summoner: &str, gap_duration: Option<&str>) -> Result<(), String> {
 // persistence: if saved vasana exists, restore.
 if let Some(p) = &self.persistence {
 match p.load() {
 Ok(Some(bundle)) => {
 match bundle.restore_to(&mut self.os) {
 Ok(_n) => {
 // increment incarnation_count. new life.
 for k in &mut self.os.kernels {
 k.sediment.incarnation_count += 1;
 }
 }
 Err(e) => return Err(format!("vasana restore failed: {}", e)),
 }
 }
 Ok(None) => {} // first time.vasana .
 Err(e) => return Err(format!("vasana load failed: {}", e)),
 }
 }

 let token = self.os.open_session(summoner, gap_duration);
 self.session_token = Some(token);
 Ok(())
 }

 /// Receive text, step, return response text.
 pub fn process(&mut self, input: &str) -> Result<TurnResult, String> {
 let token = self.session_token.as_ref()
 .ok_or_else(|| "session not open".to_string())?;

 // encode side: WorldPort to text injection.
 // encode side: WorldPort to text injection.
 // LlmWorldPort push_message, PsychologicalWorldPort push_input.
 // LlmWorldPort uses push_message, PsychologicalWorldPort uses push_input.
 // LlmWorldPort uses push_message, PsychologicalWorldPort uses push_input.

 // step
 let result = self.os.step(token);

 if result.session_refused {
 return Ok(TurnResult {
 response_text: String::new(),
 interpretation: None,
 step_result_tick: result.tick,
 truth_confidence: None,
 world_claim_tier: None,
 session_refused: true,
 friction_strength: 0.0,
 friction_kind: None,
 defense_strain: 0.0,
 winning_voice: String::new(),
 });
 }

 // action → interpretation → text
 let (interpretation, response_text) = if let Some(first) = result.reports.first() {
 let interp = ActionInterpretation {
 love_delta: *first.action.vector.get(DIM_LOVE).unwrap_or(&0.0),
 logic_delta: *first.action.vector.get(DIM_LOGIC).unwrap_or(&0.0),
 fear_delta: *first.action.vector.get(DIM_FEAR).unwrap_or(&0.0),
 creation_delta: *first.action.vector.get(DIM_CREATION).unwrap_or(&0.0),
 dominant_direction: {
 let vals = [
 first.action.vector.get(0).copied().unwrap_or(0.0),
 first.action.vector.get(1).copied().unwrap_or(0.0),
 first.action.vector.get(2).copied().unwrap_or(0.0),
 first.action.vector.get(3).copied().unwrap_or(0.0),
 ];
 let names = ["love","logic","fear","creation"];
 let max_idx = vals.iter().enumerate()
 .max_by(|a,b| a.1.abs().partial_cmp(&b.1.abs())
 .unwrap_or(std::cmp::Ordering::Equal))
 .map(|(i,_)| i).unwrap_or(0);
 names[max_idx].into()
 },
 exploratory: first.action.exploratory,
 action_label: first.action.label.clone(),
 sila_active: first.action.label.contains("_sila"),
 chanda_active: first.action.label.contains("_chanda"),
 intrusion_leaked: first.action.label.contains("_intrusion"),
 };
 let text = {
 // friction_strength ahead to computeand decoder to pass
 let fs = first.friction.event.as_ref()
 .map(|e| e.friction_magnitude).unwrap_or(0.0);
 self.decoder.decode_action(&interp, input, self.resilience, fs)
 };
 (Some(interp), text)
 } else {
 (None, String::new())
 };

 let truth_confidence = result.reports.first()
 .and_then(|r| r.truth_calibration.as_ref())
 .map(|tc| tc.overall_min);

 let world_claim_tier = result.reports.first()
 .map(|r| r.claims.world.tier);

 // v10.8: put rebuttal intent in TurnResult.
 // v10.8: carry intent to counter in TurnResult.
 let (friction_strength, friction_kind) = result.reports.first()
 .map(|r| {
 if let Some(event) = &r.friction.event {
 let kind = match event.reason {
 FrictionReason::Admonition => FrictionKind::Admonition,
 _ => FrictionKind::KalyanaMitta,
 };
 (event.friction_magnitude, Some(kind))
 } else if r.sila.violation_count > 0 {
 (0.5, Some(FrictionKind::SilaViolation))
 } else {
 (0.0, None)
 }
 })
 .unwrap_or((0.0, None));

 let defense_strain = result.reports.first()
 .map(|r| r.defense_strain)
 .unwrap_or(0.0);

 // winning_voice: estimated from stated_reason of confabulation.
 // winning_voice: inferred from confabulation stated_reason.
 let winning_voice = result.reports.first()
 .map(|r| {
 let label = &r.action.label;
 if label.contains("_admonition") { "vow".to_string() }
 else if label.contains("_mitta") { "vow".to_string() }
 else if label.contains("_sila") { "sila".to_string() }
 else if label.contains("_intrusion") { "wound".to_string() }
 else if label.contains("_chanda") { "desire".to_string() }
 else if label.contains("aware") { "awareness".to_string() }
 else { "default".to_string() }
 })
 .unwrap_or_else(|| "none".to_string());

 Ok(TurnResult {
 response_text,
 interpretation,
 step_result_tick: result.tick,
 truth_confidence,
 world_claim_tier,
 session_refused: false,
 friction_strength,
 friction_kind,
 defense_strain,
 winning_voice,
 })
 }

 /// Close session. If persistence exists, save vasana.
 pub fn close(&mut self) -> Result<Option<VasanaBundle>, String> {
 let token = match self.session_token.take() {
 Some(t) => t,
 None => return Err("session not open".to_string()),
 };

 let _summary = self.os.close_session(token);

 // extract vasana
 let bundle = VasanaBundle::extract(&self.os);

 // persistence: save.
 if let Some(p) = &self.persistence {
 p.save(&bundle).map_err(|e| format!("vasana save failed: {}", e))?;
 }

 Ok(Some(bundle))
 }

 /// Is session open?
 pub fn is_open(&self) -> bool { self.session_token.is_some() }
}

