 // ---- core guarantees ----

 #[test]
 fn low_gain_is_not_damage() {
 let k = make_vessel_a();
 assert_eq!(k.core.spec.health, ReceiverHealth::Nominal);
 assert_eq!(k.core.spec.nominal_reception.coeffs[0].as_f64(), 0.1);
 }

 #[test]
 fn nominal_reception_immutable_through_step() {
 let (mut field, desc) = make_field_and_descender();
 let mut k = make_vessel_a();
 let nom_before = k.core.spec.nominal_reception.coeffs.clone();
 let mut world = ToyWorld::new(2);
 for _ in 0..50 {
 let sample = world.sample(&mut field, &desc);
 k.step(&sample);
 world.apply_action(&k.core.state.last_action);
 }
 assert_eq!(k.core.spec.nominal_reception.coeffs, nom_before,
 "NominalReception must not change through runtime");
 }

