 let (mut field, desc) = make_field_and_descender();
 let mut world = ToyWorld::new(2);
 world.inject(&[1.0, -0.5]);
 let sample = world.sample(&mut field, &desc);
 let mut ks = make_vessel_a();
 let mut kf = make_vessel_b();
 let rs = ks.step(&sample);
 let rf = kf.step(&sample);
