 #[test]
 fn full_20_stage_loop() {
 let (mut field, desc) = make_field_and_descender();
 let mut k = make_vessel_a();
 let mut world = ToyWorld::new(2);

 for _ in 0..20 {
 let sample = world.sample(&mut field, &desc);
 k.step(&sample);
 world.apply_action(&k.core.state.last_action);
 }

 world.inject(&[-1.5, -0.5]);
 let mut shock_reports = Vec::new();
 for _ in 0..10 {
 let sample = world.sample(&mut field, &desc);
 shock_reports.push(k.step(&sample));
 world.apply_action(&k.core.state.last_action);
 }

 for _ in 0..20 {
 let sample = world.sample(&mut field, &desc);
 k.step(&sample);
 world.apply_action(&k.core.state.last_action);
 }

 assert_eq!(k.core.state.t, 50);
 assert!(shock_reports.iter().any(|r| r.workspace_broadcast_size > 0));
 assert_eq!(k.core.spec.nominal_reception.coeffs[0], BasisPoints::new(100));
 assert!(shock_reports.iter().all(|r| r.signal_id.0 > 0));

 // v0.9 fields
 let r = &shock_reports[0];
 let _ = r.filtered_payload;
 let _ = r.filter_resonance_score;
 let _ = r.unresolved_markers;
 let _ = r.reported_world;
 let _ = r.calibration_error;
 let _ = r.source_claim_confidence;
 let _ = r.projection_claim_confidence;
 let _ = r.self_claim_confidence;
 }

