 #[test]
 fn vessel_c_can_let_go() {
 let mut sediment = SedimentedVasana::new(
 "vessel_c", vec![2.0, 2.0, 2.0, 2.0], 4,
 );
 sediment.unresolved_weight = 3.0;
 sediment.unresolved_residue = vec![0.4, 0.3, 0.5, 0.2];
 let mut markers = vec![
 UnresolvedMarker::with_cycles("unresolved_self_deception", 0.5, "confabulation", 5),
 UnresolvedMarker::with_cycles("high_filtered_dukkha", 0.8, "maintenance_boundary", 5),
 ];
 let blanket = SelfBlanket::new(&[
 "confabulation".to_string(),
 "maintenance_boundary".to_string(),
 ]);
 let cond = NirodhaCondition::default();
 let mut completed = 0;
 // v10.5: logarithmic decay, 0.5 not completed in 100 cycles.
 // v10.5: logarithmic decay does not complete 0.5 in 100 cycles.
 for _ in 0..500 {
 let events = sediment.attempt_nirodha(
 &mut markers, &blanket, 0.8, 0.7, &cond,
 );
 completed += events.iter().filter(|e| e.completed).count();
 }
 assert!(completed >= 1, "500 cycles あれば何かは手放せる");
 assert!(sediment.unresolved_weight < 3.0, "weight は減った");
 assert!(sediment.unresolved_residue.iter().all(|&r| r < 0.4),
 "残響も薄れた");
 }

