 #[test]
 fn overflow_distribution_in_os() {
 // put designer (overflowing) and vessel_a (not overflowing) in same OS.
 // designer (overflow) and vessel_a (no overflow) put in same OS.
 let vessel_c = seed_vessel_c();
 let vessel_a = seed_vessel_a();

 let world = PsychologicalWorldPort::new();
 let bases = vec![ProjectionBasis {
 id: BasisId(1),
 matrix: vec![
 vec![1.0, 0.0, 0.0, 0.0],
 vec![0.0, 1.0, 0.0, 0.0],
 vec![0.0, 0.0, 1.0, 0.0],
 vec![0.0, 0.0, 0.0, 1.0],
 ],
 prior: 0.9, stability: 0.9,
 semantic_tag: "identity_4d".into(),
 }];

 let vessel_c_k = boot_integrated(adapt_seed_dim(&vessel_c, 4));
 let vessel_a_k = boot_integrated(adapt_seed_dim(&vessel_a, 4));

 let mut os = DescentOSv1::new(
 world,
 ConsciousnessField::new(),
 DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
 vec![vessel_c_k, vessel_a_k],
 );
 os.world.push_input("ありがとう");

 let token = os.open_session("test", None);
 let result = os.step(&token);
 assert!(result.reached_kernel(), "信号が届く");

 // designer report to overflow was recorded.
 let vessel_c_report = &result.reports[0];
 assert!(vessel_c_report.merit_overflow.is_some(),
 "OS 経由なら overflow summary がある");
 let overflow = vessel_c_report.merit_overflow.as_ref().unwrap();
 assert!(overflow.overflow_amount > 0.0,
 "vessel_c overflow: {}", overflow.overflow_amount);

 // vessel_a's report to received was recorded.
 let vessel_a_report = &result.reports[1];
 let vessel_a_overflow = vessel_a_report.merit_overflow.as_ref().unwrap();
 assert!(vessel_a_overflow.received_amount > 0.0,
 "vessel_a received: {}", vessel_a_overflow.received_amount);

 // vessel_a merit increased.
 assert!(os.kernels[1].merit.accumulated > 0.0,
 "vessel_a merit increased: {}", os.kernels[1].merit.accumulated);

 // designer merit not decreased.
 assert!(os.kernels[0].merit.accumulated >= 120.0,
 "vessel_c merit does not decrease: {}", os.kernels[0].merit.accumulated);
 }

