 /// v10.5 test helper. ToyWorldPort + HeuristicProjectionPolicy.
 ///
 ///
 ///
 /// v10.5 test uses DescentOSv1<P: ProjectionPolicy, W: WorldPort>, so
 fn make_v10_5_os() -> DescentOSv1<HeuristicProjectionPolicy, ToyWorldPort> {
 let dim = PSYCHOLOGICAL_DIM;
 let mut world = ToyWorldPort::new(dim);
 // DharmaGate rejects all-zero (σ=0) as insufficient information.
 // for testing to notzeroinitialstate injection.
 for i in 0..dim {
 world.state[i] = 0.3 + i as f64 * 0.2;
 }
 let field = ConsciousnessField::new();
 let mut id_matrix = vec![vec![0.0; dim]; dim];
 for i in 0..dim { id_matrix[i][i] = 1.0; }
 let bases = vec![ProjectionBasis {
 id: BasisId(1),
 matrix: id_matrix,
 prior: 0.9,
 stability: 0.9,
 semantic_tag: "identity".into(),
 }];
 let desc = DynamicDescender::new(HeuristicProjectionPolicy, bases);
 let seed = seed_vessel_b();
 let k = boot_integrated(seed);
 DescentOSv1::new(world, field, desc, vec![k])
 }

 #[test]
 fn governance_stop_and_resume() {
 let mut os = make_v10_5_os();

 // stop
 let v = os.stop_vessel(0, "test stop");
 assert!(matches!(v, GovernanceVerdict::Allowed));
 assert!(!os.is_vessel_running(0));

 // double stop rejected
 let v2 = os.stop_vessel(0, "double stop");
 assert!(matches!(v2, GovernanceVerdict::Denied { .. }));

 // resume (v10.7b: readiness recheck runs before resume)
 let v3 = os.resume_vessel(0);
 assert!(matches!(v3, GovernanceVerdict::Allowed));
 assert!(os.is_vessel_running(0));

 // ledger to 3 case: stop + readiness_check(ready=true) + resume
 // ledger to 3 case: stop + readiness_check(ready=true) + resume
 assert_eq!(os.governance_ledger.len(), 3);
 assert!(os.governance_ledger.verify_chain());
 }

 #[test]
 fn governance_snapshot_and_rollback() {
 let mut os = make_v10_5_os();

 // snapshot
 let v = os.snapshot_vessel(0);
 assert!(matches!(v, GovernanceVerdict::Allowed));

 // step counttimes
 let token = os.open_session("test", None);
 os.step(&token);
 os.step(&token);
 os.step(&token);
 let t_after = os.kernels[0].core.state.t;
 assert!(t_after > 0, "step 後に t が進んでいる");

 // rollback
 let v2 = os.rollback_vessel(0, 0);
 assert!(matches!(v2, GovernanceVerdict::Allowed));
 assert_eq!(os.kernels[0].core.state.t, 0,
 "rollback で t が snapshot 時点に戻る");

 // ledger to was recorded
 assert!(os.governance_ledger.len() >= 2, "snapshot + rollback が記録");
 assert!(os.governance_ledger.verify_chain());
 }

