 #[test]
 fn rollback_preserves_sediment_asymmetry() {
 // v10.6: rollback rewinds consciousness but sediment layer (trait_sediment, vow_bias)
 // v10.6: rollback rewinds consciousness side, but sediment layer (trait_sediment, vow_bias)
 let mut os = make_v10_5_os();

 // take snapshot
 os.snapshot_vessel(0);

 // v10.8 fix: record sediment at snapshot moment (actually use and verify)
 let sediment_before = os.kernels[0].sediment.trait_sediment.clone();
 let vow_bias_before = os.kernels[0].sediment.vow_bias;
 let vow_weights_at_snapshot = os.kernels[0].sediment.vow_weights.clone();

 // advance steps and accumulate sediment
 let token = os.open_session("test", None);
 os.world.inject(&[0.9, 0.1]);
 for _ in 0..5 { os.step(&token); }

 let sediment_after_steps = os.kernels[0].sediment.trait_sediment.clone();
 let vow_bias_after_steps = os.kernels[0].sediment.vow_bias;

 // v10.8 fix: verify sediment actually accumulated by steps.
 // v10.8 fix: confirm that sediment actually accumulates by step().
 assert!(
 sediment_after_steps != sediment_before || vow_bias_after_steps != vow_bias_before,
 "5 step で沈殿が一切変化しなかった — テスト前提条件が崩壊"
 );

 // consciousness changed
 let merit_after_steps = os.kernels[0].merit.accumulated;

 // rollback
 let v = os.rollback_vessel(0, 0);
 assert!(matches!(v, GovernanceVerdict::Allowed));

 // consciousness rewound
 assert_ne!(os.kernels[0].merit.accumulated, merit_after_steps,
 "merit が rollback で巻き戻っていない");

 // sediment layer not rewound (saṃskāra does not disappear)
 assert_eq!(
 os.kernels[0].sediment.trait_sediment, sediment_after_steps,
 "trait_sediment が rollback で巻き戻された — 沈殿非対称の違反"
 );
 assert_eq!(
 os.kernels[0].sediment.vow_bias, vow_bias_after_steps,
 "vow_bias が rollback で巻き戻された — 沈殿非対称の違反"
 );

 // vow_weights unchanged (v10.6 invariant, unrelated to rollback but just in case)
 // vow_weights is immutable (v10.6 invariant; unrelated to rollback, but for safety)
 assert_eq!(
 os.kernels[0].sediment.vow_weights, vow_weights_at_snapshot,
 "vow_weights が変わった"
 );
 }

