 #[test]
 fn session_open_and_close() {
 let mut os = make_v10_5_os();

 // first notexist
 assert!(!os.is_session_open());
 assert!(os.current_summoner().is_none());

 // open session
 let token = os.open_session("vessel_c", None);
 assert_eq!(token.session_id(), 0);
 assert!(os.is_session_open());
 assert_eq!(os.current_summoner(), Some("vessel_c"));

 // step through the sequence
 os.step(&token);
 os.step(&token);

 // session close
 let close = os.close_session(token);
 assert!(close.is_some());
 assert!(!os.is_session_open());
 assert!(os.current_summoner().is_none());

 let close = close.unwrap();
 assert_eq!(close.session_id, 0);
 }

