 #[test]
 fn canonicalize_nan_stable() {
 // different bit patterns of NaN become the same byte sequence
 let nan1 = f64::NAN;
 let nan2 = f64::from_bits(0x7FF8000000000001); // signaling NaN
 let b1 = canonicalize_float(nan1);
 let b2 = canonicalize_float(nan2);
 assert_eq!(b1, b2, "異なる NaN ビットパターンが同じバイト列に正規化される");
 }

 #[test]
 fn canonicalize_negative_zero() {
 let pos = canonicalize_float(0.0_f64);
 let neg = canonicalize_float(-0.0_f64);
 assert_eq!(pos, neg, "-0.0 と +0.0 が同じバイト列に正規化される");
 }

 #[test]
 fn canonicalize_normal_values_unchanged() {
 let v = 3.14159;
 let canonical = canonicalize_float(v);
 let direct = v.to_le_bytes();
 assert_eq!(canonical, direct, "通常の値は変換されない");
 }

 #[test]
 fn hash_floats_nan_stability() {
 // hash of float array containing NaN is stable
 let a = vec![1.0, f64::NAN, 3.0];
 let b = vec![1.0, f64::from_bits(0x7FF8000000000001), 3.0];
 let ha = hash_floats(&a);
 let hb = hash_floats(&b);
 assert_eq!(ha, hb, "NaN のビットパターンに依存しないハッシュ");
 }

