 #[test]
 fn linucb_arm_singular_fallback() {
 // behavior of LinUCBArm when matrix becomes singular
 let mut arm = LinUCBArm::new(2);
 // make a_matrix singular
 arm.a_matrix = vec![
 vec![1.0, 1.0],
 vec![1.0, 1.0],
 ];
 arm.b_vector = vec![1.0, 1.0];

 // solve_theta returns zero vector (explore-only fallback)
 let theta = arm.solve_theta();
 assert_eq!(theta, vec![0.0, 0.0],
 "特異行列では零ベクトル fallback");

 // quadratic_form f64::MAX return (maximumexploration)
 let qf = arm.quadratic_form(&[1.0, 0.0]);
 assert_eq!(qf, f64::MAX,
 "特異行列では最大探索ボーナス");
 }

