 #[test]
 fn vow_bias_in_projection_features() {
 // verify that vow_bias is reflected in projected features.
 // vow_bias = 0 → sigmoid = 0.5
 // vow_bias > 0 → sigmoid > 0.5
 let src = SourceManifold {
 source_id: SignalId(1),
 state: vec![1.0, 2.0],
 phase: vec![0.5, 0.3],
 channels: vec![],
 timestamp: 0,
 };

 let ctx_neutral = ProjectionContext {
 receiver_gain_estimate: 0.5, receiver_uncertainty: 0.3,
 residual_structure_score: 0.4, suffering_level: 0.2, timestep: 0,
 dharma_quality: None, encoding_loss_count: 0,
 vow_bias: 0.0,
 };
 let ctx_biased = ProjectionContext {
 receiver_gain_estimate: 0.5, receiver_uncertainty: 0.3,
 residual_structure_score: 0.4, suffering_level: 0.2, timestep: 0,
 dharma_quality: None, encoding_loss_count: 0,
 vow_bias: 2.0,
 };

 let feat_neutral = extract_projection_features(&src, &ctx_neutral);
 let feat_biased = extract_projection_features(&src, &ctx_biased);

 assert_eq!(feat_neutral.len(), 9, "特徴次元は9");
 assert_eq!(feat_biased.len(), 9);

 // dim 7 vow_bias (sigmoid)
 let vb_neutral = feat_neutral[7];
 let vb_biased = feat_biased[7];

 assert!((vb_neutral - 0.5).abs() < 0.01,
 "vow_bias=0 → sigmoid≈0.5: {}", vb_neutral);
 assert!(vb_biased > 0.8,
 "vow_bias=2 → sigmoid>0.8: {}", vb_biased);

 // dim 8 bias = 1.0 (unchanged)
 assert_eq!(feat_neutral[8], 1.0);
 assert_eq!(feat_biased[8], 1.0);
 }

