 #[test]
 fn noise_diversity_across_timesteps() {
 // verify that deterministic_noise(t, i) returns different values for different t.
 // Confirm that deterministic_noise(t, i) returns different values for different t.
 let mut tx = NonlinearTransducer {
 saturation: 10.0, hysteresis: 0.0,
 cross_coupling: 0.0, prev_output: vec![0.0; 2],
 };
 let input = [0.5, 0.5];
 let nominal = vec![BasisPoints::FULL; 2];
 let gate = vec![BasisPoints::FULL; 2];
 let noise_floor = vec![0.1, 0.1];

 let (out0, noise0) = tx.transduce(&input, &nominal, &gate, &noise_floor, 0);
 let (out1, noise1) = tx.transduce(&input, &nominal, &gate, &noise_floor, 1);
 let (out2, noise2) = tx.transduce(&input, &nominal, &gate, &noise_floor, 7);

 // if all noise is identical, diversity is zero → bug
 assert!(
 noise0 != noise1 || noise0 != noise2,
 "t=0,1,7 で noise が全て同じ: 多様性がない"
 );
 // output also different 
 assert!(
 out0 != out1 || out0 != out2,
 "t=0,1,7 で output が全て同じ: noise が信号に反映されていない"
 );
 }

 #[test]
 fn noise_is_bounded_by_noise_floor() {
 // noise = noise_floor[i] * deterministic_noise(t,i)
 // noise = noise_floor[i] * deterministic_noise(t,i)
 // noise = noise_floor[i] * deterministic_noise(t,i)
 let mut tx = NonlinearTransducer {
 saturation: 10.0, hysteresis: 0.0,
 cross_coupling: 0.0, prev_output: vec![0.0; 3],
 };
 let input = [0.0, 0.0, 0.0];
 let nominal = vec![BasisPoints::FULL; 3];
 let gate = vec![BasisPoints::FULL; 3];
 let noise_floor = vec![0.05, 0.1, 0.2];

 for t in 0..200u64 {
 let (_, noise) = tx.transduce(&input, &nominal, &gate, &noise_floor, t);
 for (i, n) in noise.iter().enumerate() {
 assert!(
 n.abs() <= noise_floor[i] + 1e-10,
 "t={} i={}: |noise|={} > noise_floor={}",
 t, i, n.abs(), noise_floor[i]
 );
 }
 }
 }

