 #[test]
 fn episodic_nirodha_resolved_evicted_first() {
 // nirodha_resolved episodes have wound_proximity contribution reduced to 1/10, so,
 // For nirodha_resolved episodes, wound_proximity contribution becomes 1/10,
 let mut mem = EpisodicMemory::new(2);
 mem.gate.novelty_threshold = 0.99;

 // episode A: close to wound, nirodha resolved
 let trace_a = EpisodeTrace {
 t: 0, perceived_state: vec![0.9, 0.1],
 pe_direction: vec![1.0, 0.0], pe_magnitude: 0.3,
 dukkha: Dukkha { vedana: 0.3, felt: 0.4, filtered: 0.3 },
 defense_strain: 0.2, confab_dissonance: 0.1, awareness: 0.7,
 unresolved_kinds: vec!["grief".into()], wound_proximity: 0.9,
 retrieval_count: 0, consolidation: 0.0, emotional_charge: 0.1,
 spontaneous_activation_count: 0,
 nirodha_resolved: true, // released
 };
 // episode B: far from wound, unresolved
 let trace_b = EpisodeTrace {
 t: 1, perceived_state: vec![0.1, 0.9],
 pe_direction: vec![0.0, 1.0], pe_magnitude: 0.3,
 dukkha: Dukkha { vedana: 0.3, felt: 0.4, filtered: 0.3 },
 defense_strain: 0.2, confab_dissonance: 0.1, awareness: 0.5,
 unresolved_kinds: vec![], wound_proximity: 0.2,
 retrieval_count: 0, consolidation: 0.0, emotional_charge: 0.1,
 spontaneous_activation_count: 0,
 nirodha_resolved: false, // unresolved
 };
 mem.maybe_store(trace_a, &[1.0, 0.0]);
 mem.maybe_store(trace_b, &[1.0, 0.0]);
 assert_eq!(mem.len(), 2);

 // nirodha-resolved A has low importance (wound contribution 1/10)
 // Completed nirodha A has low importance (wound contribution 1/10)
 assert!(mem.episodes[0].importance() < mem.episodes[1].importance(),
 "nirodha 済みの importance ({}) < 未解決の importance ({})",
 mem.episodes[0].importance(), mem.episodes[1].importance());

 // dismissal happens with new episode → A is dismissed
 let trace_c = EpisodeTrace {
 t: 2, perceived_state: vec![-0.5, 0.5],
 pe_direction: vec![0.5, 0.5], pe_magnitude: 0.4,
 dukkha: Dukkha { vedana: 0.4, felt: 0.5, filtered: 0.4 },
 defense_strain: 0.2, confab_dissonance: 0.1, awareness: 0.6,
 unresolved_kinds: vec![], wound_proximity: 0.3,
 retrieval_count: 0, consolidation: 0.0, emotional_charge: 0.4,
 spontaneous_activation_count: 0,
 nirodha_resolved: false,
 };
 let stored = mem.maybe_store(trace_c, &[1.0, 0.0]);
 assert!(stored);
 assert_eq!(mem.len(), 2);
 // A (t=0, nirodha_resolved) should be dismissed
 assert!(!mem.episodes.iter().any(|ep| ep.t == 0),
 "手放したエピソード (t=0) は退去されるべき");
 assert!(mem.episodes.iter().any(|ep| ep.t == 1),
 "未解決のエピソード (t=1) は残るべき");
 assert!(mem.episodes.iter().any(|ep| ep.t == 2),
 "新しいエピソード (t=2) が保存されるべき");
 }

