 #[test]
 fn spontaneous_recall_leaves_trace() {
 // when surfaced, spontaneous_activation_count increases,
 // emotional_charge smallamountstrongchange (+0.003).
 // as it surfaces, spontaneous_activation_count increases
 let mut mem = EpisodicMemory::new(64);
 let trace = EpisodeTrace {
 t: 0, perceived_state: vec![0.8, 0.2, 0.1, 0.3],
 pe_direction: vec![0.9, 0.1, 0.0, 0.0], pe_magnitude: 0.7,
 dukkha: Dukkha { vedana: 0.7, felt: 0.8, filtered: 0.6 },
 defense_strain: 0.3, confab_dissonance: 0.1, awareness: 0.6,
 unresolved_kinds: vec![], wound_proximity: 0.5,
 retrieval_count: 0, spontaneous_activation_count: 0,
 consolidation: 0.0, emotional_charge: 0.7,
 nirodha_resolved: false,
 };
 mem.maybe_store(trace, &[1.0, 0.0, 0.0, 0.0]);

 let charge_before = mem.episodes[0].emotional_charge;
 assert_eq!(mem.episodes[0].spontaneous_activation_count, 0);

 let result = mem.spontaneous_recall(None, 0);
 assert!(result.occurred);

 // trace remains
 assert_eq!(mem.episodes[0].spontaneous_activation_count, 1,
 "浮上回数が記録される");
 assert!((mem.episodes[0].emotional_charge - (charge_before + 0.003)).abs() < 1e-10,
 "微量強化: {} → {}", charge_before, mem.episodes[0].emotional_charge);
 // report is pre-strengthening value
 assert!((result.emotional_charge - charge_before).abs() < 1e-10,
 "報告は観測時点の値");

 // surface again
 let result2 = mem.spontaneous_recall(None, 3); // step_t=3 → jitter=-0.05
 assert!(result2.occurred);
 assert_eq!(mem.episodes[0].spontaneous_activation_count, 2);
 assert!((mem.episodes[0].emotional_charge - (charge_before + 0.006)).abs() < 1e-10,
 "繰り返し浮かぶものはより浮かびやすくなる");

 // retrieval_count unchanged
 assert_eq!(mem.episodes[0].retrieval_count, 0,
 "意識的な想起ではない。retrieval_count は増えない");
 }

