 #[test]
 fn attestation_chain_integrity() {
 let mut ledger = AttestationLedger::new();

 // first attestation
 let att1 = WorldPortAttestation::build(
 0, b"input_0", &[0.5, -0.3], b"cfg", 0.5, IntegrityHash::zero(),
 );
 let v1 = ledger.verify_and_record(&att1, &[0.5, -0.3]);
 assert!(v1.self_integrity);
 assert!(v1.chain_integrity, "最初の attestation は previous=zero で連鎖成立");
 assert!(v1.output_consistency);
 assert!(!v1.config_changed);

 // second. previous is the self_hash from the first.
 let att2 = WorldPortAttestation::build(
 1, b"input_1", &[0.3, 0.7], b"cfg", 0.4, att1.self_hash,
 );
 let v2 = ledger.verify_and_record(&att2, &[0.3, 0.7]);
 assert!(v2.chain_integrity, "正しい連鎖");

 assert_eq!(ledger.len(), 2);
 assert!(ledger.chain_breaks.is_empty());
 }

 #[test]
 fn attestation_chain_break_detected() {
 let mut ledger = AttestationLedger::new();

 let att1 = WorldPortAttestation::build(
 0, b"a", &[1.0], b"cfg", 0.0, IntegrityHash::zero(),
 );
 ledger.verify_and_record(&att1, &[1.0]);

 // break chain: set previous to zero (not att1.self_hash)
 let att2 = WorldPortAttestation::build(
 1, b"b", &[0.5], b"cfg", 0.0, IntegrityHash::zero(),
 );
 let v2 = ledger.verify_and_record(&att2, &[0.5]);
 assert!(!v2.chain_integrity, "連鎖断裂を検出");
 assert_eq!(ledger.chain_breaks.len(), 1);
 assert_eq!(ledger.chain_breaks[0], 1);
 }

