 #[test]
 fn sila_direction_is_normalized() {
 // verify that magnitude of direction does not affect removal amount.
 // Verify that the magnitude of direction does not affect removal amount.
 let mut action1 = Action {
 vector: vec![0.0, 0.0, 0.8, 0.0], label: "a".into(), exploratory: false,
 };
 let mut action2 = action1.clone();

 let p_unit = vec![Precept {
 name: "t".into(), direction: vec![0.0, 0.0, 1.0, 0.0],
 severity: 1.0, origin: "".into(),
 }];
 let p_scaled = vec![Precept {
 name: "t".into(), direction: vec![0.0, 0.0, 5.0, 0.0],
 severity: 1.0, origin: "".into(),
 }];

 let s1 = apply_sila(&mut action1, &p_unit, 1.0);
 let s2 = apply_sila(&mut action2, &p_scaled, 1.0);

 assert!((action1.vector[2] - action2.vector[2]).abs() < 1e-10,
 "正規化により direction の大きさは結果に影響しない: {} vs {}",
 action1.vector[2], action2.vector[2]);
 assert!((s1.total_removed - s2.total_removed).abs() < 1e-10);
 }

