 // ============================================================
 // ============================================================
 // ============================================================
 //
 //
 //
 // Verify connection with Descension Protocol v1.8.
 //
 //
 //
 // Verification items:
 // 1. pañca-skandha → CharacterSeedBuilder → LlmWorldPort → OS wiring
 // 2. Check if text input is encoded to four elements
 // 3. Check if 34-stage pipeline runs and ActionInterpretation is generated
 // 4. Check if vessel state transitions across multiple turns (awareness, defense, merit)

 /// descension protocol pañca-skandha from vessel_b's vessel construct.
 /// descension protocol pañca-skandha from vessel_b's vessel construct.
 fn build_vessel_b_for_descension() -> (
 DescentOSv1<BanditProjectionPolicy, LlmWorldPort>,
 IntegratedSeed,
 ) {
 // ---- pañca-skandha ----
 // ---- pañca-skandha ----
 // ---- pañca-skandha ----
 // 3. Chanda (Desire / Saṃjñā):
 // 3. Chanda (Desire / Saṃjñā):
 // 3. Chanda (Desire / Saṃjñā):
 // Conscious: wants to collect magic (Logic + Creation)
 // Unconscious: wants to meet again (Love)

 let seed = CharacterSeedBuilder::new("vessel_b", 2)
 // Vow: wounded by Love. Logic most open.
 .vow("to_know_before_loss", [1.0, 2.5, 0.5, 1.5])
 // Wound: Love × Fear cross. fear of attachment.
 .wound("attachment_fear", [0.6, -0.1, 0.7, -0.2])
 // Desire: consciousness=magic collection, unconscious=want to meet again
 .desire("to_collect_magic", "to_see_himmel_again")
 // Mask: indifferent elf. Logic-biased.
 .mask("indifferent_elf", [0.1, 0.6, 0.1, 0.3])
 // openness: low.long-term attenuation.
 .openness(0.25)
 // dukkha band: narrow. tolerance increases over millennium.
 .dukkha_band(0.01, 0.25)
 // skandha: memory of lost_companion, longevity, curiosity, fear of attachment
 .skandha(SkandhaSpec {
 name: "himmel_memory".into(),
 direction: [0.8, 0.2, 0.1, 0.1],
 intensity: 0.85, impermanence: 0.15,
 initially_unconscious: true, // person calls it "memory"
 })
 .skandha(SkandhaSpec {
 name: "curiosity".into(),
 direction: [0.1, 0.6, 0.0, 0.5],
 intensity: 0.7, impermanence: 0.3,
 initially_unconscious: false,
 })
 .skandha(SkandhaSpec {
 name: "attachment_fear".into(),
 direction: [0.6, -0.1, 0.7, -0.2],
 intensity: 0.6, impermanence: 0.1,
 initially_unconscious: true, // knows but does not let pass
 })
 // rejection: defend attachment direction. intensity 0.45.
 .reject(RejectionSpec {
 name: "attachment_defense".into(),
 direction: [0.6, -0.1, 0.7, -0.1],
 strength: 0.45,
 origin: "千年の防衛".into(),
 })
 .build();

 let world = LlmWorldPort::new();
 let bases = vec![ProjectionBasis {
 id: BasisId(1),
 matrix: vec![
 vec![1.0, 0.0, 0.0, 0.0],
 vec![0.0, 1.0, 0.0, 0.0],
 vec![0.0, 0.0, 1.0, 0.0],
 vec![0.0, 0.0, 0.0, 1.0],
 ],
 prior: 0.9, stability: 0.9,
 semantic_tag: "identity_4d".into(),
 }];

 let os = DescentOSv1::new(
 world,
 ConsciousnessField::new(),
 DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
 vec![boot_integrated(seed.clone())],
 );

 (os, seed)
 }

