 #[test]
 fn embodied_posture_degrades_precision() {
 // collapsed posture reduces action precision.
 let inner = Box::new(ToyWorldPort::new(PSYCHOLOGICAL_DIM));
 let mut port_stable = EmbodiedWorldPort::new(inner);

 let inner2 = Box::new(ToyWorldPort::new(PSYCHOLOGICAL_DIM));
 let mut port_unstable = EmbodiedWorldPort::new(inner2);
 port_unstable.body.posture_stability = 0.2; // on the verge of collapse

 let action = ActionRef {
 vector: vec![1.0, 0.0, 0.0, 0.0],
 label: "test".into(),
 exploratory: false,
 };
 let effect_stable = port_stable.decode(&action, 0);
 let effect_unstable = port_unstable.decode(&action, 0);

 // unstable posture makes applied small (precision drops)
 let mag_stable: f64 = effect_stable.applied.iter().map(|x| x * x).sum::<f64>().sqrt();
 let mag_unstable: f64 = effect_unstable.applied.iter().map(|x| x * x).sum::<f64>().sqrt();
 assert!(mag_unstable < mag_stable,
 "姿勢崩壊で精度が落ちる: stable={:.4} unstable={:.4}",
 mag_stable, mag_unstable);
 }

