 #[test]
 fn runtime_open_process_close() {
 let seed = CharacterSeedBuilder::new("テスト", 900)
 .vow("test", [1.0, 0.5, 0.3, 0.2])
 .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
 .openness(0.5)
 .build();
 let mut world = PsychologicalWorldPort::new();
 world.push_input("テスト入力");
 let bases = vec![ProjectionBasis {
 id: BasisId(1),
 matrix: vec![
 vec![1.0, 0.0, 0.0, 0.0], vec![0.0, 1.0, 0.0, 0.0],
 vec![0.0, 0.0, 1.0, 0.0], vec![0.0, 0.0, 0.0, 1.0],
 ],
 prior: 0.9, stability: 0.9, semantic_tag: "identity_4d".into(),
 }];
 let os = DescentOSv1::new(
 world, ConsciousnessField::new(),
 DynamicDescender::new(BanditProjectionPolicy::new(0.1), bases),
 vec![boot_integrated(seed)],
 );

 let decoder: Box<dyn SemanticDecoder> = Box::new(NaiveDecoder);
 let mut runtime = DescentRuntime::new(os, decoder, None);

 assert!(!runtime.is_open());

 runtime.open("vessel_c", None).unwrap();
 assert!(runtime.is_open());

 let result = runtime.process("テスト").unwrap();
 assert!(!result.session_refused, "session は開いている");
 assert!(result.step_result_tick == 0 || result.step_result_tick == 1);

 let bundle = runtime.close().unwrap();
 assert!(bundle.is_some(), "close で VasanaBundle が返る");
 assert!(!runtime.is_open());
 }

