 #[test]
 fn sediment_drift_initial_captured_in_pipeline() {
 // run step and verify initial_sediment_direction is auto-captured
 let seed = CharacterSeedBuilder::new("テスト", 950)
 .vow("test", [1.0, 0.5, 0.3, 0.2])
 .wound("test_wound", [0.5, 0.0, 0.8, 0.0])
 .openness(0.5)
 .build();
 let mut k = boot_integrated(seed);
 assert!(k.sediment.initial_sediment_direction.is_none(),
 "初期は None");

 let mut field = ConsciousnessField::new();
 let desc = LinearDescender::identity(PSYCHOLOGICAL_DIM);
 let mut world = ToyWorld::new(PSYCHOLOGICAL_DIM);

 // run sufficient steps to form sediment
 for t in 0..200 {
 world.inject(&[0.5, 0.3, 0.1, 0.0]);
 let sample = world.sample(&mut field, &desc);
 k.step(&sample);
 }

 // initial_sediment_direction is captured
 assert!(k.sediment.initial_sediment_direction.is_some(),
 "200 step 後に initial_sediment_direction がキャプチャされる");

 // current sediment should be nearly same as initial direction (consistent input)
 let report = k.sediment.detect_drift(0.5);
 assert!(!report.drifted,
 "一貫した入力 → ドリフトなし: distance={}", report.drift_distance);
 }

