 #[test]
 fn bistable_initial_transitioning() {
 let bs = DualBistableState::new();
 assert_eq!(bs.phase, BistablePhase::Transitioning);
 assert!((bs.balance - 0.5).abs() < 1e-9);
 }

 #[test]
 fn bistable_dharmic_convergence() {
 // High dukkha_pressure + high coherence → Dharmic well
 let mut bs = DualBistableState::new();
 for tick in 0..500 {
 bs.step(tick, 0.9, 0.0, 0.9);
 }
 assert_eq!(bs.phase, BistablePhase::DharmicWell,
 "sustained high dukkha + high coherence should reach DharmicWell: balance={}", bs.balance);
 assert!(bs.balance >= bs.barrier_to_dharmic);
 }

 #[test]
 fn bistable_adharmic_convergence() {
 // Low dukkha + high klesha + low coherence → Adharmic well
 let mut bs = DualBistableState::new();
 for tick in 0..500 {
 bs.step(tick, 0.1, 1.5, 0.1);
 }
 assert_eq!(bs.phase, BistablePhase::AdharmicWell,
 "low dukkha + high klesha + low coherence → AdharmicWell: balance={}", bs.balance);
 assert!(bs.balance <= bs.barrier_to_adharmic);
 }

 #[test]
 fn bistable_hysteresis_resists_small_perturbation() {
 // First converge to DharmicWell, then apply small adharmic force
 let mut bs = DualBistableState::new();
 for tick in 0..500 {
 bs.step(tick, 0.9, 0.0, 0.9);
 }
 assert_eq!(bs.phase, BistablePhase::DharmicWell);
 let saved_balance = bs.balance;
 // Small perturbation: slightly lower dukkha for 10 ticks
 for tick in 500..510 {
 bs.step(tick, 0.4, 0.3, 0.7);
 }
 // Should still be in DharmicWell (hysteresis)
 assert_eq!(bs.phase, BistablePhase::DharmicWell,
 "hysteresis should resist small perturbation: balance {} → {}", saved_balance, bs.balance);
 }

 #[test]
 fn bistable_flip_count_increments() {
 let mut bs = DualBistableState::new();
 // Force to Dharmic
 for tick in 0..500 {
 bs.step(tick, 0.95, 0.0, 0.95);
 }
 assert!(bs.flip_count >= 1, "should have flipped to DharmicWell");
 let flips_after_dharmic = bs.flip_count;
 // Force to Adharmic
 for tick in 500..1500 {
 bs.step(tick, 0.0, 2.0, 0.05);
 }
 assert!(bs.flip_count > flips_after_dharmic,
 "should have flipped again: {} → {}", flips_after_dharmic, bs.flip_count);
 }

 #[test]
 fn bistable_momentum_decays() {
 let mut bs = DualBistableState::new();
 bs.momentum = 0.5;
 // No force for 100 ticks
 for tick in 0..100 {
 bs.step(tick, 0.5, 0.3, 0.5); // balanced forces
 }
 assert!(bs.momentum.abs() < 0.1,
 "momentum should decay: {}", bs.momentum);
 }

 #[test]
 fn bistable_effective_balance_matches() {
 let bs = DualBistableState::new();
 assert!((bs.effective_balance() - bs.balance).abs() < 1e-9);
 }

