 // --- 1. ClaimKind cross-talk prevention ---

 #[test]
 fn claim_kind_world_observed_via_typed_method() {
 let h = IntegrityHash::digest(b"evidence");
 let mut c: TypedClaim<f64> = TypedClaim::inferred(1.0, 0.5, "test");
 assert_eq!(c.kind, ClaimKind::World);
 c.promote_to_observed(h);
 assert_eq!(c.tier, ClaimTier::Observed);
 }

 #[test]
 #[should_panic(expected = "World 主張にのみ許可")]
 fn claim_kind_action_cannot_promote_to_observed() {
 let h = IntegrityHash::digest(b"evidence");
 let mut c: TypedClaim<f64> = TypedClaim::proven(1.0, vec![h], 0.9, "closure");
 // kind == Action at promote_to_observed panic 
 c.promote_to_observed(h);
 }

 #[test]
 #[should_panic(expected = "Action 主張にのみ許可")]
 fn claim_kind_world_cannot_promote_to_proven() {
 let mut c: TypedClaim<f64> = TypedClaim::inferred(1.0, 0.5, "world_claim");
 // kind == World at promote_to_proven panic 
 c.promote_to_proven(vec![]);
 }

 #[test]
 fn claim_kind_self_report_stays_inferred() {
 let c: TypedClaim<f64> = TypedClaim::self_report(0.5, 0.8, "introspection");
 assert_eq!(c.kind, ClaimKind::SelfReport);
 assert_eq!(c.tier, ClaimTier::Inferred);
 // SelfReport has no promote method — only Inferred forever
 }

 #[test]
 fn claim_kind_degrade_preserves_kind() {
 let h = IntegrityHash::digest(b"ev");
 let mut c: TypedClaim<f64> = TypedClaim::observed(1.0, h, 0.9);
 assert_eq!(c.kind, ClaimKind::World);
 c.degrade_to_inferred();
 assert_eq!(c.tier, ClaimTier::Inferred);
 assert_eq!(c.kind, ClaimKind::World, "kind should survive degradation");
 }

 #[test]
 fn step_claims_world_is_world_kind() {
 let claims = StepClaims::all_inferred(vec![0.1, 0.2, 0.3, 0.4], 0.05, 0.7);
 assert_eq!(claims.world.kind, ClaimKind::World);
 assert_eq!(claims.calibration.kind, ClaimKind::SelfReport);
 assert_eq!(claims.self_knowledge.kind, ClaimKind::SelfReport);
 }

