 /// R-1: klesha EMA and dukkha do not runaway at 500step
 #[test]
 fn runtime_klesha_dukkha_500step_stability() {
 let mut os = make_v10_5_os();
 let token = os.open_session("vessel_c", None);

 for i in 0..500 {
 let r = os.step(&token);
 if let Some(report) = r.reports.first() {
 // klesha (three poisons) each in [0, ∞) but should stay in [0, 3.0] in practice
 let k = &report.klesha.instant;
 assert!(k.lobha >= 0.0 && k.lobha <= 3.0,
 "lobha out of range at step {}: {}", i, k.lobha);
 assert!(k.dosa >= 0.0 && k.dosa <= 3.0,
 "dosa out of range at step {}: {}", i, k.dosa);
 assert!(k.moha >= 0.0 && k.moha <= 3.0,
 "moha out of range at step {}: {}", i, k.moha);

 // dukkha: vedana PE norm at [0, ∞) ,realuseabove 10.0 frombelow
 // filtered defense decayafter at vedana than small 
 let d = &report.dukkha;
 assert!(d.vedana >= 0.0 && d.vedana <= 10.0,
 "vedana exploded at step {}: {}", i, d.vedana);
 assert!(d.filtered >= 0.0 && d.filtered <= 10.0,
 "filtered dukkha exploded at step {}: {}", i, d.filtered);
 assert!(d.filtered <= d.vedana + 0.01,
 "filtered should not exceed vedana at step {}: filtered={} vedana={}",
 i, d.filtered, d.vedana);

 // awareness [0, 1]
 assert!(report.awareness_level >= 0.0 && report.awareness_level <= 1.0,
 "awareness out of range at step {}: {}", i, report.awareness_level);
 }
 }

 os.close_session(token);
 }

