 /// R-4: ClosureProof tolerance boundary — 0.09 passes, 0.11 fails
 #[test]
 fn runtime_closure_proof_tolerance_boundary() {
 let tolerance = 0.1;
 let previous_state = vec![1.0, 0.0, 0.0, 0.0];

 // deviation = 0.009 → matched
 let action_effect_close = ActionEffect {
 applied: vec![0.5, 0.0, 0.0, 0.0],
 rejected: vec![0.0; 4],
 world_rejection_reason: None,
 state_delta: vec![0.5, 0.0, 0.0, 0.0], // predicted delta
 effect_magnitude: 0.5,
 acceptance_ratio: 1.0,
 };
 let current_state_close = vec![1.491, 0.0, 0.0, 0.0]; // observed delta=[0.491,0,0,0], dev=0.009
 let proof_close = ClosureProof::verify(
 1, 2, &action_effect_close, &previous_state, &current_state_close, tolerance);
 assert!(proof_close.matched,
 "deviation 0.009 < tolerance 0.1 should match. reason: {:?}", proof_close.mismatch_reason);

 // deviation = 0.11 → not matched
 let current_state_far = vec![1.39, 0.0, 0.0, 0.0]; // observed delta=[0.39,0,0,0], dev=0.11
 let proof_far = ClosureProof::verify(
 1, 2, &action_effect_close, &previous_state, &current_state_far, tolerance);
 assert!(!proof_far.matched,
 "deviation 0.11 > tolerance 0.1 should not match");
 }

