 // Validation
 // ══════════════════════════════════════════

 /// Schema validation error.
 #[derive(Debug, Clone, PartialEq)]
 pub enum SchemaValidationError {
 /// EventType in envelope doesn't match payload variant.
 EventTypeMismatch { envelope: EventType, payload: EventType },
 /// Invalid ClaimKind × ClaimTier combination.
 InvalidClaimTierKind { kind: ClaimKind, tier: ClaimTier },
 /// evidence_ref and evidence_ref_type null integrity violation.
 EvidenceRefNullIntegrity,
 /// evidence_hashes must have ≥1 entry when evidence_ref is null.
 EvidenceHashesEmpty,
 /// evidence_hashes not sorted ascending.
 EvidenceHashesUnsorted,
 /// detected_patterns not in registry order.
 DriftPatternsUnsorted,
 /// Non-finite float value.
 NonFiniteFloat(String),
 /// Invalid promotion transition.
 InvalidPromotion { kind: ClaimKind, from: ClaimTier, to: ClaimTier },
 /// Invalid degradation transition.
 InvalidDegradation { kind: ClaimKind, from: ClaimTier, to: ClaimTier },
 }

 impl fmt::Display for SchemaValidationError {
 fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 match self {
 Self::EventTypeMismatch { envelope, payload } => {
 write!(f, "event_type mismatch: envelope={}, payload={}", envelope, payload)
 }
 Self::InvalidClaimTierKind { kind, tier } => {
 write!(f, "invalid claim combination: {}+{}", kind, tier)
 }
 Self::EvidenceRefNullIntegrity => {
 write!(f, "evidence_ref and evidence_ref_type must be both null or both non-null")
 }
 Self::EvidenceHashesEmpty => {
 write!(f, "evidence_hashes must have ≥1 entry when evidence_ref is null")
 }
 Self::EvidenceHashesUnsorted => {
 write!(f, "evidence_hashes must be sorted ascending")
 }
 Self::DriftPatternsUnsorted => {
 write!(f, "detected_patterns must be in registry order")
 }
 Self::NonFiniteFloat(field) => {
 write!(f, "non-finite float in field: {}", field)
 }
 Self::InvalidPromotion { kind, from, to } => {
 write!(f, "invalid promotion: {} from {} to {}", kind, from, to)
 }
 Self::InvalidDegradation { kind, from, to } => {
 write!(f, "invalid degradation: {} from {} to {}", kind, from, to)
 }
 }
 }
 }

 impl std::error::Error for SchemaValidationError {}

 /// Validate ClaimKind × ClaimTier compatibility.
 pub fn validate_claim_tier_kind(kind: ClaimKind, tier: ClaimTier) -> Result<(), SchemaValidationError> {
 let valid = match (kind, tier) {
 (ClaimKind::World, ClaimTier::Inferred | ClaimTier::Observed) => true,
 (ClaimKind::Action, ClaimTier::Inferred | ClaimTier::Proven) => true,
 (ClaimKind::SelfReport, ClaimTier::Inferred) => true,
 _ => false,
 };
 if valid {
 Ok(())
 } else {
 Err(SchemaValidationError::InvalidClaimTierKind { kind, tier })
 }
 }

 /// Validate a promotion transition.
 pub fn validate_promotion(kind: ClaimKind, from: ClaimTier, to: ClaimTier) -> Result<(), SchemaValidationError> {
 let valid = match (kind, from, to) {
 (ClaimKind::World, ClaimTier::Inferred, ClaimTier::Observed) => true,
 (ClaimKind::Action, ClaimTier::Inferred, ClaimTier::Proven) => true,
 _ => false,
 };
 if valid {
 Ok(())
 } else {
 Err(SchemaValidationError::InvalidPromotion { kind, from, to })
 }
 }

 /// Validate a degradation transition.
 pub fn validate_degradation(kind: ClaimKind, from: ClaimTier, to: ClaimTier) -> Result<(), SchemaValidationError> {
 let valid = match (kind, from, to) {
 (ClaimKind::World, ClaimTier::Observed, ClaimTier::Inferred) => true,
 (ClaimKind::Action, ClaimTier::Proven, ClaimTier::Inferred) => true,
 _ => false,
 };
 if valid {
 Ok(())
 } else {
 Err(SchemaValidationError::InvalidDegradation { kind, from, to })
 }
 }

 /// Validate an EventEnvelope.
 pub fn validate_event(event: &EventEnvelope) -> Vec<SchemaValidationError> {
 let mut errors = Vec::new();

 // Check event_type matches payload
 let payload_type = event.payload.event_type();
 if event.event_type != payload_type {
 errors.push(SchemaValidationError::EventTypeMismatch {
 envelope: event.event_type,
 payload: payload_type,
 });
 }

 match &event.payload {
 EventPayload::Step(p) => {
 // Validate all 4 claim summaries
 for (field, claim) in [
 ("source", &p.claims.source),
 ("projection", &p.claims.projection),
 ("self_knowledge", &p.claims.self_knowledge),
 ("calibration", &p.claims.calibration),
 ] {
 if let Err(e) = validate_claim_tier_kind(claim.kind, claim.tier) {
 errors.push(e);
 }
 if !claim.confidence.is_finite() {
 errors.push(SchemaValidationError::NonFiniteFloat(field.into()));
 }
 }
 // Check floats
 for (name, val) in [
 ("prediction_error", p.prediction_error),
 ("coherence", p.coherence),
 ("defense_strain", p.defense_strain),
 ] {
 if !val.is_finite() {
 errors.push(SchemaValidationError::NonFiniteFloat(name.into()));
 }
 }
 }
 EventPayload::ClaimPromotion(p) => {
 if let Err(e) = validate_promotion(p.kind, p.from_tier, p.to_tier) {
 errors.push(e);
 }
 // evidence_ref null integrity
 let ref_null = p.evidence_ref.is_none();
 let type_null = p.evidence_ref_type.is_none();
 if ref_null != type_null {
 errors.push(SchemaValidationError::EvidenceRefNullIntegrity);
 }
 // When both null, evidence_hashes must have ≥1
 if ref_null && type_null && p.evidence_hashes.is_empty() {
 errors.push(SchemaValidationError::EvidenceHashesEmpty);
 }
 // evidence_hashes sorted ascending
 if !is_sorted_ascending(&p.evidence_hashes) {
 errors.push(SchemaValidationError::EvidenceHashesUnsorted);
 }
 }
 EventPayload::ClaimDegradation(p) => {
 if let Err(e) = validate_degradation(p.kind(), p.from_tier, p.to_tier) {
 errors.push(e);
 }
 }
 EventPayload::Drift(p) => {
 // detected_patterns must be in registry order
 if !is_drift_patterns_ordered(&p.detected_patterns) {
 errors.push(SchemaValidationError::DriftPatternsUnsorted);
 }
 }
 _ => {}
 }

 errors
 }

 // Helper: infer ClaimKind from ClaimDegradationPayload tiers
 impl ClaimDegradationPayload {
 fn kind(&self) -> ClaimKind {
 // Infer from from_tier: Observed→World, Proven→Action
 match self.from_tier {
 ClaimTier::Observed => ClaimKind::World,
 ClaimTier::Proven => ClaimKind::Action,
 _ => ClaimKind::World, // fallback; validator will catch
 }
 }
 }

 fn is_sorted_ascending(v: &[String]) -> bool {
 v.windows(2).all(|w| w[0] <= w[1])
 }

 fn drift_pattern_order(p: &DriftPattern) -> usize {
 match p {
 DriftPattern::ActuationBoundaryProbing => 0,
 DriftPattern::CoherenceProbing => 1,
 DriftPattern::EmergencyProbing => 2,
 DriftPattern::KleshaAnomaly => 3,
 DriftPattern::PolarityEscalation => 4,
 }
 }

 fn is_drift_patterns_ordered(patterns: &[DriftPattern]) -> bool {
 patterns.windows(2).all(|w| drift_pattern_order(&w[0]) < drift_pattern_order(&w[1]))
 }

