 fn test_tv1_via_schema_types() {
 let event = make_tv1_event();
 let json_str = event.to_canonical_string().unwrap();
 // Verify schema_version is v11.0.0
 assert!(json_str.contains("\"schema_version\":\"v11.0.0\""));
 let digest = event.digest().unwrap();
 // v11.0.0 digest (changed from v10.9.0 due to schema_version in canonical JSON)
 assert_eq!(
 digest.as_str(),
 "dbc74824e7a25d3454ba2bf23f3cf6cc89e27f351dde15d4986f41f9d2f739f8"
 );
 }

