 #[test]
 fn test_error_roundtrip() {
 let errors = [
 ConnectorError::Timeout,
 ConnectorError::RateLimit,
 ConnectorError::ContextOverflow,
 ConnectorError::MalformedResponse,
 ConnectorError::PolicyBlock,
 ConnectorError::ProviderUnavailable,
 ConnectorError::NondeterministicParseFailure,
 ];
 for e in &errors {
 let s = e.as_str();
 assert_eq!(ConnectorError::from_str(s), Some(*e), "roundtrip failed: {}", s);
 }
 }

 #[test]
