 #[test]
 fn test_step_payload_from_claims_and_config() {
 // Test that Claims conversion + StepPayload field construction works
 // without needing a full IntegratedStepReport.
 let claims = crate::StepClaims::all_inferred(vec![0.5], 0.05, 0.95);
 let proto_claims = convert_claims(&claims);

 let step = StepPayload {
 signal_id: 1,
 receiver_id: 2,
 polarity: OntologicalPolarity::Dharmic,
 prediction_error: 0.04,
 dukkha: Dukkha { vedana: 0.3, felt: 0.2, filtered: 0.1 },
 defense_strain: 0.01,
 coherence: 0.95,
 action: Action { vector: [0.1, 0.2, 0.3, 0.4], label: "compassion".into() },
 authority: ActuationAuthority::Full,
 drift_verdict: DriftVerdict::InCharacter,
 drift_effector: DriftEffectorLevel::TelemetryOnly,
 klesha: Klesha { lobha: 0.0, dosa: 0.0, moha: 0.0, quality: KleshaQuality::Empowering },
 claims: proto_claims,
 closure_proof: None,
 state_digest: "deadbeef".into(),
 };

 let envelope = EventEnvelope {
 event_type: EventType::Step,
 tick: 42,
 timestamp_unix: 1710590400,
 payload: EventPayload::Step(step),
 };

 assert_eq!(envelope.event_type, EventType::Step);
 if let EventPayload::Step(sp) = &envelope.payload {
 assert_eq!(sp.signal_id, 1);
 assert_eq!(sp.action.label, "compassion");
 assert_eq!(sp.klesha.quality, KleshaQuality::Empowering);
 } else {
 panic!("expected Step payload");
 }

 // Verify it produces valid canonical JSON + digest
 let json_str = envelope.to_canonical_string().unwrap();
 assert!(json_str.contains("\"event_type\":\"step\""));
 let digest = envelope.digest().unwrap();
 assert_eq!(digest.as_str().len(), 64);
 }

