 #[test]
 fn test_emitter_session_and_governance() {
 let config = BridgeConfig { timestamp_unix: 1000 };
 let mut emitter = EventEmitter::new(config);

 // Session open
 let vasana = crate::IntegrityHash::zero();
 let is = crate::IdentitySemantics::Reinstantiated;
 emitter.emit_session(SessionAction::Open, "vessel", &vasana, &is, 0);

 // Governance
 let action = crate::GovernanceAction::Stop {
 vessel_id: crate::ReceiverId(1),
 reason: "test".into(),
 };
 let self_hash = crate::IntegrityHash([0xaa; 32]);
 emitter.emit_governance(&action, &crate::IdentitySemantics::Suspended, &self_hash, 1);

 assert_eq!(emitter.total(), 2);
 assert_eq!(emitter.counts().session, 1);
 assert_eq!(emitter.counts().governance, 1);
 assert_eq!(emitter.governance_sequence(), 1);

 // Event indices are monotonic
 assert_eq!(emitter.events()[0].event_index, 0);
 assert_eq!(emitter.events()[1].event_index, 1);

 // Governance chain head updated
 assert_eq!(emitter.governance_chain_head(), &integrity_hash_to_hex(&self_hash));
 }

 #[test]
 fn test_emitter_governance_chain() {
 let config = BridgeConfig { timestamp_unix: 2000 };
 let mut emitter = EventEmitter::new(config);

 let is = crate::IdentitySemantics::Preserved;
 let h1 = crate::IntegrityHash([0x11; 32]);
 let h2 = crate::IntegrityHash([0x22; 32]);

 let action = crate::GovernanceAction::Resume {
 vessel_id: crate::ReceiverId(1),
 };

 emitter.emit_governance(&action, &is, &h1, 0);
 emitter.emit_governance(&action, &is, &h2, 1);

 assert_eq!(emitter.governance_sequence(), 2);
 assert_eq!(emitter.governance_chain_head(), &integrity_hash_to_hex(&h2));

 // Second governance should chain to first
 if let EventPayload::Governance(gp) = &emitter.events()[1].envelope.payload {
 assert_eq!(gp.prev_hash, integrity_hash_to_hex(&h1));
 assert_eq!(gp.sequence, 1);
 } else {
 panic!("expected Governance");
 }
 }

