 buf.extend_from_slice(&[4u8; 16]); // isv_ext_prod_id
 buf.extend_from_slice(&[5u8; 16]); // attributes
 buf.extend_from_slice(&[6u8; 32]); // mr_enclave
 buf.extend_from_slice(&[7u8; 32]); // mr_signer
 buf.extend_from_slice(&42u16.to_le_bytes()); // isv_prod_id
 buf.extend_from_slice(&10u16.to_le_bytes()); // isv_svn
